GAME_LIBRARY_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Game Library</title>
    <style>
        :root { color-scheme: dark; }
        body {
            background: #101114;
            color: #f4f5f7;
            font-family: Arial, sans-serif;
            margin: 0;
            padding: 24px;
        }
        main { margin: 0 auto; width: min(100%, 69rem); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav {
            display: flex;
            flex-wrap: wrap;
            gap: 14px;
            justify-content: center;
            margin-bottom: 24px;
        }
        .panel {
            background: #1b1d22;
            border: 1px solid #30333b;
            border-radius: 12px;
            margin: 16px 0;
            padding: 16px;
        }
        table {
            border-collapse: collapse;
            width: 100%;
        }
        th, td {
            border-bottom: 1px solid #30333b;
            padding: 10px;
            text-align: left;
            vertical-align: top;
        }
        input, select, textarea, button {
            border: 1px solid #30333b;
            border-radius: 7px;
            font-size: 15px;
            padding: 9px 10px;
        }
        input, select, textarea { width: 100%; }
        input[type="checkbox"] { width: auto; }
        textarea { min-height: 84px; resize: vertical; }
        button {
            background: #7c9cff;
            color: #0b1020;
            cursor: pointer;
            font-weight: bold;
            width: auto;
        }
        .danger {
            background: #e45d68;
            color: white;
        }
        .notice {
            border: 1px solid #30333b;
            border-radius: 8px;
            margin: 0 auto 20px;
            padding: 12px;
            text-align: center;
        }
        .notice.error { border-color: #e45d68; }
        .grid {
            display: grid;
            gap: 12px;
            grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
        }
        .actions form {
            display: inline-block;
            margin: 0 6px 6px 0;
        }
        .actions button { padding: 7px 9px; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; }
    </style>
</head>
<body>
<main>
    <h1>Game Library</h1>
    <nav>
        <a href="{{ url_for('index', key=admin_key) }}">Submissions</a>
        <a href="{{ url_for('admin_settings', key=admin_key) }}">Settings</a>
        <a href="{{ url_for('admin_seasons', key=admin_key) }}">Seasons</a>
        <a href="{{ url_for('admin_maintenance', key=admin_key) }}">Maintenance</a>
        <a href="{{ url_for('admin_media_cleanup', key=admin_key) }}">Media</a>
        <a href="{{ url_for('admin_analytics', key=admin_key) }}">Analytics</a>
        <a href="{{ url_for('admin_moderation', key=admin_key) }}">Moderation</a>
        <a href="{{ url_for('admin_jobs', key=admin_key) }}">Jobs</a>
        <a href="{{ url_for('admin_privacy', key=admin_key) }}">Privacy</a>
        <a href="{{ url_for('admin_onboarding', key=admin_key) }}">Onboarding</a>
        <a href="{{ url_for('audit_log', key=admin_key) }}">Audit log</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>

    {% if notice %}
        <div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>
    {% endif %}

    <section class="panel">
        <h2>Add Guess Item</h2>
        <p class="muted">
            Add reusable media and answers here, then start one in Discord with
            <code>/startlibrarygame #channel item_id</code>. Use <code>|</code>
            between alternate answers, for example <code>Jack Black|Jables</code>.
            Matching ignores capitalization and special characters.
        </p>
        <form method="post" enctype="multipart/form-data" action="{{ url_for('admin_game_library') }}">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="create_item">
            <div class="grid">
                <label>Discord server
                    <select name="guild_id" required>
                        {% for guild in guild_options %}
                            <option value="{{ guild.id }}" {% if selected_guild_id == guild.id %}selected{% endif %}>{{ guild.name }}</option>
                        {% endfor %}
                    </select>
                </label>
                <label>Title
                    <input name="title" maxlength="120" placeholder="Optional display title">
                </label>
                <label>Answer and aliases
                    <input name="answer" required maxlength="300" placeholder="Minecraft: The Movie | Minecraft Movie">
                </label>
                <label>Category
                    <input name="category" maxlength="80" placeholder="movie, game, music, etc.">
                </label>
                <label>Pack
                    <input name="pack_name" maxlength="80" placeholder="Movie night, music pack, season 1">
                </label>
                <label>Tags
                    <input name="tags" maxlength="400" placeholder="easy, 2000s, comedy">
                </label>
                <label>Auto hint minutes
                    <input name="auto_hint_minutes" type="number" min="0" max="1440" value="0">
                </label>
                <label>Media
                    <input name="media" type="file" required>
                </label>
            </div>
            <label>
                <input type="hidden" name="enabled" value="0">
                <input name="enabled" type="checkbox" value="1" checked>
                Enabled for scheduled/random library games
            </label>
            <p class="muted">Maximum file size: {{ max_file_label }}.</p>
            <label>Prompt text
                <textarea name="prompt_text" maxlength="{{ max_text_length }}" placeholder="Optional text shown with the media"></textarea>
            </label>
            <label>Custom hint
                <textarea name="hint_text" maxlength="500" placeholder="Optional hint included in generated hints"></textarea>
            </label>
            <label>Admin notes
                <textarea name="notes" maxlength="1000" placeholder="Optional private notes for admins"></textarea>
            </label>
            <p><button type="submit">Add Library Item</button></p>
        </form>
    </section>

    <section class="panel">
        <h2>Bulk Import Guess Items</h2>
        <p class="muted">
            Upload a CSV to add many guess items at once. Add an optional media ZIP when
            rows include <code>media_filename</code>. The importer matches the CSV value
            to a file in the ZIP by full path or filename, stores the media in the normal
            Game Library folder, and leaves rows without matching media as drafts.
            Use <code>status=active</code> only for rows with media; text-only or missing-media
            rows are kept as drafts until media is attached.
            <a href="{{ url_for('download_guess_bulk_import_example', key=admin_key) }}">Download an example CSV</a>.
        </p>
        <p class="muted">
            Quick setup: put files such as <code>skyline.png</code> or
            <code>anime/studio-clue.webp</code> in <code>media.zip</code>, then put the same
            value in the CSV <code>media_filename</code> column. Leave
            <code>media_filename</code> blank for quote/clue-only drafts.
        </p>
        <form method="post" enctype="multipart/form-data" action="{{ url_for('admin_game_library') }}">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="bulk_import">
            <div class="grid">
                <label>Discord server
                    <select name="guild_id" required>
                        {% for guild in guild_options %}
                            <option value="{{ guild.id }}" {% if selected_guild_id == guild.id %}selected{% endif %}>{{ guild.name }}</option>
                        {% endfor %}
                    </select>
                </label>
                <label>CSV file
                    <input name="csv_file" type="file" accept=".csv,text/csv" required>
                </label>
                <label>Media ZIP (optional)
                    <input name="media_zip" type="file" accept=".zip,.7z,.tar,.tgz,.tar.gz,.rar,application/zip,application/x-7z-compressed,application/x-tar,application/vnd.rar">
                </label>
            </div>
            <p><button type="submit">Import Drafts</button></p>
        </form>
    </section>

    <section class="panel">
        <h2>Saved Items</h2>
        <form method="get" action="{{ url_for('admin_game_library') }}">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <select name="guild_id">
                <option value="all">All Discord Servers</option>
                {% for guild in guild_options %}
                    <option value="{{ guild.id }}" {% if selected_guild_id == guild.id %}selected{% endif %}>{{ guild.name }}</option>
                {% endfor %}
            </select>
            <button type="submit">Filter</button>
        </form>
        <table>
            <thead>
                <tr>
                    <th>ID</th>
                    <th>Server</th>
                    <th>Title / Answer</th>
                    <th>Media</th>
                    <th>Status</th>
                    <th>Used</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                {% for item in items %}
                    <tr>
                        <td><code>{{ item.id }}</code></td>
                        <td>{{ item.guild_name }}</td>
                        <td>
                            <strong>{{ item.title or item.answer_display }}</strong><br>
                            Answer: <code>{{ item.answer_display }}</code><br>
                            Aliases: {{ item.alias_count }}<br>
                            {% if item.category %}Category: {{ item.category }}<br>{% endif %}
                            {% if item.pack_name %}Pack: {{ item.pack_name }}<br>{% endif %}
                            {% if item.tags %}Tags: {{ item.tags|join(', ') }}<br>{% endif %}
                            {% if item.prompt_text %}<span class="muted">{{ item.prompt_text }}</span>{% endif %}
                            {% if item.notes %}<br><span class="muted">Notes: {{ item.notes }}</span>{% endif %}
                        </td>
                        <td>
                            {% if item.media_url %}
                                <a href="{{ item.media_url }}" target="_blank">{{ item.media_name }}</a>
                            {% else %}
                                <span class="muted">No media attached</span>
                            {% endif %}
                            <br>{{ item.media_type }}{% if item.size_label %} - {{ item.size_label }}{% endif %}
                        </td>
                        <td>
                            <code>{{ item.status }}</code><br>
                            <span class="{{ '' if item.enabled else 'muted' }}">{{ "Enabled" if item.enabled else "Picker disabled" }}</span>
                        </td>
                        <td>
                            {{ item.times_used or 0 }} time(s)<br>
                            <span class="muted">Last: {{ item.last_used_at or "Never" }}</span><br>
                            <span class="muted">Created: {{ item.created_at or "" }}</span>
                        </td>
                        <td class="actions">
                            <details>
                                <summary>Edit / attach media</summary>
                                <form method="post" enctype="multipart/form-data" action="{{ url_for('admin_game_library') }}">
                                    <input type="hidden" name="key" value="{{ admin_key }}">
                                    <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                    <input type="hidden" name="action" value="update_item">
                                    <input type="hidden" name="guild_id" value="{{ selected_guild_id or 'all' }}">
                                    <input type="hidden" name="item_id" value="{{ item.id }}">
                                    <input name="title" value="{{ item.title or '' }}" placeholder="Title">
                                    <input name="answer" value="{{ item.answer_display }}" placeholder="Answer | Alias">
                                    <input name="category" value="{{ item.category or '' }}" placeholder="Category">
                                    <input name="pack_name" value="{{ item.pack_name or '' }}" placeholder="Pack">
                                    <input name="tags" value="{{ item.tags|join(', ') }}" placeholder="Tags">
                                    <input name="auto_hint_minutes" type="number" min="0" max="1440" value="{{ item.auto_hint_minutes or 0 }}">
                                    <textarea name="prompt_text" placeholder="Prompt text">{{ item.prompt_text or '' }}</textarea>
                                    <textarea name="hint_text" placeholder="Hint text">{{ item.hint_text or '' }}</textarea>
                                    <textarea name="notes" placeholder="Admin notes">{{ item.notes or '' }}</textarea>
                                    <select name="status">
                                        {% for status in ["draft", "active", "disabled"] %}
                                            <option value="{{ status }}" {% if item.status == status %}selected{% endif %}>{{ status }}</option>
                                        {% endfor %}
                                    </select>
                                    <label>
                                        <input type="hidden" name="enabled" value="0">
                                        <input name="enabled" type="checkbox" value="1" {% if item.enabled %}checked{% endif %}>
                                        Enabled for scheduled/random games
                                    </label>
                                    <input name="media" type="file">
                                    <button type="submit">Save Item</button>
                                </form>
                            </details>
                            {% if item.media_url %}
                                <form method="post" action="{{ url_for('admin_game_library') }}">
                                    <input type="hidden" name="key" value="{{ admin_key }}">
                                    <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                    <input type="hidden" name="action" value="set_status">
                                    <input type="hidden" name="guild_id" value="{{ selected_guild_id or 'all' }}">
                                    <input type="hidden" name="item_id" value="{{ item.id }}">
                                    <input type="hidden" name="status" value="{{ 'disabled' if item.status == 'active' else 'active' }}">
                                    <button type="submit">{{ 'Disable' if item.status == 'active' else 'Enable' }}</button>
                                </form>
                            {% else %}
                                <span class="muted">Create a media item to activate.</span>
                            {% endif %}
                            <form method="post" action="{{ url_for('admin_game_library') }}">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="delete_item">
                                <input type="hidden" name="guild_id" value="{{ selected_guild_id or 'all' }}">
                                <input type="hidden" name="item_id" value="{{ item.id }}">
                                <button class="danger" type="submit">Delete</button>
                            </form>
                        </td>
                    </tr>
                {% else %}
                    <tr><td colspan="7" class="muted">No game library items yet.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
</main>
</body>
</html>
"""

ANIME_ACTIVITIES_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Anime Activities</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1100px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav { display: flex; flex-wrap: wrap; gap: clamp(0.6rem, 1.5vw, 0.9rem); justify-content: center; margin-bottom: clamp(1rem, 3vw, 1.5rem); }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 0.75rem; margin: clamp(0.75rem, 2vw, 1rem) 0; padding: clamp(0.85rem, 2vw, 1rem); }
        .grid { display: grid; gap: clamp(0.65rem, 1.5vw, 0.85rem); grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr)); }
        .card { background: #111318; border: 1px solid #30333b; border-radius: 0.5rem; padding: clamp(0.75rem, 1.8vw, 0.9rem); }
        .card h3 { margin: 0 0 8px; }
        .muted { color: #a8adb8; }
        .warning { border-color: #f59e0b; color: #ffd28a; }
        .commands { display: grid; gap: clamp(0.65rem, 1.5vw, 0.85rem); grid-template-columns: repeat(auto-fit, minmax(min(100%, 16rem), 1fr)); }
        .commands code { display: block; white-space: normal; }
        .actions { align-items: end; display: grid; gap: 0.75rem; grid-template-columns: minmax(0, 1fr) auto; }
        input, select, button { border: 1px solid #30333b; border-radius: 0.45rem; box-sizing: border-box; font-size: 0.95rem; padding: 0.55rem 0.65rem; }
        select { width: 100%; }
        button { background: #7c9cff; color: #0b1020; cursor: pointer; font-weight: 800; }
        .notice { border: 1px solid #30333b; border-radius: 0.5rem; margin: 0 0 1rem; padding: 0.75rem; text-align: center; }
        .notice.error { border-color: #e45d68; }
        code { color: #cdd7ff; }
        @media (max-width: 44rem) { .actions { grid-template-columns: 1fr; } button { width: 100%; } }
    </style>
</head>
<body>
<main>
    <h1>Anime Activities</h1>
    <nav>
        <a href="{{ url_for('index', key=admin_key) }}">Submissions</a>
        <a href="{{ url_for('admin_game_library', key=admin_key) }}">Game Library</a>
        <a href="{{ url_for('admin_polls', key=admin_key) }}">Polls</a>
        <a href="{{ url_for('admin_settings', key=admin_key) }}">Settings</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>
    {% if notice %}<div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>{% endif %}
    <section class="panel warning">
        <h2>Experimental Notice</h2>
        <p>{{ retirement_note }}</p>
        <p class="muted">These slash commands are enabled by default and sync to Discord when the bot starts. Set <code>SDAC_ENABLE_ANIME_COMMANDS=0</code> before startup if you want to hide them. Individual modes may change or be removed.</p>
    </section>
    <section class="panel">
        <h2>Seed All Activities</h2>
        <p class="muted">Create one draft Game Library item for every anime activity key. Drafts include prompts, tags, pack names, and admin notes; attach media and replace answers before activating them.</p>
        <form class="actions" method="post">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="seed_anime_library">
            <label>Discord server
                <select name="guild_id" required>
                    {% for guild in guild_options %}
                        <option value="{{ guild.id }}" {% if selected_guild_id == guild.id %}selected{% endif %}>{{ guild.name }}</option>
                    {% endfor %}
                </select>
            </label>
            <button type="submit">Seed Drafts</button>
        </form>
    </section>
    <section class="panel">
        <h2>Implemented Entry Points</h2>
        <div class="commands">
            <div class="card"><code>/animeevent activity #channel details</code><p>Post an activity prompt to Discord using one of the keys below.</p></div>
            <div class="card"><code>/animechallenge mode prompt answer hint</code><p>Create a Game Library item for anime guessing modes.</p></div>
            <div class="card"><code>/animeprofile favorites watching</code><p>Let users save favorite anime and currently watching notes.</p></div>
            <div class="card"><code>/animeprofileimport username</code><p>Import public MyAnimeList favorites and watching data into a user anime profile.</p></div>
            <div class="card"><code>/animeleaderboard month</code><p>Show a combined anime score from submission votes and guessing points.</p></div>
        </div>
    </section>
    {% for group in catalog %}
        <section class="panel">
            <h2>{{ group["category"] }}</h2>
            <div class="grid">
                {% for item in group["items"] %}
                    <article class="card">
                        <h3>{{ item["name"] }}</h3>
                        <p><code>{{ activity_key(item["name"]) }}</code></p>
                        <p>{{ item["summary"] }}</p>
                        <p class="muted"><strong>Note:</strong> {{ retirement_note }}</p>
                    </article>
                {% endfor %}
            </div>
        </section>
    {% endfor %}
</main>
</body>
</html>
"""

USERS_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Admin Users</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1120px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 0.75rem; margin: clamp(0.75rem, 2vw, 1rem) 0; padding: clamp(0.85rem, 2vw, 1rem); }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        input, select, button, textarea { border: 1px solid #30333b; border-radius: 7px; font-size: 15px; padding: 9px 10px; }
        textarea { min-height: 70px; width: min(100%, 520px); }
        button { background: #7c9cff; color: #0b1020; cursor: pointer; font-weight: bold; margin-top: 6px; }
        .danger { background: #e45d68; color: #19080b; }
        .notice { border: 1px solid #30333b; border-radius: 8px; margin: 0 auto 20px; padding: 12px; text-align: center; }
        .notice.error { border-color: #e45d68; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; }
        .stack { display: grid; gap: 8px; }
        @media (max-width: 760px) {
            body { padding: 12px; }
            input, select, button, textarea { box-sizing: border-box; width: 100%; }
            table, thead, tbody, tr, th, td { display: block; }
            thead { display: none; }
            tr { border-bottom: 1px solid #30333b; padding: 10px 0; }
            th, td { border-bottom: 0; padding: 6px 0; }
        }
    </style>
</head>
<body>
<main>
    <h1>Users</h1>
    {% if notice %}<div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>{% endif %}
    <section class="panel">
        <h2>Dashboard Accounts</h2>
        <table>
            <thead><tr><th>User</th><th>Discord</th><th>Role</th><th>Server Access</th><th>Status</th><th>Promote</th><th>Ban</th></tr></thead>
            <tbody>
            {% for user in dashboard_users %}
                <tr>
                    <td><code>{{ user.username }}</code>{% if user.display_name %}<br><span class="muted">{{ user.display_name }}</span>{% endif %}</td>
                    <td><code>{{ user.discord_user_id or '' }}</code></td>
                    <td>{{ role_labels.get(user.role, user.role) }}</td>
                    <td>{{ access_summary_by_user.get(user.username, 'Not Added') }}</td>
                    <td>{{ 'Banned' if user.disabled else 'Active' }}</td>
                    <td>
                        {% if can_promote_dashboard_user(user.role, 'moderator', user.username) or can_promote_dashboard_user(user.role, 'admin', user.username) or can_promote_dashboard_user(user.role, 'owner', user.username) %}
                            <form method="post" class="stack">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="promote_dashboard_user">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <select name="role">
                                    {% for role_key, role_label in role_labels.items() %}
                                        {% if can_promote_dashboard_user(user.role, role_key, user.username) %}
                                            <option value="{{ role_key }}" {% if user.role == role_key %}selected{% endif %}>{{ role_label }}</option>
                                        {% endif %}
                                    {% endfor %}
                                </select>
                                <button type="submit">Save Role</button>
                            </form>
                        {% else %}
                            <span class="muted">Not allowed</span>
                        {% endif %}
                    </td>
                    <td>
                        {% if can_ban_dashboard_user(user.role, user.username) %}
                            <form method="post">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="ban_dashboard_user">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <button class="danger" type="submit">Ban</button>
                            </form>
                        {% elif current_admin_is_baytae_owner() and user.role == 'owner' and user.username != owner_override_username %}
                            <form method="post" class="stack">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="request_owner_ban_code">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <button type="submit">Get Code</button>
                            </form>
                            <form method="post" class="stack">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="ban_dashboard_user">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <input name="owner_code" inputmode="numeric" placeholder="Owner-ban code">
                                <button class="danger" type="submit">Ban Owner</button>
                            </form>
                        {% else %}
                            <span class="muted">Not allowed</span>
                        {% endif %}
                    </td>
                </tr>
            {% else %}
                <tr><td colspan="7" class="muted">No dashboard accounts yet.</td></tr>
            {% endfor %}
            </tbody>
        </table>
    </section>
    <section class="panel">
        <h2>Per-Server Role Matrix</h2>
        <p class="muted">Use this when a person should have different access on different servers. The server dropdown only shows servers already linked to that user.</p>
        <table>
            <thead><tr><th>User</th><th>Current Servers</th><th>Update Existing Server</th><th>Add Server / Issue Code</th></tr></thead>
            <tbody>
            {% for user in dashboard_users %}
                {% set user_rows = access_rows_by_user.get(user.username, []) %}
                {% set addable_guilds = addable_guilds_by_user.get(user.username, []) %}
                <tr>
                    <td><code>{{ user.username }}</code><br><span class="muted">Default: {{ role_labels.get(user.role, user.role) }}</span></td>
                    <td>
                        {% if user_rows %}
                            {% for row in user_rows %}
                                <div>{{ row.name }}<br><code>{{ row.id }}</code><br><span class="muted">{{ role_labels.get(row.role, row.role) }} via {{ row.source }}</span></div>
                                {% if not loop.last %}<hr>{% endif %}
                            {% endfor %}
                        {% else %}
                            <span class="muted">Not Added</span>
                        {% endif %}
                    </td>
                    <td>
                        {% if user_rows %}
                            <form method="post" class="stack" data-role-matrix-form>
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="set_dashboard_server_role">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <select name="guild_id" aria-label="Existing server for {{ user.username }}">
                                    {% for row in user_rows %}
                                        <option value="{{ row.id }}" data-role="{{ row.role }}">{{ row.name }} ({{ role_labels.get(row.role, row.role) }})</option>
                                    {% endfor %}
                                </select>
                                <select name="role" aria-label="Role for selected server">
                                    {% for role_key, role_label in matrix_role_labels.items() %}
                                        <option value="{{ role_key }}" {% if user_rows and user_rows[0].role == role_key %}selected{% endif %}>{{ role_label }}</option>
                                    {% endfor %}
                                </select>
                                <button type="submit">Save Server Role</button>
                            </form>
                        {% else %}
                            <span class="muted">Add the user to a server first.</span>
                        {% endif %}
                    </td>
                    <td>
                        {% if addable_guilds %}
                            <form method="post" class="stack">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="add_dashboard_user_to_server">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <select name="guild_id" aria-label="Server to add {{ user.username }}">
                                    {% for guild in addable_guilds %}
                                        <option value="{{ guild.id }}">{{ guild.name }} ({{ guild.id }})</option>
                                    {% endfor %}
                                </select>
                                <select name="role" aria-label="Initial server role">
                                    {% for role_key, role_label in assignable_role_labels.items() %}
                                        <option value="{{ role_key }}">{{ role_label }}</option>
                                    {% endfor %}
                                </select>
                                <button type="submit">Add User To Server</button>
                            </form>
                            <form method="post" class="stack">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="issue_dashboard_auth_code">
                                <input type="hidden" name="username" value="{{ user.username }}">
                                <select name="guild_id" aria-label="Server code for {{ user.username }}">
                                    {% for guild in addable_guilds %}
                                        <option value="{{ guild.id }}">{{ guild.name }} ({{ guild.id }})</option>
                                    {% endfor %}
                                </select>
                                <select name="role" aria-label="Role granted by code">
                                    {% for role_key, role_label in assignable_role_labels.items() %}
                                        <option value="{{ role_key }}">{{ role_label }}</option>
                                    {% endfor %}
                                </select>
                                <button type="submit">Create Auth Code</button>
                            </form>
                        {% else %}
                            <span class="muted">All accessible servers already linked.</span>
                        {% endif %}
                    </td>
                </tr>
            {% else %}
                <tr><td colspan="4" class="muted">No dashboard accounts yet.</td></tr>
            {% endfor %}
            </tbody>
        </table>
        <script>
        (() => {
            document.querySelectorAll('[data-role-matrix-form]').forEach((form) => {
                const server = form.querySelector('select[name="guild_id"]');
                const role = form.querySelector('select[name="role"]');
                if (!server || !role) return;
                const syncRole = () => {
                    const selectedRole = server.selectedOptions[0]?.dataset.role || 'not_added';
                    role.value = selectedRole;
                };
                server.addEventListener('change', syncRole);
                syncRole();
            });
        })();
        </script>
    </section>
    <section class="panel">
        <h2>User Lockouts</h2>
        <form method="post" class="stack">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="set_user_lockout">
            <label>Server
                <select name="guild_id">
                    <option value="">All servers</option>
                    {% for guild in guilds %}<option value="{{ guild.id }}">{{ guild.name }} ({{ guild.id }})</option>{% endfor %}
                </select>
            </label>
            <label>Discord user ID <input name="user_id" inputmode="numeric" required></label>
            <label>Username <input name="username" placeholder="Display name for audit rows"></label>
            <label>Lockout
                <select name="scope">
                    {% for scope_key, scope_label in lockout_scope_labels.items() %}<option value="{{ scope_key }}">{{ scope_label }}</option>{% endfor %}
                </select>
            </label>
            <label>Reason <textarea name="reason" placeholder="Reason shown to admins and stored in audit history"></textarea></label>
            <button type="submit">Save Lockout</button>
        </form>
        <table>
            <thead><tr><th>User</th><th>Server</th><th>Lockout</th><th>Reason</th><th>Updated</th><th>Action</th></tr></thead>
            <tbody>
                {% for row in restrictions %}
                    <tr>
                        <td>{{ row.username or row.dashboard_username or row.user_id }}<br><code>{{ row.user_id }}</code></td>
                        <td>{{ guild_names.get(row.guild_id, row.guild_id) if row.guild_id else 'All servers' }}</td>
                        <td>{% if row.lock_games %}Games{% endif %}{% if row.lock_games and row.lock_submissions %}, {% endif %}{% if row.lock_submissions %}Submissions{% endif %}</td>
                        <td>{{ row.reason or '' }}</td>
                        <td>{{ row.updated_at or row.created_at }}</td>
                        <td>
                            <form method="post">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="clear_user_lockout">
                                <input type="hidden" name="restriction_id" value="{{ row.id }}">
                                <button type="submit">Clear</button>
                            </form>
                        </td>
                    </tr>
                {% else %}
                    <tr><td colspan="6" class="muted">No active lockouts.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
    <section class="panel">
        <h2>Recent Discord Users</h2>
        <table>
            <thead><tr><th>User</th><th>Submissions</th><th>Guess Points</th><th>Last Seen</th></tr></thead>
            <tbody>
                {% for row in known_users %}
                    <tr><td>{{ row.username or row.user_id }}<br><code>{{ row.user_id }}</code></td><td>{{ row.submissions or 0 }}</td><td>{{ row.guess_points or 0 }}</td><td>{{ row.last_seen_at or '' }}</td></tr>
                {% else %}
                    <tr><td colspan="4" class="muted">No Discord user activity recorded yet.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
</main>
</body>
</html>
"""


