POLLS_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Polls</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1100px); }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 8px; margin: 16px 0; padding: 16px; }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        input, textarea, select, button { border: 1px solid #30333b; border-radius: 7px; box-sizing: border-box; font-size: 15px; padding: 9px 10px; width: 100%; }
        button { background: #4f46e5; color: white; cursor: pointer; font-weight: bold; margin-top: 8px; }
        .inline { display: inline; }
        .inline button { width: auto; }
        .muted { color: #a8adb8; }
        .notice { border: 1px solid #30333b; border-radius: 8px; margin-bottom: 16px; padding: 12px; }
        .error { border-color: #e45d68; }
        code { color: #cdd7ff; }
    </style>
</head>
<body>
<main>
    <h1>Polls</h1>
    {% if notice %}<div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>{% endif %}
    <section class="panel">
        <h2>Create Poll</h2>
        <form method="post">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="create_poll">
            <p><label>Server</label><select name="guild_id">
                {% for guild in guild_options %}
                    <option value="{{ guild.id }}">{{ guild.name }} ({{ guild.id }})</option>
                {% endfor %}
            </select></p>
            <p><label>Question</label><input name="question" maxlength="240" required></p>
            <p><label>Options</label><textarea name="options" rows="5" placeholder="One option per line, or separate with |" required></textarea></p>
            <p><label>Channel ID <span class="muted">(optional, for Discord-posted polls)</span></label><input name="channel_id" inputmode="numeric"></p>
            <button type="submit">Create Poll</button>
        </form>
    </section>
    <section class="panel">
        <h2>Manage Polls</h2>
        <table>
            <thead><tr><th>ID</th><th>Server</th><th>Question</th><th>Status</th><th>Results</th><th>Actions</th></tr></thead>
            <tbody>
                {% for poll in polls %}
                    <tr>
                        <td><code>{{ poll.id }}</code></td>
                        <td>{{ guild_names.get(poll.guild_id, poll.guild_id) }}</td>
                        <td>{{ poll.question }}<br><span class="muted">Created {{ poll.created_at }} by {{ poll.created_by_name or poll.created_by }}</span></td>
                        <td>{{ poll.status }}</td>
                        <td>
                            {% for option in poll.summary %}
                                <div>{{ option.number }}. {{ option.label }} - {{ option.votes }} vote(s), {{ option.percent }}%</div>
                            {% endfor %}
                            <span class="muted">{{ poll.total_votes }} total vote(s)</span>
                        </td>
                        <td>
                            {% if poll.status == "active" %}
                                <form class="inline" method="post">
                                    <input type="hidden" name="key" value="{{ admin_key }}">
                                    <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                    <input type="hidden" name="action" value="close_poll">
                                    <input type="hidden" name="poll_id" value="{{ poll.id }}">
                                    <button type="submit">Close</button>
                                </form>
                            {% else %}
                                <form class="inline" method="post">
                                    <input type="hidden" name="key" value="{{ admin_key }}">
                                    <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                    <input type="hidden" name="action" value="reopen_poll">
                                    <input type="hidden" name="poll_id" value="{{ poll.id }}">
                                    <button type="submit">Reopen</button>
                                </form>
                            {% endif %}
                            <form class="inline" method="post" onsubmit="return confirm('Delete this poll and its votes?');">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="action" value="delete_poll">
                                <input type="hidden" name="poll_id" value="{{ poll.id }}">
                                <button type="submit">Delete</button>
                            </form>
                        </td>
                    </tr>
                {% else %}
                    <tr><td colspan="6" class="muted">No polls yet.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
</main>
</body>
</html>
"""


RELEASES_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Release Channel</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1000px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav { display: flex; flex-wrap: wrap; gap: clamp(0.6rem, 1.5vw, 0.9rem); justify-content: center; margin-bottom: clamp(1rem, 3vw, 1.5rem); }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 0.75rem; margin: clamp(0.75rem, 2vw, 1rem) 0; padding: clamp(0.85rem, 2vw, 1rem); }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        .ok { color: #63c174; font-weight: bold; }
        .bad { color: #e45d68; font-weight: bold; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; }
    </style>
</head>
<body>
<main>
    <h1>Release Channel</h1>
    <nav>
        <a href="{{ url_for('admin_maintenance', key=admin_key) }}">Maintenance</a>
        <a href="{{ url_for('admin_production_health', key=admin_key) }}">Health Score</a>
        <a href="{{ url_for('admin_settings', key=admin_key) }}">Settings</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>
    {% if notice %}<div class="notice {{ 'bad' if error else 'ok' }}">{{ notice }}</div>{% endif %}
    <section class="panel">
        <h2>Installed And Available</h2>
        <table>
            <tbody>
                <tr><th>Installed release</th><td><code>{{ release_status.installed }}</code></td></tr>
                <tr><th>Configured update tag</th><td><code>{{ release_status.configured_tag }}</code></td></tr>
                <tr><th>User/fork repository</th><td><code>{{ release_status.repo }}</code></td></tr>
                <tr><th>Original repository</th><td><code>{{ release_status.original_repo }}</code></td></tr>
                <tr><th>Latest official</th><td><code>{{ release_status.official.tag }}</code>{% if release_status.official.published_at %} ({{ release_status.official.published_at }}){% endif %}</td></tr>
                <tr><th>Latest experimental</th><td><code>{{ release_status.experimental.tag }}</code>{% if release_status.experimental.published_at %} ({{ release_status.experimental.published_at }}){% endif %}</td></tr>
                {% if release_status.error %}<tr><th>Release check</th><td class="bad">{{ release_status.error }}</td></tr>{% endif %}
            </tbody>
        </table>
        <form method="post" style="margin-top: 12px;">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <input type="hidden" name="action" value="test_release_notification">
            <button type="submit">Send Test Release Notification</button>
        </form>
    </section>
    <section class="panel">
        <h2>Update Commands</h2>
        {% if release_status.configured_tag == "latest-experimental" %}
            <p class="bad">This install is tracking the experimental channel. Use it for validation before promoting a build to official.</p>
        {% elif release_status.configured_tag == "latest-official" or release_status.configured_tag in ["Version 3", "version-3"] %}
            <p class="ok">This install is tracking the official channel.</p>
        {% else %}
            <p class="muted">This install is pinned to an explicit release. That is safest when you need repeatable deploys.</p>
        {% endif %}
        <p>Stable official channel:</p>
        <p><code>sudo sdac-update latest-official</code></p>
        <p>Version 3 alias:</p>
        <p><code>sudo sdac-update "Version 3"</code></p>
        <p>Last Version 2 official:</p>
        <p><code>sudo sdac-update "Version 2"</code></p>
        <p>Exact release:</p>
        <p><code>sudo sdac-update 3.1.0</code></p>
        <p>Experimental test channel:</p>
        <p><code>sudo sdac-update latest-experimental</code></p>
        <p class="muted">Recommendation: run <code>latest-experimental</code> only on a test/verification server, then update production with <code>latest-official</code> after the release is promoted.</p>
    </section>
    <section class="panel">
        <h2>Recent Experimental Versions</h2>
        <table>
            <thead><tr><th>Version</th><th>Published</th><th>Type</th></tr></thead>
            <tbody>
                {% for release in recent_releases %}
                    <tr>
                        <td>{% if release.url %}<a href="{{ release.url }}">{{ release.name }}</a>{% else %}{{ release.name }}{% endif %}<br><code>{{ release.tag }}</code></td>
                        <td>{{ release.published_at or "Unknown" }}</td>
                        <td>{{ "Experimental" if release.prerelease else "Official" }}</td>
                    </tr>
                {% else %}
                    <tr><td colspan="3" class="muted">No recent release list available. Check GitHub credentials/network access.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
    <section class="panel">
        <h2>Latest Patch Notes</h2>
        {% if latest_patch_notes %}
            <pre>{{ latest_patch_notes }}</pre>
        {% else %}
            <p class="muted">No local release notes found.</p>
        {% endif %}
    </section>
    <section class="panel">
        <h2>Rollback</h2>
        <p>
            The updater can restore the latest deploy snapshot with:
            <code>sudo sdac-update rollback</code>
        </p>
        <p>Rollback to a known release:</p>
        <p><code>sudo sdac-update 3.0.14</code></p>
        <p><code>sudo sdac-update 3.0.13</code></p>
        <p><code>sudo sdac-update 3.0.12</code></p>
        <p>Run server diagnostics after any rollback or update:</p>
        <p><code>sudo sana-doctor</code></p>
        <p class="muted">
            You can also queue rollback from Maintenance. The dashboard service
            user must have permission to restart the SDAC systemd services.
        </p>
        <table>
            <thead><tr><th>Snapshot</th><th>Modified</th></tr></thead>
            <tbody>
                {% for snapshot in snapshots %}
                    <tr><td><code>{{ snapshot.name }}</code></td><td>{{ snapshot.modified }}</td></tr>
                {% else %}
                    <tr><td colspan="2" class="muted">No deploy snapshots found yet.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
</main>
</body>
</html>
"""




GO_LIVE_CHECKLIST_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Go Live Checklist</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1100px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav { display: flex; flex-wrap: wrap; gap: clamp(0.6rem, 1.5vw, 0.9rem); justify-content: center; margin-bottom: clamp(1rem, 3vw, 1.5rem); }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 0.75rem; margin: clamp(0.75rem, 2vw, 1rem) 0; padding: clamp(0.85rem, 2vw, 1rem); }
        .grid { display: grid; gap: 12px; grid-template-columns: repeat(auto-fit, minmax(min(220px, 100%), 1fr)); }
        .metric { background: #111318; border: 1px solid #30333b; border-radius: 8px; padding: 14px; }
        .metric strong { display: block; font-size: 1.7rem; }
        .metric span { color: #a8adb8; display: block; font-size: .78rem; font-weight: 800; text-transform: uppercase; }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        .ok { color: #63c174; font-weight: bold; }
        .bad { color: #e45d68; font-weight: bold; }
        .warn { color: #f5c451; font-weight: bold; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; overflow-wrap: anywhere; }
        ul { margin: 0; padding-left: 1.2rem; }
        li + li { margin-top: 4px; }
    </style>
</head>
<body>
<main>
    <h1>Go Live Checklist</h1>
    <nav>
        <a href="{{ url_for('admin_releases', key=admin_key) }}">Releases</a>
        <a href="{{ url_for('admin_release_checklist', key=admin_key) }}">Release Checklist</a>
        <a href="{{ url_for('admin_production_health', key=admin_key) }}">Production Health</a>
        <a href="{{ url_for('admin_install_doctor', key=admin_key) }}">Install Doctor</a>
        <a href="{{ url_for('bot_invite') }}">Invite Flow</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>
    <section class="panel">
        <div class="grid">
            <div class="metric"><strong>{{ ready_count }} / {{ total_count }}</strong><span>Ready Checks</span></div>
            <div class="metric"><strong>{{ blocker_count }}</strong><span>Launch Blockers</span></div>
            <div class="metric"><strong>{{ warning_count }}</strong><span>Warnings</span></div>
            <div class="metric"><strong>{{ launch_state }}</strong><span>Launch State</span></div>
        </div>
        <p class="muted">Use this page as the final gate before promoting an experimental build to official or inviting public servers.</p>
    </section>
    <section class="panel">
        <h2>Checklist</h2>
        <table>
            <thead><tr><th>Area</th><th>Status</th><th>Details</th><th>Next Step</th></tr></thead>
            <tbody>
                {% for item in checklist %}
                    <tr>
                        <td>{{ item.label }}</td>
                        <td class="{{ 'ok' if item.ok else ('warn' if item.severity == 'warning' else 'bad') }}">{{ item.state }}</td>
                        <td>{{ item.detail }}</td>
                        <td>{{ item.next_step }}</td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
    <section class="panel">
        <h2>Manual Live Test Path</h2>
        <ul>
            {% for step in manual_steps %}
                <li>{{ step }}</li>
            {% endfor %}
        </ul>
    </section>
    <section class="panel">
        <h2>Release Channels</h2>
        <p>Installed: <code>{{ release.installed_version }}</code></p>
        <p>Latest experimental: <code>{{ release.experimental_version }}</code></p>
        <p>Latest official: <code>{{ release.official_version }}</code></p>
        <p>Configured update tag: <code>{{ release.configured_tag }}</code></p>
    </section>
</main>
</body>
</html>
"""

