THEME_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Theme</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #0f172a; color: #f8fafc; font-family: Arial, sans-serif; margin: 0; padding: 24px; }
        main { margin: 0 auto; width: min(100%, 960px); }
        .panel { background: #111827; border: 1px solid #30333b; border-radius: 8px; margin: 16px 0; padding: 16px; }
        .grid { display: grid; gap: 12px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }
        label { display: block; font-weight: bold; margin: 10px 0 6px; }
        input, button { border: 1px solid #30333b; border-radius: 7px; box-sizing: border-box; font-size: 15px; padding: 10px; width: 100%; }
        input[type="color"] { appearance: auto; background: transparent; height: 46px; padding: 3px; }
        input[type="color"]::-webkit-color-swatch-wrapper { padding: 0; }
        input[type="color"]::-webkit-color-swatch { border: 0; border-radius: 5px; }
        .color-field { background: #0b1220; border: 1px solid #30333b; border-radius: 8px; padding: 12px; }
        .color-field label { align-items: center; display: flex; justify-content: space-between; margin-top: 0; }
        .color-field code { color: #cbd5e1; font-size: 12px; font-weight: 700; }
        input[type="file"] { background: #2b3038; color: #e5e7eb; }
        input[type="file"]::file-selector-button { background: #3b424c; border: 0; border-radius: 6px; color: #f8fafc; cursor: pointer; font-weight: bold; margin-right: 10px; padding: 8px 10px; }
        button { background: #4f46e5; color: white; cursor: pointer; font-weight: bold; margin-top: 16px; }
        .notice { border: 1px solid #30333b; border-radius: 8px; margin-bottom: 14px; padding: 12px; }
        .preview { min-height: 180px; border-radius: 8px; padding: 18px; background: var(--sdac-bg); background-image: var(--sdac-theme-image, linear-gradient(135deg, var(--sdac-primary), var(--sdac-secondary))); background-size: cover; }
        .muted { color: #94a3b8; }
        .layout-workbench { background: #020617; border: 1px solid #30333b; border-radius: 8px; box-sizing: border-box; display: block; height: min(78vh, 820px); margin-top: 12px; width: 100%; }
    </style>
</head>
<body>
<main>
    <h1>Theme</h1>
    {% if notice %}<div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>{% endif %}
    <section class="panel">
        <h2>Dashboard Colors</h2>
        <form method="post" enctype="multipart/form-data">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <div class="grid">
                {% for key, label in color_fields %}
                    <div class="color-field"><label for="{{ key }}">{{ label }} <code>{{ theme[key] }}</code></label><input id="{{ key }}" name="{{ key }}" type="color" value="{{ theme[key] }}"></div>
                {% endfor %}
            </div>
            <label for="background_image">Background Image URL</label>
            <input id="background_image" name="background_image" value="{{ theme.background_image }}" placeholder="https://... or uploaded file below">
            <label for="background_file">Upload Background Image</label>
            <input id="background_file" name="background_file" type="file" accept="image/png,image/jpeg,image/gif,image/webp">
            <button type="submit">Save Theme</button>
        </form>
    </section>
    <section class="panel">
        <h2>Live Theme Preview</h2>
        <div class="preview">
            <div class="sdac-dashboard-grid">
                <div class="sdac-dashboard-card"><strong>128</strong><span>Submissions</span></div>
                <div class="sdac-dashboard-card"><strong>42</strong><span>Users</span></div>
            </div>
        </div>
    </section>
    <section class="panel">
        <h2>Full Layout Workbench</h2>
        <p class="muted">Use the embedded layout editor below to manage object position, card sizing, sidebar width, spacing, background placement, and density while staying on the Theme page.</p>
        <iframe class="layout-workbench" src="{{ url_for('admin_layout', key=admin_key, embed=1) }}" title="Sana-Chan layout workbench"></iframe>
    </section>
</main>
</body>
</html>
"""


LAYOUT_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Layout</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #0f172a; color: #f8fafc; font-family: Arial, sans-serif; margin: 0; padding: 24px; }
        main { margin: 0 auto; width: min(100%, 1180px); }
        .panel { background: #111827; border: 1px solid #30333b; border-radius: 8px; margin: 16px 0; padding: 16px; }
        .grid { display: grid; gap: 12px; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }
        label { display: block; font-weight: bold; margin: 10px 0 6px; }
        input, select, button { background: #1f2937; border: 1px solid #30333b; border-radius: 7px; box-sizing: border-box; color: #f8fafc; font-size: 15px; padding: 10px; width: 100%; }
        button { background: #4f46e5; color: white; cursor: pointer; font-weight: bold; margin-top: 16px; }
        .notice { border: 1px solid #30333b; border-radius: 8px; margin-bottom: 14px; padding: 12px; }
        .editor-shell { display: grid; gap: 16px; grid-template-columns: minmax(0, 1fr) minmax(320px, 360px); }
        .site-layout-panel { display: none; }
        .preview {
            --preview-content-width: min(calc(100% - var(--preview-sidebar-width) - 32px), calc(var(--sdac-content-width) * .52));
            --preview-grid-min: calc(var(--sdac-grid-min) * .54);
            --preview-sidebar-width: calc(var(--sdac-sidebar-width) * .62);
            background: var(--sdac-bg);
            border-radius: var(--sdac-card-radius);
            min-height: 440px;
            overflow: hidden;
            padding: 0;
            position: relative;
        }
        .preview::before { content: ""; position: absolute; inset: 0; background-image: var(--sdac-theme-image, linear-gradient(135deg, var(--sdac-primary), var(--sdac-secondary))); background-position: var(--sdac-bg-position); background-size: cover; opacity: var(--sdac-theme-image-opacity); pointer-events: none; }
        .preview-shell { display: flex; min-height: 440px; position: relative; z-index: 1; }
        .preview-sidebar {
            background: linear-gradient(180deg, var(--sdac-sidebar-bg), color-mix(in srgb, var(--sdac-sidebar-bg) 88%, #020617));
            border-right: 1px solid var(--sdac-border);
            box-sizing: border-box;
            flex: 0 0 var(--preview-sidebar-width);
            padding: calc(var(--sdac-panel-padding) * .78);
            transition: flex-basis .18s ease, padding .18s ease;
        }
        .preview-sidebar strong { display: block; font-size: .95rem; margin-bottom: 8px; }
        .preview-sidebar span { color: var(--sdac-muted); display: block; font-size: .72rem; margin-bottom: var(--sdac-layout-gap); }
        .preview-nav-line { background: color-mix(in srgb, var(--sdac-text) 14%, transparent); border-radius: var(--sdac-card-radius); height: 18px; margin: 8px 0; }
        .preview-nav-line.active { background: linear-gradient(90deg, var(--sdac-primary), var(--sdac-secondary)); }
        .preview-menu-actions { display: flex; gap: 8px; left: min(calc(var(--preview-sidebar-width) + 12px), calc(100% - 160px)); position: absolute; top: 12px; transition: left .18s ease; z-index: 2; }
        .preview-menu-button {
            background: linear-gradient(90deg, var(--sdac-primary), var(--sdac-secondary));
            border: 1px solid var(--sdac-border);
            border-radius: var(--sdac-card-radius);
            box-shadow: 0 10px 26px rgba(2, 6, 23, .26);
            color: #fff;
            font-size: .78rem;
            font-weight: 850;
            left: auto;
            padding: 8px 11px;
            position: relative;
            top: auto;
            transition: left .18s ease, border-radius .18s ease;
            z-index: 2;
        }
        .preview[data-menu-alignment="page_left"] .preview-menu-button,
        .preview[data-menu-alignment="viewport_left"] .preview-menu-button { left: 12px; }
        .preview-content {
            box-sizing: border-box;
            margin: 0 auto;
            max-width: var(--preview-content-width);
            padding: calc(var(--sdac-panel-padding) * 2.2) var(--sdac-panel-padding) var(--sdac-panel-padding);
            transition: max-width .18s ease, padding .18s ease;
            width: 100%;
        }
        .preview-heading { font-size: 1.15rem; font-weight: 850; margin-bottom: var(--sdac-layout-gap); }
        .preview-filter { border: 1px solid var(--sdac-border); border-radius: var(--sdac-card-radius); margin-bottom: var(--sdac-layout-gap); padding: calc(var(--sdac-panel-padding) * .55); text-align: center; }
        .preview-inner { align-items: stretch; display: grid; gap: var(--sdac-layout-gap); grid-template-columns: repeat(12, minmax(0, 1fr)); position: relative; }
        .preview-card { background: var(--sdac-surface); border: 1px solid var(--sdac-border); border-radius: var(--sdac-card-radius); cursor: grab; min-height: 104px; padding: var(--sdac-panel-padding); user-select: none; }
        .preview-card:active { cursor: grabbing; }
        .preview-card.is-selected { outline: 2px solid var(--sdac-accent); outline-offset: 2px; }
        .preview-card.is-dragging { opacity: .42; }
        .preview-card strong { display: block; font-size: var(--item-font-size, 1.6rem); line-height: 1.1; }
        .preview-card span { color: var(--sdac-muted); display: block; font-size: .8rem; font-weight: 750; margin-top: 6px; text-transform: uppercase; }
        .preview-card[data-width="small"] { grid-column: span 3; }
        .preview-card[data-width="medium"] { grid-column: span 4; }
        .preview-card[data-width="wide"] { grid-column: span 6; }
        .preview-card[data-width="full"] { grid-column: span 12; }
        .preview-card[data-tone="primary"] { background: color-mix(in srgb, var(--sdac-primary) 24%, var(--sdac-surface)); }
        .preview-card[data-tone="secondary"] { background: color-mix(in srgb, var(--sdac-secondary) 22%, var(--sdac-surface)); }
        .preview-card[data-tone="accent"] { background: color-mix(in srgb, var(--sdac-accent) 24%, var(--sdac-surface)); }
        .preview-card[data-visible="false"] { opacity: .42; }
        .preview-editable-control.is-selected,
        .preview-card.is-selected { outline: 2px solid var(--sdac-accent); outline-offset: 2px; }
        .preview-card[data-locked="true"],
        .preview-editable-control[data-locked="true"] { cursor: not-allowed; }
        .preview-card[data-locked="true"]::after { content: "Locked"; color: var(--sdac-muted); display: block; font-size: .72rem; font-weight: 800; margin-top: 10px; }
        .item-list { display: grid; gap: 8px; margin: 10px 0 14px; }
        .item-list button { align-items: center; background: #111827; border: 1px solid #30333b; display: flex; justify-content: space-between; margin: 0; text-align: left; }
        .item-list button.is-selected { background: linear-gradient(90deg, var(--sdac-primary), var(--sdac-secondary)); }
        .item-list small { color: #cbd5e1; font-weight: 700; }
        .property-actions { display: grid; gap: 8px; grid-template-columns: 1fr 1fr; }
        .property-actions button { margin-top: 0; }
        .lock-row { align-items: center; display: flex; gap: 8px; margin: 10px 0; }
        .lock-row input { width: auto; }
        .preview-grid-demo { display: grid; gap: var(--sdac-layout-gap); grid-template-columns: repeat(auto-fit, minmax(max(70px, var(--preview-grid-min)), 1fr)); margin-top: var(--sdac-layout-gap); }
        .preview-grid-demo div { background: color-mix(in srgb, var(--sdac-secondary) 14%, var(--sdac-surface)); border: 1px solid var(--sdac-border); border-radius: var(--sdac-card-radius); min-height: 44px; padding: calc(var(--sdac-panel-padding) * .48); }
        .preview[data-density="compact"] { --sdac-layout-gap: 8px; }
        .preview[data-density="comfortable"] { --sdac-layout-gap: 14px; }
        .preview[data-density="spacious"] { --sdac-layout-gap: 20px; }
        .property-panel { align-self: start; background: #0b1220; border: 1px solid #30333b; border-radius: 8px; max-height: min(86vh, 900px); overflow: auto; padding: 14px; position: sticky; top: 14px; }
        .property-panel .grid { grid-template-columns: 1fr; }
        .property-section { border-top: 1px solid #30333b; margin-top: 14px; padding-top: 14px; }
        .property-panel h3 { margin: 0 0 8px; }
        .muted { color: #94a3b8; }
        @media (max-width: 900px) {
            .editor-shell { grid-template-columns: 1fr; }
            .property-panel { position: static; }
            .preview { --preview-content-width: 100%; --preview-sidebar-width: min(calc(var(--sdac-sidebar-width) * .62), 62%); }
            .preview-card[data-width] { grid-column: span 12; }
        }
    </style>
</head>
<body>
<main>
    <h1>Layout</h1>
    {% if notice %}<div class="notice {{ 'error' if error else '' }}">{{ notice }}</div>{% endif %}
    <section class="panel site-layout-panel">
        <h2>Site Layout</h2>
        <form id="layout-form" method="post">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
            <div class="grid">
                <div><label for="content_width">Content Width</label><input id="content_width" name="content_width" type="number" min="840" max="1600" value="{{ layout.content_width }}"></div>
                <div><label for="sidebar_width">Sidebar Width</label><input id="sidebar_width" name="sidebar_width" type="number" min="220" max="360" value="{{ layout.sidebar_width }}"></div>
                <div><label for="card_radius">Card Radius</label><input id="card_radius" name="card_radius" type="number" min="0" max="24" value="{{ layout.card_radius }}"></div>
                <div><label for="panel_padding">Panel Padding</label><input id="panel_padding" name="panel_padding" type="number" min="10" max="34" value="{{ layout.panel_padding }}"></div>
                <div><label for="grid_min_width">Card Grid Minimum</label><input id="grid_min_width" name="grid_min_width" type="number" min="150" max="360" value="{{ layout.grid_min_width }}"></div>
                <div><label for="background_opacity">Background Image Opacity</label><input id="background_opacity" name="background_opacity" type="number" min="0" max="60" value="{{ layout.background_opacity }}"></div>
                <div>
                    <label for="menu_button_alignment">Menu Button Alignment</label>
                    <select id="menu_button_alignment" name="menu_button_alignment">
                        {% for value, label in menu_button_alignments %}
                            <option value="{{ value }}" {% if layout.menu_button_alignment == value %}selected{% endif %}>{{ label }}</option>
                        {% endfor %}
                    </select>
                </div>
                <div>
                    <label for="background_position">Background Position</label>
                    <select id="background_position" name="background_position">
                        {% for value, label in background_positions %}
                            <option value="{{ value }}" {% if layout.background_position == value %}selected{% endif %}>{{ label }}</option>
                        {% endfor %}
                    </select>
                </div>
                <div>
                    <label for="density">Density</label>
                    <select id="density" name="density">
                        {% for value, label in densities %}
                            <option value="{{ value }}" {% if layout.density == value %}selected{% endif %}>{{ label }}</option>
                        {% endfor %}
                    </select>
                </div>
            </div>
            <input id="item_order" name="item_order" type="hidden" value="{{ layout.item_order }}">
            <input id="item_properties" name="item_properties" type="hidden" value='{{ item_properties_json | safe }}'>
            <button type="submit">Save Layout</button>
        </form>
    </section>
    <section class="panel">
        <h2>Visual Test Environment</h2>
        <div class="editor-shell">
            <div class="preview" id="layout-preview-frame" data-density="{{ layout.density }}" data-menu-alignment="{{ layout.menu_button_alignment }}">
                <div class="preview-menu-actions">
                    {% for item in layout_items %}{% if item.id == "menu_button" %}<div class="preview-menu-button preview-editable-control" data-id="{{ item.id }}" data-tone="{{ item.tone }}" data-font-size="{{ item.font_size }}" data-locked="{{ 'true' if item.locked else 'false' }}">{{ item.value }}</div>{% endif %}{% endfor %}
                    {% for item in layout_items %}{% if item.id == "home_button" %}<div class="preview-menu-button preview-editable-control" data-id="{{ item.id }}" data-tone="{{ item.tone }}" data-font-size="{{ item.font_size }}" data-locked="{{ 'true' if item.locked else 'false' }}">{{ item.value }}</div>{% endif %}{% endfor %}
                </div>
                <div class="preview-shell">
                    <aside class="preview-sidebar">
                        <strong>Sana-Chan Admin</strong>
                        <span>Server Owner</span>
                        <div class="preview-nav-line active"></div>
                        <div class="preview-nav-line"></div>
                        <div class="preview-nav-line"></div>
                        <div class="preview-nav-line"></div>
                    </aside>
                    <div class="preview-content">
                        <div class="preview-heading">Sana-Chan Dashboard</div>
                        <div class="preview-filter">Filters</div>
                        <div class="preview-inner" id="layout-preview">
                            {% for item in layout_items %}
                                {% if item.id not in ("menu_button", "home_button") %}
                                <div class="preview-card"
                                     draggable="true"
                                     data-id="{{ item.id }}"
                                     data-width="{{ item.width }}"
                                     data-tone="{{ item.tone }}"
                                     data-visible="{{ 'true' if item.visible else 'false' }}"
                                     data-font-size="{{ item.font_size }}"
                                     data-locked="{{ 'true' if item.locked else 'false' }}">
                                    <strong>{{ item.value }}</strong>
                                    <span>{{ item.label }}</span>
                                </div>
                                                            {% endif %}
                            {% endfor %}
                        </div>
                        <div class="preview-grid-demo" aria-hidden="true">
                            <div></div>
                            <div></div>
                            <div></div>
                            <div></div>
                        </div>
                    </div>
                </div>
            </div>
            <aside class="property-panel">
                <h3>Editable Items</h3>
                <p class="muted" id="selected-help">Select an item here or click it in the preview. Use Move buttons if drag is awkward.</p>
                <div class="item-list" id="layout-item-list"></div>
                <div class="property-actions">
                    <button id="move-up" type="button" disabled>Move Up</button>
                    <button id="move-down" type="button" disabled>Move Down</button>
                </div>
                <h3 id="selected-title">Select an item</h3>
                <label for="prop_label">Text Label</label>
                <input id="prop_label" disabled>
                <label for="prop_value">Main Text / Number</label>
                <input id="prop_value" disabled>
                <label for="prop_font_size">Font Size</label>
                <select id="prop_font_size" disabled>
                    <option value="small">Small</option>
                    <option value="normal">Normal</option>
                    <option value="large">Large</option>
                    <option value="display">Display</option>
                </select>
                <label for="prop_width">Object Size</label>
                <select id="prop_width" disabled>
                    <option value="small">Small</option>
                    <option value="medium">Medium</option>
                    <option value="wide">Wide</option>
                    <option value="full">Full Width</option>
                </select>
                <label for="prop_tone">Color Style</label>
                <select id="prop_tone" disabled>
                    <option value="surface">Surface</option>
                    <option value="primary">Primary</option>
                    <option value="secondary">Secondary</option>
                    <option value="accent">Accent</option>
                </select>
                <label class="lock-row"><input id="prop_visible" type="checkbox" disabled> Visible</label>
                <label class="lock-row"><input id="prop_locked" type="checkbox" disabled> Locked</label>
                <button id="reset-item" type="button" disabled>Reset Selected Item</button>
                <button id="reset-layout" type="button">Reset Test Layout</button>
            </aside>
        </div>
        <script>
        (function () {
            const defaults = {{ item_defaults_json | safe }};
            const previewFrame = document.getElementById("layout-preview-frame");
            const preview = document.getElementById("layout-preview");
            const propertyPanel = document.querySelector(".property-panel");
            const layoutForm = document.getElementById("layout-form");
            const siteLayoutPanel = document.querySelector(".site-layout-panel");
            const orderInput = document.getElementById("item_order");
            const propertiesInput = document.getElementById("item_properties");
            const labelInput = document.getElementById("prop_label");
            const valueInput = document.getElementById("prop_value");
            const widthInput = document.getElementById("prop_width");
            const fontSizeInput = document.getElementById("prop_font_size");
            const toneInput = document.getElementById("prop_tone");
            const visibleInput = document.getElementById("prop_visible");
            const lockedInput = document.getElementById("prop_locked");
            const itemList = document.getElementById("layout-item-list");
            const moveUpButton = document.getElementById("move-up");
            const moveDownButton = document.getElementById("move-down");
            const selectedTitle = document.getElementById("selected-title");
            const selectedHelp = document.getElementById("selected-help");
            const resetItem = document.getElementById("reset-item");
            const editableControls = [labelInput, valueInput, widthInput, fontSizeInput, toneInput, visibleInput, lockedInput, resetItem, moveUpButton, moveDownButton];
            const fontSizes = { small: "1.25rem", normal: "1.6rem", large: "2rem", display: "2.35rem" };
            let selected = null;
            let dragging = null;
            let properties = {};
            try { properties = JSON.parse(propertiesInput.value || "{}"); } catch (error) { properties = {}; }
            const layoutControls = {
                contentWidth: document.getElementById("content_width"),
                sidebarWidth: document.getElementById("sidebar_width"),
                cardRadius: document.getElementById("card_radius"),
                panelPadding: document.getElementById("panel_padding"),
                gridMinWidth: document.getElementById("grid_min_width"),
                backgroundOpacity: document.getElementById("background_opacity"),
                menuButtonAlignment: document.getElementById("menu_button_alignment"),
                backgroundPosition: document.getElementById("background_position"),
                density: document.getElementById("density")
            };

            function numberValue(input, fallback, min, max) {
                const parsed = parseInt(input.value, 10);
                if (Number.isNaN(parsed)) return fallback;
                return Math.max(min, Math.min(max, parsed));
            }

            function updateLayoutPreview() {
                previewFrame.style.setProperty("--sdac-content-width", numberValue(layoutControls.contentWidth, 1220, 840, 1600) + "px");
                previewFrame.style.setProperty("--sdac-sidebar-width", numberValue(layoutControls.sidebarWidth, 260, 220, 360) + "px");
                previewFrame.style.setProperty("--sdac-card-radius", numberValue(layoutControls.cardRadius, 8, 0, 24) + "px");
                previewFrame.style.setProperty("--sdac-panel-padding", numberValue(layoutControls.panelPadding, 16, 10, 34) + "px");
                previewFrame.style.setProperty("--sdac-grid-min", numberValue(layoutControls.gridMinWidth, 190, 150, 360) + "px");
                previewFrame.style.setProperty("--sdac-theme-image-opacity", (numberValue(layoutControls.backgroundOpacity, 18, 0, 60) / 100).toFixed(2));
                previewFrame.style.setProperty("--sdac-bg-position", layoutControls.backgroundPosition.value || "center");
                previewFrame.dataset.menuAlignment = layoutControls.menuButtonAlignment.value || "sidebar_edge";
                previewFrame.dataset.density = layoutControls.density.value || "comfortable";
            }

            function cards() {
                return Array.from(previewFrame.querySelectorAll(".preview-editable-control, .preview-card"));
            }

            function isPreviewCard(card) {
                return card && card.classList.contains("preview-card");
            }

            function itemDefaults(id) {
                return defaults.find((item) => item.id === id) || {};
            }

            function itemProps(id) {
                return Object.assign({}, itemDefaults(id), properties[id] || {});
            }

            function syncHiddenInputs() {
                orderInput.value = cards().map((card) => card.dataset.id).join(",");
                propertiesInput.value = JSON.stringify(properties);
            }

            function applyCard(card) {
                const props = itemProps(card.dataset.id);
                card.dataset.width = props.width || "medium";
                card.dataset.tone = props.tone || "surface";
                card.dataset.visible = props.visible === false ? "false" : "true";
                card.dataset.fontSize = props.font_size || "normal";
                card.dataset.locked = props.locked === true ? "true" : "false";
                card.draggable = isPreviewCard(card) && props.locked !== true;
                card.style.setProperty("--item-font-size", fontSizes[props.font_size || "normal"] || fontSizes.normal);
                if (isPreviewCard(card)) {
                    card.querySelector("strong").textContent = props.value || "";
                    card.querySelector("span").textContent = props.label || "";
                } else {
                    card.textContent = props.value || props.label || "";
                }
            }

            function renderItemList() {
                itemList.innerHTML = "";
                cards().forEach((card, index) => {
                    const props = itemProps(card.dataset.id);
                    const button = document.createElement("button");
                    button.type = "button";
                    button.className = card === selected ? "is-selected" : "";
                    button.dataset.id = card.dataset.id;
                    button.innerHTML = "<span>" + (props.label || card.dataset.id) + "</span><small>" + (props.locked ? "Locked" : "Item " + (index + 1)) + "</small>";
                    button.addEventListener("click", () => selectCard(card));
                    itemList.appendChild(button);
                });
            }

            function applyAll() {
                cards().forEach(applyCard);
                renderItemList();
                syncHiddenInputs();
            }

            function selectCard(card) {
                selected = card;
                cards().forEach((item) => item.classList.toggle("is-selected", item === card));
                const props = itemProps(card.dataset.id);
                selectedTitle.textContent = props.label || "Selected item";
                selectedHelp.textContent = "Editing " + card.dataset.id + ". Change text, font, size, lock state, or order from this panel.";
                editableControls.forEach((input) => input.disabled = false);
                labelInput.value = props.label || "";
                valueInput.value = props.value || "";
                widthInput.value = props.width || "medium";
                fontSizeInput.value = props.font_size || "normal";
                toneInput.value = props.tone || "surface";
                visibleInput.checked = props.visible !== false;
                lockedInput.checked = props.locked === true;
                const cardList = Array.from(preview.querySelectorAll(".preview-card"));
                const index = cardList.indexOf(card);
                const canMove = isPreviewCard(card) && props.locked !== true;
                moveUpButton.disabled = !canMove || index <= 0;
                moveDownButton.disabled = !canMove || index >= cardList.length - 1;
                renderItemList();
            }

            function updateSelected() {
                if (!selected) return;
                const id = selected.dataset.id;
                properties[id] = {
                    label: labelInput.value.trim() || itemDefaults(id).label,
                    value: valueInput.value.trim() || itemDefaults(id).value,
                    width: widthInput.value,
                    font_size: fontSizeInput.value,
                    tone: toneInput.value,
                    visible: visibleInput.checked,
                    locked: lockedInput.checked
                };
                applyCard(selected);
                syncHiddenInputs();
                selectCard(selected);
            }

            function dragAfterElement(y) {
                return cards().filter((card) => card !== dragging).reduce((closest, child) => {
                    const box = child.getBoundingClientRect();
                    const offset = y - box.top - box.height / 2;
                    if (offset < 0 && offset > closest.offset) {
                        return { offset: offset, element: child };
                    }
                    return closest;
                }, { offset: Number.NEGATIVE_INFINITY, element: null }).element;
            }

            function moveSelected(direction) {
                if (!selected || selected.dataset.locked === "true" || !isPreviewCard(selected)) return;
                const list = Array.from(preview.querySelectorAll(".preview-card"));
                const index = list.indexOf(selected);
                const targetIndex = index + direction;
                if (targetIndex < 0 || targetIndex >= list.length) return;
                if (direction < 0) preview.insertBefore(selected, list[targetIndex]);
                else preview.insertBefore(list[targetIndex], selected);
                syncHiddenInputs();
                selectCard(selected);
            }

            previewFrame.addEventListener("click", (event) => {
                const card = event.target.closest(".preview-editable-control, .preview-card");
                if (card) selectCard(card);
            });
            preview.addEventListener("dragstart", (event) => {
                dragging = event.target.closest(".preview-card");
                if (!dragging || dragging.dataset.locked === "true") {
                    event.preventDefault();
                    dragging = null;
                    return;
                }
                dragging.classList.add("is-dragging");
                event.dataTransfer.effectAllowed = "move";
            });
            preview.addEventListener("dragover", (event) => {
                event.preventDefault();
                if (!dragging) return;
                const after = dragAfterElement(event.clientY);
                if (after == null) preview.appendChild(dragging);
                else preview.insertBefore(dragging, after);
                syncHiddenInputs();
                renderItemList();
            });
            preview.addEventListener("dragend", () => {
                if (dragging) dragging.classList.remove("is-dragging");
                dragging = null;
                syncHiddenInputs();
                renderItemList();
            });
            [labelInput, valueInput, widthInput, fontSizeInput, toneInput, visibleInput, lockedInput].forEach((input) => {
                input.addEventListener("input", updateSelected);
                input.addEventListener("change", updateSelected);
            });
            moveUpButton.addEventListener("click", () => moveSelected(-1));
            moveDownButton.addEventListener("click", () => moveSelected(1));
            resetItem.addEventListener("click", () => {
                if (!selected) return;
                delete properties[selected.dataset.id];
                applyCard(selected);
                selectCard(selected);
                syncHiddenInputs();
            });
            document.getElementById("reset-layout").addEventListener("click", () => {
                properties = {};
                defaults.forEach((item) => {
                    const card = preview.querySelector('[data-id="' + item.id + '"]');
                    if (card) preview.appendChild(card);
                });
                selected = null;
                cards().forEach((item) => item.classList.remove("is-selected"));
                selectedTitle.textContent = "Select an item";
                selectedHelp.textContent = "Select an item here or click it in the preview. Use Move buttons if drag is awkward.";
                editableControls.forEach((input) => input.disabled = true);
                applyAll();
            });
            function moveLayoutControlsIntoSidebar() {
                if (!siteLayoutPanel || !propertyPanel || !layoutForm) return;
                const layoutGrid = siteLayoutPanel.querySelector(".grid");
                const saveButton = siteLayoutPanel.querySelector('button[type="submit"]');
                if (!layoutGrid || document.getElementById("right-layout-controls")) return;
                const section = document.createElement("div");
                section.className = "property-section";
                section.id = "right-layout-controls";
                const heading = document.createElement("h3");
                heading.textContent = "Page Layout";
                section.appendChild(heading);
                section.appendChild(layoutGrid);
                if (saveButton) section.appendChild(saveButton);
                section.querySelectorAll("input, select, button").forEach((control) => control.setAttribute("form", "layout-form"));
                propertyPanel.insertBefore(section, propertyPanel.firstChild);
            }
            Object.values(layoutControls).forEach((input) => {
                input.addEventListener("input", updateLayoutPreview);
                input.addEventListener("change", updateLayoutPreview);
            });
            moveLayoutControlsIntoSidebar();
            updateLayoutPreview();
            applyAll();
        }());
        </script>
    </section>
</main>
</body>
</html>
"""


OWNER_PORTAL_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Owner Portal</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1100px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav { display: flex; flex-wrap: wrap; gap: clamp(0.6rem, 1.5vw, 0.9rem); justify-content: center; margin-bottom: clamp(1rem, 3vw, 1.5rem); }
        .server { background: #1b1d22; border: 1px solid #30333b; border-radius: 12px; margin: 16px 0; padding: 16px; }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        input, button, textarea { border: 1px solid #30333b; border-radius: 7px; font-size: 15px; margin: 4px 0; padding: 9px 10px; width: min(100%, 560px); }
        textarea { min-height: 76px; }
        button { background: #7c9cff; color: #0b1020; cursor: pointer; font-weight: bold; width: auto; }
        .danger { background: #e45d68; color: #19080b; }
        .notice { border: 1px solid #30333b; border-radius: 8px; margin: 0 auto 16px; padding: 12px; }
        .muted { color: #a8adb8; }
        .bad { color: #e45d68; font-weight: bold; }
        .ok { color: #63c174; font-weight: bold; }
        code { color: #cdd7ff; }
    </style>
</head>
<body>
<main>
    <h1>Server Owner Portal</h1>
    <nav>
        <a href="{{ url_for('admin_onboarding', key=admin_key) }}">Onboarding</a>
        <a href="{{ url_for('admin_settings', key=admin_key) }}">Settings</a>
        <a href="{{ url_for('admin_media_cleanup', key=admin_key) }}">Media</a>
        <a href="{{ url_for('admin_server_health_cards', key=admin_key) }}">Server Health</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>
    {% if notice %}<div class="notice">{{ notice }}</div>{% endif %}
    {% for server in servers %}
        <article class="server">
            <h2>{{ server.name }} <span class="muted">({{ server.id }})</span></h2>
            <table>
                <tbody>
                    <tr><th>Bot access</th><td>
                        {% if server.bot_access_disabled %}
                            <span class="bad">Disabled</span><br>
                            Reason: {{ server.bot_access_reason or "No reason provided." }}<br>
                            Contact: {{ server.bot_access_contact or "No contact provided." }}
                        {% else %}
                            <span class="ok">Enabled</span>
                        {% endif %}
                    </td></tr>
                    <tr><th>Setup score</th><td>{{ server.health }}%</td></tr>
                    <tr><th>Storage</th><td>{{ server.forecast.current if server.forecast else "Unknown" }}; {{ server.forecast.forecast if server.forecast else "No forecast yet." }}</td></tr>
                    <tr><th>Backup</th><td>
                        Enabled: <code>{{ "Yes" if server.backup.enabled else "No" }}</code><br>
                        Remote: <code>{{ server.backup.remote or "Not set" }}</code><br>
                        Last status: <code>{{ server.backup.last_status or "Unknown" }}</code>
                    </td></tr>
                    <tr><th>Quick commands</th><td>
                        {% for command in server.commands %}<code>{{ command }}</code>{% if not loop.last %}<br>{% endif %}{% endfor %}
                    </td></tr>
                    <tr><th>Invite link</th><td>
                        {% if server.invite_url %}<a href="{{ server.invite_url }}" target="_blank">Invite/Re-authorize SDAC</a>{% else %}<span class="muted">Set bot client ID to show invite link.</span>{% endif %}
                    </td></tr>
                    {% if can_manage_bot_access %}
                        <tr><th>Bot Owner Access Control</th><td>
                            <form method="post">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="guild_id" value="{{ server.id }}">
                                <label>Contact details shown in Discord/dashboard</label><br>
                                <input name="contact" value="{{ server.bot_access_contact }}" placeholder="Discord username, email, support server, or website"><br>
                                <label>Reason shown to this server</label><br>
                                <textarea name="reason" placeholder="Why access is disabled or restored">{{ server.bot_access_reason }}</textarea><br>
                                {% if server.bot_access_disabled %}
                                    <button name="action" value="enable_bot_access" type="submit">Restore Access</button>
                                {% else %}
                                    <button class="danger" name="action" value="disable_bot_access" type="submit" onclick="return confirm('Disable SDAC access for this server?');">Remove Access</button>
                                {% endif %}
                            </form>
                        </td></tr>
                    {% endif %}
                </tbody>
            </table>
        </article>
    {% else %}
        <p class="muted">No servers are available to this dashboard admin.</p>
    {% endfor %}
</main>
</body>
</html>
"""


SERVER_HEALTH_CARDS_HTML = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Sana-Chan Server Health Cards</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1200px); }
        h1, h2 { text-align: center; }
        a { color: #7c9cff; }
        nav { display: flex; flex-wrap: wrap; gap: clamp(0.6rem, 1.5vw, 0.9rem); justify-content: center; margin-bottom: clamp(1rem, 3vw, 1.5rem); }
        .grid { display: grid; gap: 16px; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); }
        .card { background: #1b1d22; border: 1px solid #30333b; border-radius: 12px; padding: 16px; }
        .health-metric { display: grid; gap: 10px; grid-template-columns: repeat(auto-fit, minmax(min(100%, 8.5rem), 1fr)); }
        .health-pill { background: #111318; border: 1px solid #30333b; border-radius: 10px; display: grid; gap: 4px; grid-template-columns: minmax(0, 1fr); min-height: 0; padding: 10px; }
        .health-pill strong, .health-pill span { min-width: 0; overflow-wrap: anywhere; white-space: normal; }
        .health-pill .health-value { font-size: 1.1rem; font-weight: 850; line-height: 1.1; }
        .health-pill .muted { line-height: 1.2; }
        .ok { color: #63c174; font-weight: bold; }
        .bad { color: #e45d68; font-weight: bold; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; overflow-wrap: anywhere; }
    </style>
</head>
<body>
<main>
    <h1>Server Health Cards</h1>
    <nav>
        <a href="{{ url_for('admin_maintenance', key=admin_key) }}">Maintenance</a>
        <a href="{{ url_for('admin_owner_portal', key=admin_key) }}">Owner Portal</a>
        <a href="{{ url_for('admin_settings', key=admin_key) }}">Settings</a>
        <a href="{{ url_for('admin_game_library', key=admin_key) }}">Game Library</a>
        <a href="{{ url_for('admin_health', key=admin_key) }}">Health JSON</a>
        <a href="{{ url_for('admin_logout') }}">Log out</a>
    </nav>
    <section class="grid">
        <article class="card">
            <h2>Service Logs</h2>
            <p>Last bot logs:</p>
            <p><code>sudo journalctl -u sdac-bot -n 80 --no-pager</code></p>
            <p>Follow bot logs live:</p>
            <p><code>sudo journalctl -u sdac-bot -f</code></p>
            <p>Service status:</p>
            <p><code>sudo systemctl status sdac-bot --no-pager</code></p>
            <p>Full server doctor:</p>
            <p><code>sudo sana-doctor</code></p>
        </article>
        {% for row in servers %}
            <article class="card">
                <h2>{{ row.name }}</h2>
                <p class="muted"><code>{{ row.guild_id }}</code></p>
                <div class="health-metric">
                    <div class="health-pill">
                        <strong>Setup</strong><br>
                        <span class="health-value {{ 'ok' if row.setup_score >= 80 else 'bad' }}">{{ row.setup_score }}%</span>
                    </div>
                    <div class="health-pill">
                        <strong>Storage</strong><br>
                        <span class="health-value">{{ row.storage.current if row.storage else "Unknown" }}</span>
                        <span class="muted">{{ row.storage.forecast if row.storage else "No forecast" }}</span>
                    </div>
                    <div class="health-pill">
                        <strong>Submissions</strong><br>
                        <span class="health-value">{{ row.submissions }} total</span>
                        <span class="muted">{{ row.pending_submissions }} pending</span>
                    </div>
                    <div class="health-pill">
                        <strong>Games</strong><br>
                        <span class="health-value">{{ row.active_games }} active</span>
                        <span class="muted">{{ row.scheduled_games }} scheduled</span>
                    </div>
                    <div class="health-pill">
                        <strong>Library</strong><br>
                        <span class="health-value">{{ row.enabled_library_items }} enabled</span>
                        <span class="muted">{{ row.library_items }} total</span>
                    </div>
                    <div class="health-pill">
                        <strong>Achievements</strong><br>
                        <span class="health-value">{{ row.achievements }} awarded</span>
                    </div>
                </div>
                <p>
                    Backup:
                    <span class="{{ 'ok' if row.backup.enabled and row.backup.remote else 'bad' }}">
                        {{ "configured" if row.backup.enabled and row.backup.remote else "needs setup" }}
                    </span><br>
                    Remote: <code>{{ row.backup.remote or "Not set" }}</code><br>
                    Last archive: <code>{{ row.last_archive.status or "None" }}</code>
                    {% if row.last_archive.created_at %} at {{ row.last_archive.created_at }}{% endif %}
                </p>
                <p class="muted">
                    Useful Discord commands:
                    <code>/setupchecklist</code>,
                    <code>/backupstatus</code>,
                    <code>/scheduledgames</code>
                </p>
            </article>
        {% else %}
            <p class="muted">No servers are available to this dashboard admin.</p>
        {% endfor %}
    </section>
</main>
</body>
</html>
"""


