def production_health_report(config_data=None):
    config_data = config_data or load_config()
    bot_status = read_bot_status()
    warnings = security_warnings() + storage_warnings(config_data)
    offsite = config_data.get("offsite_backup") or {}
    guild_backups = [
        (guild_config.get("external_backup") or {})
        for guild_config in (config_data.get("guilds") or {}).values()
    ]
    configured_guild_backups = [
        backup
        for backup in guild_backups
        if backup.get("enabled") and backup.get("remote")
    ]
    checks = []

    def add(label, ok, details):
        checks.append({"label": label, "ok": bool(ok), "details": details})

    add("Secrets", not security_warnings(), "No default/missing dashboard secrets." if not security_warnings() else "; ".join(security_warnings()))
    add(
        "Dashboard accounts",
        dashboard_user_count() > 0,
        (
            f"{dashboard_user_count()} active dashboard account(s)."
            if dashboard_user_count() > 0
            else "Create an owner with scripts/reset_admin_login.py before exposing the admin dashboard."
        ),
    )
    add("Discord OAuth", oauth_enabled(), "OAuth configured." if oauth_enabled() else "Set SDAC_DISCORD_CLIENT_ID and SDAC_DISCORD_CLIENT_SECRET.")
    add("Bot heartbeat", bot_status.get("fresh"), bot_status.get("message") or "No heartbeat.")
    add("Database backend", True, "PostgreSQL mode." if using_postgres() else "SQLite mode.")
    add("Backups", bool(recent_database_backups()), "Recent backup found." if recent_database_backups() else "No database backup found yet.")
    add(
        "Offsite backups",
        bool(offsite.get("last_success_at") or offsite.get("remote")),
        offsite.get("last_success_at") or offsite.get("remote") or "No offsite backup destination recorded.",
    )
    add(
        "Per-server backups",
        bool(configured_guild_backups),
        (
            f"{len(configured_guild_backups)} guild backup target(s) configured."
            if configured_guild_backups
            else "No guild-specific backup targets configured."
        ),
    )
    add("Storage warnings", not storage_warnings(config_data), "No storage warnings." if not storage_warnings(config_data) else "; ".join(storage_warnings(config_data)))
    add("Public URL", bool(os.getenv("SDAC_PUBLIC_URL") or os.getenv("SDAC_DOMAIN")), "Public URL configured." if os.getenv("SDAC_PUBLIC_URL") or os.getenv("SDAC_DOMAIN") else "Set SDAC_PUBLIC_URL.")
    add("Guilds configured", bool(config_data.get("guilds")), f"{len(config_data.get('guilds') or {})} guild(s) configured.")
    add(
        "Instance ID",
        bool(os.getenv("SDAC_INSTANCE_ID")),
        (
            f"Explicit SDAC_INSTANCE_ID={DASHBOARD_INSTANCE_ID}."
            if os.getenv("SDAC_INSTANCE_ID")
            else f"Using generated instance ID {DASHBOARD_INSTANCE_ID}; set SDAC_INSTANCE_ID for multi-instance hosts."
        ),
    )
    add(
        "Release updater",
        bool(release_status().get("configured_tag")),
        f"Configured tag: {release_status().get('configured_tag') or 'unknown'}",
    )
    add("Warnings", not warnings, "No warnings." if not warnings else "; ".join(warnings))
    score = sum(1 for check in checks if check["ok"])
    return {
        "score": score,
        "max_score": len(checks),
        "checks": checks,
    }


def doctor_item(label, ok, details, severity="warn"):
    return {
        "label": label,
        "ok": bool(ok),
        "details": details,
        "severity": severity,
    }


def command_available(command):
    return shutil.which(command) is not None


def check_directory_writable(path):
    path = Path(path)
    try:
        path.mkdir(parents=True, exist_ok=True)
        probe = path / f".sdac-write-test-{secrets.token_hex(4)}"
        probe.write_text("ok", encoding="utf-8")
        probe.unlink()
        return True, f"Writable: {path}"
    except OSError as error:
        return False, f"Not writable: {path} ({error})"


def install_doctor_report():
    checks = []
    config_data = load_config()
    update_config = read_update_config()

    def add(label, ok, details, severity="warn"):
        checks.append(doctor_item(label, ok, details, severity))

    add("Discord token", bool(TOKEN), "DISCORD_TOKEN is set." if TOKEN else "DISCORD_TOKEN is missing.", "critical")
    add(
        "Dashboard accounts",
        dashboard_user_count() > 0,
        (
            f"{dashboard_user_count()} active dashboard account(s)."
            if dashboard_user_count() > 0
            else "Create an owner with scripts/reset_admin_login.py.",
        ),
        "critical",
    )
    add("Session secret", bool(os.getenv("SDAC_SECRET_KEY")), "SDAC_SECRET_KEY is set." if os.getenv("SDAC_SECRET_KEY") else "Set SDAC_SECRET_KEY for stable sessions.", "critical")
    add("Public URL", bool(os.getenv("SDAC_PUBLIC_URL") or os.getenv("SDAC_DOMAIN")), os.getenv("SDAC_PUBLIC_URL") or os.getenv("SDAC_DOMAIN") or "Set SDAC_PUBLIC_URL or SDAC_DOMAIN.")
    add("Configured guilds", bool(config_data.get("guilds")), f"{len(config_data.get('guilds') or {})} guild(s) configured.")
    add("Repository", bool(RELEASE_REPO), f"User/fork repo: {RELEASE_REPO}; original repo: {ORIGINAL_REPO}.")

    for label, path in (
        ("Media folder", MEDIA_DIR),
        ("Backup folder", BACKUP_DIR),
        ("Config folder", CONFIG_FILE.parent),
        ("Quarantine folder", MEDIA_QUARANTINE_DIR),
    ):
        ok, details = check_directory_writable(path)
        add(label, ok, details, "critical" if not ok else "warn")

    try:
        with closing(connect_db()) as connection:
            schema_row = connection.execute("""
                SELECT version
                FROM schema_version
                WHERE id = 1
            """).fetchone()
            version = int(schema_row["version"]) if schema_row else 0
            if using_postgres():
                table_details = "PostgreSQL backend."
            else:
                table_count = connection.execute("""
                    SELECT COUNT(*)
                    FROM sqlite_master
                    WHERE type = 'table'
                """).fetchone()[0]
                table_details = f"{table_count} table(s)."
        add("Database schema", version >= SCHEMA_VERSION, f"Schema v{version}; expected v{SCHEMA_VERSION}; {table_details}", "critical")
    except Exception as error:
        add("Database schema", False, f"Database check failed: {error}", "critical")

    bot_status = read_bot_status()
    add("Bot heartbeat", bot_status.get("fresh"), bot_status.get("message") or "No heartbeat.", "critical")
    add(
        "Instance ID",
        bool(os.getenv("SDAC_INSTANCE_ID")),
        (
            f"Explicit SDAC_INSTANCE_ID={DASHBOARD_INSTANCE_ID}; bot reports {bot_status.get('instance_id') or 'unknown'}."
            if os.getenv("SDAC_INSTANCE_ID")
            else f"Generated ID {DASHBOARD_INSTANCE_ID}; set SDAC_INSTANCE_ID when running multiple installs on one host."
        ),
    )

    add("Updater config", bool(update_config), f"Update config: {UPDATE_ENV_FILE}" if update_config else f"No readable updater config at {UPDATE_ENV_FILE}.")
    add("Updater command", Path("/usr/local/bin/sana-update").exists() or Path("/usr/local/bin/sanachan-update").exists() or (BASE_DIR / "scripts" / "update_from_github.sh").is_file(), "sana-update command or bundled updater script found.")
    add("Rollback script", (BASE_DIR / "scripts" / "rollback_ubuntu.sh").is_file(), "Rollback script is bundled." if (BASE_DIR / "scripts" / "rollback_ubuntu.sh").is_file() else "Missing scripts/rollback_ubuntu.sh.")

    systemd_available = command_available("systemctl")
    add("systemd", systemd_available, "systemctl is available." if systemd_available else "systemctl is not available on this host.")
    if os.name != "nt":
        add("sdac-bot unit", Path("/etc/systemd/system/sdac-bot.service").exists(), "/etc/systemd/system/sdac-bot.service")
        add("sdac-dashboard unit", Path("/etc/systemd/system/sdac-dashboard.service").exists(), "/etc/systemd/system/sdac-dashboard.service")

    nginx_available = command_available("nginx")
    add("Nginx", nginx_available, "nginx command found." if nginx_available else "nginx command not found.")
    if nginx_available:
        try:
            result = subprocess.run(
                ["nginx", "-t"],
                capture_output=True,
                text=True,
                timeout=8,
                check=False,
            )
            add("Nginx config", result.returncode == 0, (result.stderr or result.stdout or "nginx -t ran.")[-500:])
        except (OSError, subprocess.SubprocessError) as error:
            add("Nginx config", False, f"nginx -t failed: {error}")

    certbot_needed = bool(os.getenv("SDAC_PUBLIC_URL") or os.getenv("SDAC_DOMAIN"))
    certbot_available = command_available("certbot")
    add("Certbot", (not certbot_needed) or certbot_available, "certbot found." if certbot_available else "certbot not found; needed for public HTTPS hosts.")

    release = release_status()
    add("Release check", not release.get("error"), release.get("error") or f"Official: {release['official']['tag']}; Experimental: {release['experimental']['tag']}.")

    score = sum(1 for check in checks if check["ok"])
    return {
        "score": score,
        "max_score": len(checks),
        "checks": checks,
    }


def owner_portal_rows():
    cache_id = cache_key("owner_portal_rows")
    cached = ttl_cache_get(cache_id)
    if cached is not None:
        return cached
    config_data = load_config()
    onboarding = {row["id"]: row for row in build_onboarding_rows(config_data)}
    forecasts = {row["guild_id"]: row for row in storage_forecast_rows(config_data)}
    backup_rows = {row["guild_id"]: row for row in guild_storage_rows(config_data)}
    rows = []
    for option in guild_options(config_data):
        guild_id = option["id"]
        guild_config = (config_data.get("guilds") or {}).get(guild_id) or {}
        backup = guild_config.get("external_backup") or {}
        rows.append({
            "id": guild_id,
            "name": option["name"],
            "bot_access_disabled": bool(guild_config.get("bot_access_disabled")),
            "bot_access_contact": guild_config.get("bot_access_contact") or "",
            "bot_access_reason": guild_config.get("bot_access_reason") or "",
            "health": (onboarding.get(guild_id) or {}).get("health_score", 0),
            "forecast": forecasts.get(guild_id),
            "storage": backup_rows.get(guild_id),
            "backup": backup,
            "invite_url": bot_invite_url(),
            "commands": [
                "/setup",
                "/diagnose",
                "/repairpermissions",
                "/serverbackupstatus",
            ],
        })
    return ttl_cache_set(cache_id, rows, 60)


def server_health_card_rows(config_data=None):
    use_cache = config_data is None
    cache_id = cache_key("server_health_card_rows")
    if use_cache:
        cached = ttl_cache_get(cache_id)
        if cached is not None:
            return cached
    config_data = config_data or load_config()
    onboarding = {row["id"]: row for row in build_onboarding_rows(config_data)}
    forecasts = {row["guild_id"]: row for row in storage_forecast_rows(config_data)}
    rows = []
    with closing(connect_db()) as connection:
        for option in guild_options(config_data):
            guild_id = option["id"]
            guild_config = (config_data.get("guilds") or {}).get(guild_id) or {}
            backup = {
                **DEFAULT_GUILD_EXTERNAL_BACKUP,
                **(guild_config.get("external_backup") or {}),
            }
            stats = {
                "submissions": connection.execute("""
                    SELECT COUNT(*)
                    FROM submissions
                    WHERE guild_id = ?
                """, (guild_id,)).fetchone()[0],
                "pending_submissions": connection.execute("""
                    SELECT COUNT(*)
                    FROM submissions
                    WHERE guild_id = ?
                      AND status IN ('pending', 'held')
                """, (guild_id,)).fetchone()[0],
                "active_games": connection.execute("""
                    SELECT COUNT(*)
                    FROM guess_games
                    WHERE guild_id = ?
                      AND status = 'active'
                """, (guild_id,)).fetchone()[0],
                "scheduled_games": connection.execute("""
                    SELECT COUNT(*)
                    FROM scheduled_games
                    WHERE guild_id = ?
                      AND status IN ('queued', 'starting', 'running')
                """, (guild_id,)).fetchone()[0],
                "library_items": connection.execute("""
                    SELECT COUNT(*)
                    FROM guess_library_items
                    WHERE guild_id = ?
                """, (guild_id,)).fetchone()[0],
                "enabled_library_items": connection.execute("""
                    SELECT COUNT(*)
                    FROM guess_library_items
                    WHERE guild_id = ?
                      AND status = 'active'
                      AND (enabled IS NULL OR enabled != 0)
                """, (guild_id,)).fetchone()[0],
                "achievements": connection.execute("""
                    SELECT COUNT(*)
                    FROM user_achievements
                    WHERE guild_id = ?
                """, (guild_id,)).fetchone()[0],
            }
            archive = connection.execute("""
                SELECT status, destination, size_bytes, created_at
                FROM backup_archives
                WHERE guild_id = ?
                ORDER BY created_at DESC, id DESC
                LIMIT 1
            """, (guild_id,)).fetchone()
            rows.append({
                "guild_id": guild_id,
                "name": option["name"],
                "setup_score": (
                    onboarding.get(guild_id, {}).get("health_score", 0)
                ),
                "storage": forecasts.get(guild_id),
                "backup": backup,
                "last_archive": dict(archive) if archive else {},
                **stats,
            })
    if not use_cache:
        return rows
    return ttl_cache_set(cache_id, rows, 60)


def csv_response(filename, rows, columns):
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(columns)
    for row in rows:
        writer.writerow([row[column] for column in columns])
    return Response(
        output.getvalue(),
        mimetype="text/csv",
        headers={
            "Content-Disposition": f"attachment; filename={filename}",
        },
    )


def nullable_channel_id(raw_value):
    value = str(raw_value or "").strip()
    if not value:
        return None
    if not value.isdigit():
        raise ValueError("Channel IDs must be numbers.")
    return int(value)


def role_id_list(raw_value):
    role_ids = []
    for value in re_split_ids(raw_value):
        if not value.isdigit():
            raise ValueError("Role IDs must be numbers.")
        role_ids.append(value)
    return sorted(set(role_ids))


def re_split_ids(raw_value):
    return [
        value
        for value in str(raw_value or "").replace(",", " ").split()
        if value.strip()
    ]


def clean_category_name(category):
    return category.lower().strip().replace(" ", "")


def normalize_guess(value):
    cleaned = re.sub(r"[^\w\s]", " ", str(value or "").casefold())
    cleaned = re.sub(r"[_\s]+", " ", cleaned)
    return cleaned.strip()


def parse_answer_aliases(answer):
    aliases = []
    seen = set()
    for part in str(answer or "").split("|"):
        display = part.strip()
        normalized = normalize_guess(display)
        if not display or not normalized or normalized in seen:
            continue
        aliases.append({
            "display": display,
            "normalized": normalized,
        })
        seen.add(normalized)
    return aliases


def parse_metadata_list(raw_value, limit=24, item_limit=40):
    values = []
    seen = set()
    for part in re.split(r"[,|;\n]+", str(raw_value or "")):
        value = re.sub(r"\s+", " ", part.strip())
        if not value:
            continue
        value = value[:item_limit]
        key = value.casefold()
        if key in seen:
            continue
        values.append(value)
        seen.add(key)
        if len(values) >= limit:
            break
    return values


def parse_enabled_field(raw_value, default=True):
    value = str(raw_value if raw_value is not None else "").strip().casefold()
    if not value:
        return 1 if default else 0
    if value in {"1", "true", "yes", "y", "on", "enabled", "active"}:
        return 1
    if value in {"0", "false", "no", "n", "off", "disabled"}:
        return 0
    return 1 if default else 0


def is_allowed_file(filename):
    return Path(filename or "").suffix.lower() in ALLOWED_EXTENSIONS


def get_media_type(filename):
    extension = Path(filename or "").suffix.lower()
    if extension in {".png", ".jpg", ".jpeg", ".gif", ".webp"}:
        return "image"
    if extension in {".mp4", ".mov", ".webm", ".mkv"}:
        return "video"
    if extension in {".mp3", ".wav", ".ogg", ".flac", ".m4a"}:
        return "audio"
    return "unknown"


def safe_upload_filename(filename):
    basename = Path(filename or "").name.replace("\\", "_")
    basename = re.sub(r"[^A-Za-z0-9_.-]+", "-", basename).strip("-")
    return basename or "media"


def guess_library_media_metadata(filename, path, content_type=""):
    try:
        size = Path(path).stat().st_size
    except OSError:
        size = 0
    media_type = get_media_type(filename)
    return {
        "filename": filename,
        "media_type": media_type,
        "size": int(size or 0),
        "size_label": format_bytes(int(size or 0)),
        "content_type": content_type or "",
        "thumbnail_path": create_media_thumbnail(path, filename),
    }


def save_guess_library_upload(guild_id, upload, limits):
    if upload is None or not upload.filename:
        raise ValueError("Game media is required.")
    if not is_allowed_file(upload.filename):
        raise ValueError("Game media must be an image, video, or audio file.")

    folder = MEDIA_DIR / str(guild_id) / "guess_library"
    folder.mkdir(parents=True, exist_ok=True)
    filename = safe_upload_filename(upload.filename)
    stored_name = f"{int(time.time())}-{secrets.token_hex(4)}-{filename}"
    path = folder / stored_name
    upload.save(path)
    maybe_compress_image(path, filename)

    size = path.stat().st_size if path.exists() else 0
    max_file_bytes = int(limits.get("max_file_bytes", 25 * 1024 * 1024))
    if size <= 0:
        try:
            path.unlink()
        except OSError:
            pass
        raise ValueError("Uploaded media was empty.")
    if max_file_bytes and size > max_file_bytes:
        try:
            path.unlink()
        except OSError:
            pass
        raise ValueError("Uploaded media exceeds the per-file size limit.")

    metadata = guess_library_media_metadata(
        filename,
        path,
        getattr(upload, "mimetype", "") or "",
    )
    return {
        "path": str(path),
        "name": filename,
        "type": metadata["media_type"],
        "size": size,
        "metadata": metadata,
    }


def zip_media_lookup_key(filename):
    value = str(filename or "").strip().replace("\\", "/").lstrip("/")
    value = re.sub(r"/+", "/", value)
    return value.casefold()


class GuessMediaArchiveEntry:
    def __init__(self, filename, file_size=0, member=None, extracted_path=None):
        self.filename = str(filename or "")
        self.file_size = int(file_size or 0)
        self.member = member
        self.extracted_path = Path(extracted_path) if extracted_path else None


class GuessMediaArchive:
    def __init__(self, archive_type, archive=None, temp_dir=None):
        self.archive_type = archive_type
        self.archive = archive
        self.temp_dir = temp_dir

    def open(self, entry, mode="r"):
        if entry.extracted_path:
            return entry.extracted_path.open("rb")
        if self.archive_type in {"zip", "rar"}:
            return self.archive.open(entry.member, "r")
        if self.archive_type == "tar":
            handle = self.archive.extractfile(entry.member)
            if handle is None:
                raise ValueError(f"Media file {entry.filename} could not be opened.")
            return handle
        raise ValueError("Unsupported media archive type.")

    def close(self):
        if self.archive is not None:
            self.archive.close()
        if self.temp_dir is not None:
            self.temp_dir.cleanup()


def guess_archive_extension(filename):
    name = str(filename or "").casefold()
    for suffix in (".tar.gz", ".tar.bz2", ".tar.xz", ".tgz", ".tbz2", ".txz"):
        if name.endswith(suffix):
            return suffix
    return Path(name).suffix


def safe_archive_member_name(filename):
    normalized = zip_media_lookup_key(filename)
    if not normalized or normalized.startswith("/") or any(part in {"", ".", ".."} for part in normalized.split("/")):
        return ""
    return normalized


def add_guess_archive_entry(lookup, entry):
    normalized = safe_archive_member_name(entry.filename)
    if not normalized:
        return
    if not is_allowed_file(entry.filename):
        return
    basename = zip_media_lookup_key(Path(normalized).name)
    lookup.setdefault(normalized, entry)
    lookup.setdefault(basename, entry)


def open_guess_media_zip(upload):
    if upload is None or not upload.filename:
        return None, {}
    extension = guess_archive_extension(upload.filename)
    allowed_extensions = {".zip", ".7z", ".tar", ".tar.gz", ".tar.bz2", ".tar.xz", ".tgz", ".tbz2", ".txz", ".rar"}
    if extension not in allowed_extensions:
        raise ValueError("Media archive must be a .zip, .7z, .tar, .tar.gz, .tgz, or .rar file.")
    raw_content = upload.stream.read()
    if not raw_content:
        raise ValueError("Media archive file was empty.")
    lookup = {}

    if extension == ".zip":
        try:
            zip_archive = zipfile.ZipFile(io.BytesIO(raw_content))
        except zipfile.BadZipFile as archive_error:
            raise ValueError("Media ZIP could not be opened.") from archive_error
        archive = GuessMediaArchive("zip", zip_archive)
        for info in zip_archive.infolist():
            if info.is_dir():
                continue
            add_guess_archive_entry(lookup, GuessMediaArchiveEntry(info.filename, info.file_size, info))
        return archive, lookup

    if extension in {".tar", ".tar.gz", ".tar.bz2", ".tar.xz", ".tgz", ".tbz2", ".txz"}:
        try:
            tar_archive = tarfile.open(fileobj=io.BytesIO(raw_content), mode="r:*")
        except tarfile.TarError as archive_error:
            raise ValueError("Media TAR archive could not be opened.") from archive_error
        archive = GuessMediaArchive("tar", tar_archive)
        for member in tar_archive.getmembers():
            if not member.isfile():
                continue
            add_guess_archive_entry(lookup, GuessMediaArchiveEntry(member.name, member.size, member))
        return archive, lookup

    if extension == ".7z":
        try:
            import py7zr
        except ImportError as import_error:
            raise ValueError("7z media imports require the py7zr package. Install requirements.txt on the server.") from import_error
        temp_dir = tempfile.TemporaryDirectory(prefix="sana-7z-media-")
        try:
            with py7zr.SevenZipFile(io.BytesIO(raw_content), mode="r") as seven_archive:
                safe_names = [name for name in seven_archive.getnames() if safe_archive_member_name(name) and is_allowed_file(name)]
                if safe_names:
                    seven_archive.extract(path=temp_dir.name, targets=safe_names)
        except Exception as archive_error:
            temp_dir.cleanup()
            raise ValueError("Media 7z archive could not be opened.") from archive_error
        archive = GuessMediaArchive("7z", None, temp_dir)
        for extracted in Path(temp_dir.name).rglob("*"):
            if not extracted.is_file():
                continue
            relative_name = extracted.relative_to(temp_dir.name).as_posix()
            add_guess_archive_entry(lookup, GuessMediaArchiveEntry(relative_name, extracted.stat().st_size, extracted_path=extracted))
        return archive, lookup

    if extension == ".rar":
        try:
            import rarfile
        except ImportError as import_error:
            raise ValueError("RAR media imports require the rarfile package and a server RAR backend such as unar, unrar, or bsdtar.") from import_error
        try:
            rar_archive = rarfile.RarFile(io.BytesIO(raw_content))
        except rarfile.Error as archive_error:
            raise ValueError("Media RAR archive could not be opened.") from archive_error
        archive = GuessMediaArchive("rar", rar_archive)
        for info in rar_archive.infolist():
            if info.isdir():
                continue
            add_guess_archive_entry(lookup, GuessMediaArchiveEntry(info.filename, info.file_size, info))
        return archive, lookup

    raise ValueError("Unsupported media archive type.")


def save_guess_library_zip_media(guild_id, archive, info, limits):
    if archive is None or info is None:
        return None
    filename = safe_upload_filename(Path(info.filename).name)
    if not is_allowed_file(filename):
        raise ValueError(f"Media file {filename} is not an allowed type.")
    max_file_bytes = int(limits.get("max_file_bytes", 25 * 1024 * 1024))
    if max_file_bytes and int(info.file_size or 0) > max_file_bytes:
        raise ValueError(f"Media file {filename} exceeds the per-file size limit.")
    folder = MEDIA_DIR / str(guild_id) / "guess_library"
    folder.mkdir(parents=True, exist_ok=True)
    stored_name = f"{int(time.time())}-{secrets.token_hex(4)}-{filename}"
    path = folder / stored_name
    with archive.open(info, "r") as source, path.open("wb") as destination:
        shutil.copyfileobj(source, destination)
    maybe_compress_image(path, filename)
    size = path.stat().st_size if path.exists() else 0
    if size <= 0:
        try:
            path.unlink()
        except OSError:
            pass
        raise ValueError(f"Media file {filename} was empty.")
    if max_file_bytes and size > max_file_bytes:
        try:
            path.unlink()
        except OSError:
            pass
        raise ValueError(f"Media file {filename} exceeds the per-file size limit.")
    metadata = guess_library_media_metadata(filename, path, f"application/x-{archive.archive_type}")
    return {
        "path": str(path),
        "name": filename,
        "type": metadata["media_type"],
        "size": size,
        "metadata": metadata,
    }



class LocalStoredUpload:
    def __init__(self, filename, path):
        self.filename = filename
        self.stream = Path(path).open("rb")

    def close(self):
        try:
            self.stream.close()
        except OSError:
            pass


def update_guess_import_progress(job_id, **progress):
    if not job_id:
        return
    snapshot = {
        "stage": progress.pop("stage", "running"),
        **progress,
        "updated_at": utc_now_iso(),
    }
    update_background_job(
        job_id,
        result_json=json.dumps(snapshot, separators=(",", ":")),
    )


def stage_guess_library_bulk_import_uploads(csv_upload, media_upload=None):
    if csv_upload is None or not csv_upload.filename:
        raise ValueError("Choose a CSV file to import.")
    token = f"{int(time.time())}-{secrets.token_hex(8)}"
    folder = IMPORT_JOB_DIR / token
    folder.mkdir(parents=True, exist_ok=False)
    csv_path = folder / "import.csv"
    csv_upload.save(csv_path)
    if not csv_path.exists() or csv_path.stat().st_size <= 0:
        shutil.rmtree(folder, ignore_errors=True)
        raise ValueError("CSV file was empty.")
    payload = {
        "csv_path": str(csv_path),
        "staging_dir": str(folder),
        "csv_filename": safe_upload_filename(csv_upload.filename),
    }
    if media_upload is not None and media_upload.filename:
        archive_name = safe_upload_filename(media_upload.filename)
        archive_path = folder / f"media-{archive_name}"
        media_upload.save(archive_path)
        if not archive_path.exists() or archive_path.stat().st_size <= 0:
            shutil.rmtree(folder, ignore_errors=True)
            raise ValueError("Media archive file was empty.")
        payload.update({
            "archive_path": str(archive_path),
            "archive_filename": archive_name,
            "archive_size": archive_path.stat().st_size,
        })
    return payload


def run_guess_library_bulk_import(
    guild_id,
    csv_path,
    media_archive_path="",
    media_archive_filename="",
    actor_id="",
    actor_name="",
    job_id=None,
):
    config_data = load_config()
    if guild_id not in set(config_data.get("guilds", {}).keys()):
        raise ValueError("Choose a valid Discord server.")
    update_guess_import_progress(job_id, stage="reading_csv", guild_id=guild_id)
    raw_content = Path(csv_path).read_bytes()
    if not raw_content:
        raise ValueError("CSV file was empty.")
    try:
        decoded = raw_content.decode("utf-8-sig")
    except UnicodeDecodeError as decode_error:
        raise ValueError("CSV must be UTF-8 encoded.") from decode_error
    reader = csv.DictReader(io.StringIO(decoded))
    if not reader.fieldnames:
        raise ValueError("CSV must include a header row.")

    media_archive = None
    media_lookup = {}
    stored_upload = None
    if media_archive_path:
        update_guess_import_progress(
            job_id,
            stage="opening_archive",
            guild_id=guild_id,
            archive=media_archive_filename or Path(media_archive_path).name,
            archive_size=Path(media_archive_path).stat().st_size if Path(media_archive_path).exists() else 0,
        )
        stored_upload = LocalStoredUpload(
            media_archive_filename or Path(media_archive_path).name,
            media_archive_path,
        )
        try:
            media_archive, media_lookup = open_guess_media_zip(stored_upload)
        finally:
            stored_upload.close()
        update_guess_import_progress(
            job_id,
            stage="archive_indexed",
            guild_id=guild_id,
            media_entries=len(media_lookup),
        )

    max_text_length = int(
        config_data.get("limits", {}).get(
            "max_text_length",
            DEFAULT_LIMITS["max_text_length"],
        )
    )
    imported = 0
    imported_with_media = 0
    missing_media = 0
    skipped = 0
    saved_media_paths = []
    now = utc_now_iso()
    storage_limit = guild_storage_limit(
        config_data.get("guilds", {}).get(guild_id, {})
    )
    try:
        with database() as connection:
            for row_number, raw_row in enumerate(reader, start=1):
                row = {
                    str(key or "").strip().lower(): str(value or "").strip()
                    for key, value in raw_row.items()
                }
                answer_value = (
                    row.get("answer")
                    or row.get("answers")
                    or row.get("answer_aliases")
                    or ""
                )
                aliases_value = row.get("aliases") or ""
                alias_source = answer_value
                if aliases_value:
                    alias_source = alias_source + "|" + aliases_value.replace(",", "|")
                answer_aliases = parse_answer_aliases(alias_source)
                if not answer_aliases:
                    skipped += 1
                    continue
                answer_display = answer_aliases[0]["display"]
                normalized_answer = answer_aliases[0]["normalized"]
                title = (row.get("title") or answer_display)[:120]
                prompt_text = (row.get("prompt_text") or row.get("prompt") or "")[:max_text_length]
                category = (row.get("category") or "")[:80]
                hint_text = (row.get("hint") or row.get("hint_text") or "")[:500]
                pack_name = (row.get("pack") or row.get("pack_name") or "")[:80]
                tags = parse_metadata_list(row.get("tags") or "")
                notes = (row.get("notes") or "")[:1000]
                enabled = parse_enabled_field(row.get("enabled"), True)
                try:
                    auto_hint_minutes = int(row.get("auto_hint_minutes") or "0")
                except ValueError:
                    auto_hint_minutes = 0
                auto_hint_minutes = max(0, min(1440, auto_hint_minutes))
                requested_status = (row.get("status") or "draft").lower()
                media_filename = row.get("media_filename") or row.get("media") or ""
                media_info = None
                if media_filename:
                    media_key = zip_media_lookup_key(media_filename)
                    media_entry = media_lookup.get(media_key) or media_lookup.get(
                        zip_media_lookup_key(Path(media_filename).name)
                    )
                    if media_entry:
                        if storage_limit and guild_media_size(guild_id) + int(media_entry.file_size or 0) > storage_limit:
                            raise ValueError("This server has reached its configured media storage limit.")
                        media_info = save_guess_library_zip_media(
                            guild_id,
                            media_archive,
                            media_entry,
                            config_data.get("limits", {}),
                        )
                        saved_media_paths.append(media_info["path"])
                        imported_with_media += 1
                    else:
                        missing_media += 1
                status = "draft"
                if requested_status == "disabled":
                    status = "disabled"
                elif requested_status == "active" and media_info:
                    status = "active"
                connection.execute("""
                    INSERT INTO guess_library_items (
                        guild_id, title, answer, answer_display,
                        answer_aliases_json, prompt_text, category,
                        tags_json, pack_name, enabled, notes,
                        hint_text, auto_hint_minutes, media_path,
                        media_name, media_type, media_size,
                        media_metadata_json, status, times_used,
                        created_by, created_at, updated_at
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, ?, ?, ?)
                """, (
                    guild_id,
                    title,
                    normalized_answer,
                    answer_display,
                    json.dumps(answer_aliases, separators=(",", ":")),
                    prompt_text,
                    category,
                    json.dumps(tags, separators=(",", ":")),
                    pack_name,
                    enabled,
                    notes,
                    hint_text,
                    auto_hint_minutes,
                    media_info["path"] if media_info else "",
                    media_info["name"] if media_info else "",
                    media_info["type"] if media_info else "unknown",
                    int(media_info["size"] or 0) if media_info else 0,
                    json.dumps(media_info["metadata"], separators=(",", ":")) if media_info else "{}",
                    status,
                    actor_name,
                    now,
                    now,
                ))
                imported += 1
                if job_id and (row_number == 1 or row_number % 10 == 0):
                    update_guess_import_progress(
                        job_id,
                        stage="importing_rows",
                        guild_id=guild_id,
                        rows_seen=row_number,
                        imported=imported,
                        attached_media=imported_with_media,
                        missing_media=missing_media,
                        skipped=skipped,
                    )
            add_admin_audit_log(
                connection,
                guild_id,
                "dashboard_bulk_import_guess_library",
                actor_id,
                actor_name,
                "guess_library_item",
                "",
                (
                    f"Imported {imported} library item(s); "
                    f"attached media to {imported_with_media}; "
                    f"missing media for {missing_media}; skipped {skipped}."
                ),
            )
    except Exception:
        for saved_path in saved_media_paths:
            delete_guess_library_media(saved_path)
        raise
    finally:
        if media_archive is not None:
            media_archive.close()
    result = {
        "stage": "complete",
        "guild_id": guild_id,
        "imported": imported,
        "attached_media": imported_with_media,
        "missing_media": missing_media,
        "skipped": skipped,
    }
    update_guess_import_progress(job_id, **result)
    return result
def delete_guess_library_media(stored_path):
    relative_path = media_relative_path(stored_path)
    if not relative_path:
        return
    file_path = (MEDIA_DIR / relative_path).resolve()
    try:
        file_path.relative_to(MEDIA_DIR)
    except ValueError:
        return
    if file_path.is_file():
        try:
            file_path.unlink()
        except OSError:
            pass
    thumb_path = thumbnail_path_for_media(file_path)
    if thumb_path and thumb_path.is_file():
        try:
            thumb_path.unlink()
        except OSError:
            pass


def validate_time(value):
    value = str(value or "").strip()
    if not re.match(r"^\d{2}:\d{2}$", value):
        raise ValueError("Time must be HH:MM.")
    hour, minute = [int(part) for part in value.split(":")]
    if hour > 23 or minute > 59:
        raise ValueError("Time must be between 00:00 and 23:59.")
    return value


def feature_enabled(guild_config, feature):
    if (guild_config or {}).get("bot_access_disabled"):
        return False
    features = (guild_config or {}).get("features") or {}
    return bool(features.get(feature, DEFAULT_FEATURES.get(feature, True)))


def feature_guild_ids(config_data, feature):
    return {
        guild_id
        for guild_id, guild_config in (config_data.get("guilds") or {}).items()
        if feature_enabled(guild_config, feature)
    }


def guild_id_filter(column, guild_ids):
    guild_ids = sorted(str(guild_id) for guild_id in (guild_ids or set()))
    if not guild_ids:
        return "1 = 0", []
    placeholders = ", ".join("?" for _ in guild_ids)
    return f"{column} IN ({placeholders})", guild_ids


def admin_scope_filter(column, config_data=None, include_global=False, minimum_role="moderator"):
    if is_bot_owner_username(current_admin_username()):
        return "1 = 1", []
    filter_sql, parameters = guild_id_filter(
        column,
        current_admin_allowed_guild_ids(config_data, minimum_role),
    )
    if include_global:
        filter_sql = f"({filter_sql} OR {column} IS NULL OR {column} = '')"
    return filter_sql, parameters


def current_endpoint_minimum_guild_role(default_role="moderator"):
    if not has_request_context():
        return normalize_role(default_role)
    return normalize_role(
        ADMIN_ENDPOINT_GUILD_ROLE_REQUIREMENTS.get(
            request.endpoint,
            default_role,
        )
    )


def guild_options(config_data=None, public_only=False, cross_server_only=False, minimum_role=None):
    config_data = config_data or load_config()
    allowed_admin_ids = None
    allowed_account_ids = None
    if has_request_context() and is_admin_logged_in() and not is_bot_owner_username(current_admin_username()):
        allowed_admin_ids = current_admin_allowed_guild_ids(
            config_data,
            minimum_role or current_endpoint_minimum_guild_role(),
        )
    elif public_only and has_request_context() and is_account_logged_in():
        allowed_account_ids = current_account_allowed_guild_ids(config_data)
    options = []
    for guild_id, guild_config in sorted(
        (config_data.get("guilds") or {}).items(),
        key=lambda item: (
            item[1].get("guild_name") or item[0]
        ).casefold(),
    ):
        if guild_config.get("bot_access_disabled") and (
            not has_request_context() or not is_bot_owner_username(current_admin_username())
        ):
            continue
        if allowed_admin_ids is not None and str(guild_id) not in allowed_admin_ids:
            continue
        if allowed_account_ids is not None and str(guild_id) not in allowed_account_ids:
            continue
        if public_only and not feature_enabled(guild_config, "public_gallery"):
            continue
        if cross_server_only and not feature_enabled(guild_config, "cross_server_gallery"):
            continue
        display_name = (
            guild_config.get("brand_name")
            or guild_config.get("guild_name")
            or f"Discord {guild_id}"
        )
        options.append({
            "id": guild_id,
            "name": display_name,
            "guild_name": guild_config.get("guild_name") or display_name,
            "brand_accent": guild_config.get("brand_accent") or "#7c9cff",
            "brand_logo_url": guild_config.get("brand_logo_url") or "",
            "bot_nickname": guild_config.get("bot_nickname") or "",
        })
    return options


def guild_name_map(config_data=None):
    return {
        option["id"]: option["name"]
        for option in guild_options(config_data)
    }


def sidebar_server_options(config_data=None):
    config_data = config_data or load_config()
    allowed_ids = set()
    if has_request_context() and is_admin_logged_in():
        allowed_ids = current_admin_allowed_guild_ids(config_data)
    elif has_request_context() and is_account_logged_in():
        allowed_ids = current_account_allowed_guild_ids(config_data)
    options = []
    for guild_id, guild_config in sorted(
        (config_data.get("guilds") or {}).items(),
        key=lambda item: (
            item[1].get("guild_name") or item[0]
        ).casefold(),
    ):
        if str(guild_id) not in allowed_ids:
            continue
        display_name = (
            guild_config.get("brand_name")
            or guild_config.get("guild_name")
            or f"Discord {guild_id}"
        )
        options.append({
            "id": guild_id,
            "name": display_name,
        })
    return options


def public_app_metadata():
    public_url = (os.getenv("SDAC_PUBLIC_URL") or "").strip().rstrip("/")
    domain = (os.getenv("SDAC_DOMAIN") or "").strip().strip("/")
    if not public_url and domain:
        public_url = f"https://{domain}"
    invite_url = bot_invite_url(public_url=public_url)
    return {
        "name": os.getenv("SDAC_PUBLIC_BOT_NAME", "Sana-Chan Bot").strip() or "Sana-Chan Bot",
        "tagline": os.getenv("SDAC_PUBLIC_TAGLINE", "Screenshot, media, and guessing-game management for Discord communities.").strip(),
        "client_id": bot_client_id(),
        "invite_url": invite_url,
        "public_url": public_url,
        "support_url": os.getenv("SDAC_SUPPORT_URL", "").strip(),
        "privacy_url": os.getenv("SDAC_PRIVACY_URL", "").strip() or (f"{public_url}/privacy" if public_url else ""),
        "terms_url": os.getenv("SDAC_TERMS_URL", "").strip() or (f"{public_url}/terms" if public_url else ""),
        "github_url": os.getenv("SDAC_GITHUB_URL", "https://github.com/BaytaeTistear/SDAC-Bot").strip(),
        "wiki_url": os.getenv("SDAC_WIKI_URL", "https://github.com/BaytaeTistear/SDAC-Bot/wiki").strip(),
        "permissions": os.getenv("SDAC_BOT_PERMISSIONS", "274878221376").strip(),
    }


def bot_client_id():
    return (
        os.getenv("SDAC_BOT_CLIENT_ID")
        or os.getenv("DISCORD_CLIENT_ID")
        or DISCORD_OAUTH_CLIENT_ID
        or ""
    ).strip()


def bot_invite_url(public_url=None):
    client_id = bot_client_id()
    if not client_id:
        return ""
    permissions = os.getenv("SDAC_BOT_PERMISSIONS", "274878221376").strip() or "274878221376"
    scopes = os.getenv("SDAC_BOT_SCOPES", "bot applications.commands").strip() or "bot applications.commands"
    params = {
        "client_id": client_id,
        "permissions": permissions,
        "scope": scopes,
    }
    redirect_uri = os.getenv("SDAC_BOT_INVITE_REDIRECT_URI", "").strip()
    if redirect_uri:
        params["redirect_uri"] = redirect_uri
        params["response_type"] = "code"
    elif public_url:
        params["integration_type"] = os.getenv("SDAC_BOT_INTEGRATION_TYPE", "0").strip() or "0"
    return "https://discord.com/oauth2/authorize?" + urlencode(params, quote_via=quote_plus)


def onboarding_item(ok, label, fix, optional=False):
    return {
        "ok": bool(ok),
        "label": label,
        "fix": fix,
        "optional": optional,
    }


def latest_setup_test_rows():
    with closing(connect_db()) as connection:
        rows = connection.execute("""
            SELECT *
            FROM setup_test_runs
            ORDER BY created_at DESC, id DESC
        """).fetchall()
    latest = {}
    for row in rows:
        guild_id = row["guild_id"] or ""
        if guild_id and guild_id not in latest:
            latest[guild_id] = row
    return latest


def season_leaderboard(connection, season, limit=10):
    return connection.execute("""
        SELECT user_id, username, COUNT(*) AS points
        FROM guess_correct_guesses
        WHERE guild_id = ?
          AND guessed_at >= ?
          AND guessed_at <= ?
        GROUP BY user_id, username
        ORDER BY points DESC, MIN(guessed_at) ASC
        LIMIT ?
    """, (
        season["guild_id"],
        season["starts_at"],
        season["ends_at"],
        limit,
    )).fetchall()


def build_onboarding_rows(config_data):
    rows = []
    setup_tests = latest_setup_test_rows()
    allowed_ids = (
        current_admin_allowed_guild_ids(config_data)
        if has_request_context() and is_admin_logged_in()
        else set((config_data.get("guilds") or {}).keys())
    )
    for guild_id, guild_config in sorted(
        (config_data.get("guilds") or {}).items(),
        key=lambda item: (
            item[1].get("guild_name") or item[0]
        ).casefold(),
    ):
        if str(guild_id) not in allowed_ids:
            continue
        categories = guild_config.get("categories") or {}
        approval_enabled = guild_config.get("approval_enabled", False)
        backup = {
            **DEFAULT_GUILD_EXTERNAL_BACKUP,
            **(guild_config.get("external_backup") or {}),
        }
        digest = guild_config.get("notification_digest") or {}
        items = [
            onboarding_item(
                guild_config.get("submit_channel"),
                "Submit channel configured",
                "/setsubmit #channel",
            ),
            onboarding_item(
                categories,
                "At least one submission category",
                "/setcategory category #channel",
            ),
            onboarding_item(
                guild_config.get("timezone"),
                "Timezone configured",
                "/settimezone America/New_York",
            ),
            onboarding_item(
                not approval_enabled or guild_config.get("approval_channel"),
                "Approval channel ready when approval is enabled",
                "/setapproval enabled #channel",
            ),
            onboarding_item(
                guild_config.get("error_channel"),
                "Error notification channel",
                "/seterrorchannel #staff-errors",
                optional=True,
            ),
            onboarding_item(
                guild_config.get("game_summary_channel"),
                "Guessing game summary channel",
                "/setgamesummarychannel #channel",
                optional=True,
            ),
            onboarding_item(
                guild_config.get("daily_top_channel"),
                "Weekly top submissions channel",
                "/setweeklychannel #channel",
                optional=True,
            ),
            onboarding_item(
                guild_config.get("admin_role_ids"),
                "SDAC admin role",
                "/setadminrole @role",
                optional=True,
            ),
            onboarding_item(
                guild_config.get("brand_name"),
                "Server branding",
                "/setbranding name:#7c9cff",
                optional=True,
            ),
            onboarding_item(
                guild_config.get("bot_nickname"),
                "Bot name chosen",
                "/sana -> Setup -> Bot Name",
                optional=True,
            ),
            onboarding_item(
                config_data.get("bot_avatar_updated_at"),
                "Bot image chosen",
                "/sana -> Setup -> Bot Image or dashboard Settings",
                optional=True,
            ),
            onboarding_item(
                backup.get("enabled") and backup.get("remote"),
                "Per-server backup target",
                "/backupguide provider then /backupsetup",
                optional=True,
            ),
            onboarding_item(
                backup.get("zip_backups", True),
                "Zip backup archives enabled",
                "/backupsetup zip_backups:true",
                optional=True,
            ),
            onboarding_item(
                digest.get("enabled") and digest.get("channel_id"),
                "Admin notification digest",
                "/setdigest true weekly #channel",
                optional=True,
            ),
        ]
        required_items = [item for item in items if not item["optional"]]
        optional_items = [item for item in items if item["optional"]]
        weighted_total = len(required_items) * 2 + len(optional_items)
        weighted_complete = (
            sum(1 for item in required_items if item["ok"]) * 2
            + sum(1 for item in optional_items if item["ok"])
        )
        health_score = (
            round((weighted_complete / weighted_total) * 100)
            if weighted_total
            else 100
        )
        rows.append({
            "id": guild_id,
            "name": (
                guild_config.get("brand_name")
                or guild_config.get("guild_name")
                or f"Discord {guild_id}"
            ),
            "guild_name": guild_config.get("guild_name") or f"Discord {guild_id}",
            "brand_accent": guild_config.get("brand_accent") or "#7c9cff",
            "brand_logo_url": guild_config.get("brand_logo_url") or "",
            "bot_nickname": guild_config.get("bot_nickname") or "",
            "last_setup_test": setup_tests.get(guild_id),
            "command_steps": [
                "/setup",
                "/setupstatus",
                "/setuptest",
                "/settings",
                "/checkpermissions",
            ],
            "items": items,
            "complete_count": sum(1 for item in required_items if item["ok"]),
            "total_count": len(required_items),
            "optional_complete_count": sum(
                1 for item in optional_items if item["ok"]
            ),
            "optional_total_count": len(optional_items),
            "health_score": health_score,
        })
    return rows


def selected_guild_id(options):
    valid_ids = {option["id"] for option in options}
    requested = request.values.get("guild_id", "").strip()
    restricted_admin = is_admin_logged_in() and current_admin_role() != "bot_owner"
    if requested == "all":
        session.pop("sdac_guild_id", None)
        return ""
    if requested in valid_ids:
        session["sdac_guild_id"] = requested
        return requested

    stored = session.get("sdac_guild_id", "")
    if stored in valid_ids:
        return stored
    session.pop("sdac_guild_id", None)
    if restricted_admin and valid_ids:
        selected = sorted(valid_ids)[0]
        session["sdac_guild_id"] = selected
        return selected
    return ""


def safe_backup_label(label):
    return "".join(
        character if character.isalnum() or character in "_.-" else "-"
        for character in label
    ).strip("-") or "backup"


def cleanup_old_database_backups():
    if not BACKUP_DIR.exists():
        return
    backups = sorted(
        BACKUP_DIR.glob("sdac-*.db"),
        key=lambda path: path.stat().st_mtime,
        reverse=True,
    )
    for backup_path in backups[BACKUP_KEEP_COUNT:]:
        try:
            backup_path.unlink()
        except OSError:
            pass


def create_database_backup(label):
    if not DB_FILE.exists():
        return None, False, "Database file does not exist."

    BACKUP_DIR.mkdir(parents=True, exist_ok=True)
    backup_path = BACKUP_DIR / f"sdac-{safe_backup_label(label)}.db"
    if backup_path.exists():
        return backup_path, False, "Backup already exists."

    source = sqlite3.connect(DB_FILE)
    destination = sqlite3.connect(backup_path)
    try:
        with destination:
            source.backup(destination)
    finally:
        destination.close()
        source.close()

    cleanup_old_database_backups()
    record_backup_integrity(backup_path)
    return backup_path, True, "Backup created."


def backup_sha256(path):
    hasher = hashlib.sha256()
    with Path(path).open("rb") as file:
        for chunk in iter(lambda: file.read(1024 * 1024), b""):
            hasher.update(chunk)
    return hasher.hexdigest()


def record_backup_integrity(backup_path, restore_status="", restore_details=""):
    if not backup_path or not Path(backup_path).is_file():
        return
    backup_path = Path(backup_path)
    stat = backup_path.stat()
    digest = backup_sha256(backup_path)
    with database() as connection:
        connection.execute("""
            INSERT INTO backup_integrity (
                backup_name, sha256, size_bytes, restore_status,
                restore_details, checked_at
            )
            VALUES (?, ?, ?, ?, ?, ?)
            ON CONFLICT(backup_name) DO UPDATE SET
                sha256 = excluded.sha256,
                size_bytes = excluded.size_bytes,
                restore_status = COALESCE(NULLIF(excluded.restore_status, ''), backup_integrity.restore_status),
                restore_details = COALESCE(NULLIF(excluded.restore_details, ''), backup_integrity.restore_details),
                checked_at = excluded.checked_at
        """, (
            backup_path.name,
            digest,
            int(stat.st_size),
            restore_status,
            restore_details,
            utc_now_iso(),
        ))


