def create_pending_admin_action(
    action_type,
    target_type,
    target_id,
    payload,
    actor_id,
    actor_name,
    guild_id=None,
):
    with database() as connection:
        cursor = connection.execute("""
            INSERT INTO pending_admin_actions (
                guild_id, action_type, target_type, target_id, payload_json,
                requested_by, requested_by_name, status, created_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, 'pending', ?)
        """, (
            str(guild_id) if guild_id is not None else None,
            action_type,
            target_type,
            str(target_id or ""),
            json.dumps(payload or {}, separators=(",", ":")),
            str(actor_id or ""),
            str(actor_name or ""),
            utc_now_iso(),
        ))
        action_id = cursor.lastrowid
        add_admin_audit_log(
            connection,
            guild_id,
            "pending_admin_action_created",
            actor_id,
            actor_name,
            "pending_admin_action",
            action_id,
            f"Requested approval for {action_type}.",
        )
    return action_id


def approval_required_redirect(
    action_type,
    target_type,
    target_id,
    payload,
    actor_id,
    actor_name,
    guild_id=None,
    endpoint="admin_approvals",
    route_values=None,
):
    action_id = create_pending_admin_action(
        action_type,
        target_type,
        target_id,
        payload,
        actor_id,
        actor_name,
        guild_id,
    )
    values = {"key": ADMIN_KEY, **(route_values or {})}
    values["notice"] = (
        f"Created pending approval #{action_id}. A second admin must approve it."
    )
    return redirect(url_for(endpoint, **values))


def pending_admin_action_rows(status="pending", limit=100):
    where = []
    params = []
    if status and status != "all":
        where.append("status = ?")
        params.append(status)
    scope_sql, scope_params = admin_scope_filter("guild_id", load_config(), include_global=True)
    if scope_sql:
        where.append(scope_sql)
        params.extend(scope_params)
    where_sql = "WHERE " + " AND ".join(where) if where else ""
    with closing(connect_db()) as connection:
        rows = connection.execute(f"""
            SELECT *
            FROM pending_admin_actions
            {where_sql}
            ORDER BY created_at DESC, id DESC
            LIMIT ?
        """, params + [int(limit)]).fetchall()
    actions = []
    for row in rows:
        item = dict(row)
        try:
            item["payload"] = json.loads(item.get("payload_json") or "{}")
        except (TypeError, ValueError):
            item["payload"] = {}
        actions.append(item)
    return actions


def execute_pending_admin_action(row, actor_id, actor_name):
    payload = json.loads(row["payload_json"] or "{}")
    action_type = row["action_type"]
    if action_type == "delete_submission":
        return remove_submission_from_dashboard(
            int(payload.get("submission_id") or row["target_id"] or 0),
            actor_id,
            actor_name,
        )
    if action_type == "privacy_delete_user_data":
        details = delete_user_privacy_data(
            payload.get("guild_id") or row["guild_id"],
            payload.get("user_id") or row["target_id"],
            actor_id,
            actor_name,
        )
        return True, f"Deleted privacy data: {details}"
    if action_type == "delete_orphans":
        deleted = delete_orphaned_media_files()
        return True, f"Deleted {deleted} orphaned media file(s)."
    if action_type == "prune_backed_up_originals":
        job_id = queue_background_job(
            "prune_backed_up_originals",
            guild_id=payload.get("guild_id"),
            payload={"guild_id": payload.get("guild_id")},
            actor_id=actor_id,
            actor_name=actor_name,
        )
        return True, f"Queued backed-up original pruning as job #{job_id}."
    if action_type == "rollback_latest_snapshot":
        job_id = queue_background_job(
            "rollback_latest_snapshot",
            actor_id=actor_id,
            actor_name=actor_name,
        )
        return True, f"Queued rollback as background job #{job_id}."
    if action_type == "quarantine_submission":
        return quarantine_submission_media(
            int(payload.get("submission_id") or row["target_id"] or 0),
            payload.get("reason") or "Approved admin quarantine",
            actor_id,
            actor_name,
        )
    return False, f"Unknown pending action type: {action_type}"


def resolve_pending_admin_action(action_id, decision, actor_id, actor_name):
    with closing(connect_db()) as connection:
        row = connection.execute("""
            SELECT *
            FROM pending_admin_actions
            WHERE id = ?
        """, (action_id,)).fetchone()
    if not row:
        return False, "Pending action not found."
    if row["status"] != "pending":
        return False, "Pending action is already resolved."
    if str(row["requested_by"] or "") == str(actor_id or ""):
        return False, "A second admin must approve this action."
    if not can_admin_access_guild(row["guild_id"], load_config()):
        abort(403)

    now = utc_now_iso()
    if decision == "deny":
        ok = True
        message = "Pending action denied."
        status = "denied"
    else:
        ok, message = execute_pending_admin_action(row, actor_id, actor_name)
        status = "complete" if ok else "failed"
    with database() as connection:
        connection.execute("""
            UPDATE pending_admin_actions
            SET status = ?, approved_by = ?, approved_by_name = ?,
                approved_at = ?, completed_at = ?, result_text = ?
            WHERE id = ?
        """, (
            status,
            str(actor_id or ""),
            str(actor_name or ""),
            now,
            now,
            message,
            action_id,
        ))
        add_admin_audit_log(
            connection,
            row["guild_id"],
            f"pending_admin_action_{status}",
            actor_id,
            actor_name,
            "pending_admin_action",
            action_id,
            message,
        )
    return ok, message


def has_valid_key():
    return (
        request.args.get("key") == ADMIN_KEY
        or request.form.get("key") == ADMIN_KEY
    )


def get_csrf_token():
    token = session.get("csrf_token")
    if not token:
        token = secrets.token_urlsafe(32)
        session["csrf_token"] = token
    return token


def require_csrf_token():
    expected = session.get("csrf_token", "")
    provided = request.form.get("csrf_token", "")
    if not expected or not secrets.compare_digest(provided, expected):
        abort(400)


def login_remote_key():
    return request.remote_addr or "unknown"


def prune_login_attempts(remote_key):
    cutoff = time.time() - LOGIN_WINDOW_SECONDS
    attempts = [
        attempt
        for attempt in LOGIN_ATTEMPTS.get(remote_key, [])
        if attempt >= cutoff
    ]
    if attempts:
        LOGIN_ATTEMPTS[remote_key] = attempts
    else:
        LOGIN_ATTEMPTS.pop(remote_key, None)
    return attempts


def login_rate_limited(remote_key):
    return len(prune_login_attempts(remote_key)) >= LOGIN_MAX_ATTEMPTS


def record_login_failure(remote_key):
    attempts = prune_login_attempts(remote_key)
    attempts.append(time.time())
    LOGIN_ATTEMPTS[remote_key] = attempts


def clear_login_failures(remote_key):
    LOGIN_ATTEMPTS.pop(remote_key, None)


def normalize_email(email):
    value = str(email or "").strip().casefold()
    if not value:
        return ""
    if len(value) > 254 or not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", value):
        raise ValueError("Enter a valid email address.")
    return value


def normalize_account_username(username, email=""):
    value = str(username or "").strip().casefold()
    if not value and email:
        value = str(email).split("@", 1)[0].casefold()
    value = re.sub(r"[^a-z0-9_.-]+", "-", value).strip("-._")
    if not value:
        raise ValueError("Username is required when it cannot be derived from email.")
    if not re.match(r"^[a-z0-9_.-]{3,40}$", value):
        raise ValueError(
            "Username must be 3-40 letters, numbers, dots, dashes, or underscores."
        )
    return value


def normalize_discord_user_id(value):
    value = str(value or "").strip()
    if not value:
        return ""
    if not value.isdigit() or len(value) < 15 or len(value) > 25:
        raise ValueError("Discord user ID must be numeric.")
    return value


def unique_account_username(connection, preferred):
    base = preferred[:36].strip("-._") or "user"
    candidate = base
    suffix = 2
    while connection.execute(
        "SELECT 1 FROM dashboard_admin_users WHERE username = ?",
        (candidate,),
    ).fetchone():
        candidate = f"{base[:36]}-{suffix}"
        suffix += 1
        if suffix > 9999:
            raise ValueError("Could not create a unique username.")
    return candidate


def is_bot_owner_username(username):
    username = str(username or "").strip().casefold()
    if not username:
        return False
    if username == OWNER_OVERRIDE_USERNAME:
        return True
    try:
        with closing(connect_db()) as connection:
            row = connection.execute("""
                SELECT 1
                FROM dashboard_bot_owners
                WHERE lower(username) = ?
                LIMIT 1
            """, (username,)).fetchone()
            if row:
                return True
            user = connection.execute("""
                SELECT 1
                FROM dashboard_admin_users
                WHERE lower(username) = ?
                  AND role = 'bot_owner'
                  AND COALESCE(disabled, 0) = 0
                LIMIT 1
            """, (username,)).fetchone()
            return user is not None
    except sqlite3.Error:
        return False


def remember_dashboard_session():
    session.permanent = True
    session.modified = True


def is_admin_logged_in():
    return bool(session.get("sdac_admin"))


def is_account_logged_in():
    return bool(session.get("sdac_account_username"))


def current_account_username():
    return session.get("sdac_account_username") or ""


def current_requested_guild_id():
    if not has_request_context():
        return ""
    requested = request.values.get("guild_id", "").strip()
    if requested == "all":
        return ""
    return requested or session.get("sdac_guild_id", "")


def current_account_allowed_guild_ids(config_data=None):
    config_data = config_data or load_config()
    all_ids = {str(guild_id) for guild_id in (config_data.get("guilds") or {})}
    if is_bot_owner_username(current_account_username()):
        return all_ids
    if is_admin_logged_in():
        return current_admin_allowed_guild_ids(config_data, "user")
    access_ids = set(dashboard_user_server_access_map(current_account_username()))
    if access_ids:
        return all_ids & access_ids
    scoped_ids = set(parse_guild_scope(session.get("sdac_account_guild_ids", [])))
    if not scoped_ids and is_account_logged_in():
        account = dashboard_user(current_account_username())
        scoped_ids = set(parse_guild_scope(account["guild_ids_json"] if account else []))
        session["sdac_account_guild_ids"] = sorted(scoped_ids)
    return all_ids & scoped_ids


def current_admin_username():
    return session.get("sdac_admin_username") or "web-admin"


def current_admin_explicit_guild_id():
    if not has_request_context():
        return ""
    requested = request.values.get("guild_id", "").strip()
    if requested == "all":
        return ""
    return requested


def current_admin_legacy_scoped_ids(config_data=None):
    config_data = config_data or load_config()
    all_ids = {str(guild_id) for guild_id in (config_data.get("guilds") or {})}
    scoped_ids = set(parse_guild_scope(session.get("sdac_admin_guild_ids", [])))
    if not scoped_ids:
        user = dashboard_user(current_admin_username())
        scoped_ids = set(parse_guild_scope(user["guild_ids_json"] if user else []))
        session["sdac_admin_guild_ids"] = sorted(scoped_ids)
    return all_ids & scoped_ids


def current_admin_role_for_guild(guild_id, config_data=None):
    guild_id = str(guild_id or "").strip()
    if is_bot_owner_username(current_admin_username()):
        return "bot_owner"
    if not guild_id:
        return current_admin_max_scoped_role(config_data)
    role_map = dashboard_user_server_access_map(current_admin_username())
    if guild_id in role_map:
        return normalize_role(role_map[guild_id])
    if guild_id in current_admin_legacy_scoped_ids(config_data):
        return normalize_role(session.get("sdac_admin_role") or "user")
    return "user"


def current_admin_max_scoped_role(config_data=None):
    if is_bot_owner_username(current_admin_username()):
        return "bot_owner"
    config_data = config_data or load_config()
    all_ids = {str(guild_id) for guild_id in (config_data.get("guilds") or {})}
    max_role = "user"
    for guild_id, role in dashboard_user_server_access_map(current_admin_username()).items():
        if guild_id in all_ids and ROLE_LEVELS[normalize_role(role)] > ROLE_LEVELS[max_role]:
            max_role = normalize_role(role)
    legacy_role = normalize_role(session.get("sdac_admin_role") or "user")
    for guild_id in current_admin_legacy_scoped_ids(config_data):
        if ROLE_LEVELS[legacy_role] > ROLE_LEVELS[max_role]:
            max_role = legacy_role
    return max_role


def current_admin_role():
    guild_id = current_admin_explicit_guild_id()
    if guild_id:
        return current_admin_role_for_guild(guild_id)
    return current_admin_max_scoped_role()


def safe_next_url(value, fallback="/"):
    value = str(value or "").strip()
    if value.startswith("/") and not value.startswith("//"):
        return value
    return fallback


def has_admin_role(required_role, guild_id=None):
    role = current_admin_role_for_guild(guild_id) if guild_id else current_admin_role()
    return ROLE_LEVELS[normalize_role(role)] >= ROLE_LEVELS[normalize_role(required_role)]


def has_sidebar_admin_role(required_role):
    role = current_admin_max_scoped_role()
    return ROLE_LEVELS[normalize_role(role)] >= ROLE_LEVELS[normalize_role(required_role)]


def can_assign_dashboard_role(role):
    role = normalize_role(role)
    if role == "bot_owner":
        return has_admin_role("bot_owner")
    if role in {"admin", "owner"}:
        return has_admin_role("owner")
    return has_admin_role("admin")


def current_admin_is_baytae_owner():
    if current_admin_username().casefold() != OWNER_OVERRIDE_USERNAME:
        return False
    if current_admin_role() not in {"owner", "bot_owner"}:
        return False
    user = dashboard_user(current_admin_username())
    return bool(user and normalize_role(user["role"]) in {"owner", "bot_owner"} and not int(user["disabled"] or 0))


def parse_database_datetime(value):
    if not value:
        return None
    try:
        parsed = datetime.fromisoformat(str(value))
    except (TypeError, ValueError):
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed


def owner_ban_code_session_key(target_username):
    return f"owner_ban_code:{str(target_username or '').strip().casefold()}"


def issue_owner_ban_code(target_username):
    code = "".join(secrets.choice("0123456789") for _ in range(6))
    session[owner_ban_code_session_key(target_username)] = {
        "code": code,
        "expires_at": (datetime.now(timezone.utc) + timedelta(
            seconds=OWNER_BAN_CODE_TTL_SECONDS,
        )).isoformat(),
    }
    return code


def valid_owner_ban_code(target_username, code):
    payload = session.get(owner_ban_code_session_key(target_username)) or {}
    if not payload or str(payload.get("code") or "") != str(code or "").strip():
        return False
    expires_at = parse_database_datetime(payload.get("expires_at"))
    if not expires_at or expires_at < datetime.now(timezone.utc):
        session.pop(owner_ban_code_session_key(target_username), None)
        return False
    session.pop(owner_ban_code_session_key(target_username), None)
    return True


def can_promote_dashboard_user(target_role, new_role, target_username=""):
    target_role = normalize_role(target_role)
    new_role = normalize_role(new_role)
    target_username = str(target_username or "").strip().casefold()
    current_level = ROLE_LEVELS[current_admin_role()]
    target_level = ROLE_LEVELS[target_role]
    if current_level < ROLE_LEVELS["admin"]:
        return False
    if new_role == "bot_owner":
        if not has_admin_role("bot_owner"):
            return False
    elif new_role in {"admin", "owner"}:
        if not has_admin_role("owner"):
            return False
    elif not has_admin_role("admin"):
        return False
    if not has_admin_role("owner") and target_level >= current_level:
        return False
    if target_username == current_admin_username().casefold() and not has_admin_role("owner"):
        return False
    return True


def can_ban_dashboard_user(target_role="user", target_username="", owner_code=""):
    target_role = normalize_role(target_role)
    target_username = str(target_username or "").strip().casefold()
    current_username = current_admin_username().casefold()
    current_level = ROLE_LEVELS[current_admin_role()]
    target_level = ROLE_LEVELS[target_role]
    if current_level < ROLE_LEVELS["moderator"]:
        return False
    if target_username and target_username == current_username:
        return False
    if current_level > target_level:
        return True
    if (
        target_role in {"owner", "bot_owner"}
        and current_admin_is_baytae_owner()
        and target_username != OWNER_OVERRIDE_USERNAME
        and valid_owner_ban_code(target_username, owner_code)
    ):
        return True
    return False


def can_lockout_dashboard_target(target_role="user", target_username=""):
    target_role = normalize_role(target_role)
    target_username = str(target_username or "").strip().casefold()
    current_level = ROLE_LEVELS[current_admin_role()]
    target_level = ROLE_LEVELS[target_role]
    if current_level < ROLE_LEVELS["moderator"]:
        return False
    if target_username and target_username == current_admin_username().casefold():
        return False
    if target_level >= ROLE_LEVELS["moderator"]:
        return current_level > target_level
    return True


def can_manage_dashboard_user(target_role="user", target_username=""):
    target_role = normalize_role(target_role)
    target_username = str(target_username or "").strip().casefold()
    current_level = ROLE_LEVELS[current_admin_role()]
    target_level = ROLE_LEVELS[target_role]
    if current_level < ROLE_LEVELS["admin"]:
        return False
    if target_username == current_admin_username().casefold():
        return has_admin_role("owner")
    return current_level > target_level


def parse_guild_scope(raw_value):
    if raw_value is None:
        return []
    if isinstance(raw_value, (list, tuple, set)):
        return [
            str(item).strip()
            for item in raw_value
            if str(item).strip()
        ]
    text = str(raw_value or "").strip()
    if not text:
        return []
    try:
        parsed = json.loads(text)
        if isinstance(parsed, list):
            return parse_guild_scope(parsed)
    except json.JSONDecodeError:
        pass
    return [
        item.strip()
        for item in re.split(r"[\s,]+", text)
        if item.strip()
    ]


def current_admin_allowed_guild_ids(config_data=None, minimum_role="moderator"):
    config_data = config_data or load_config()
    minimum_role = normalize_role(minimum_role)
    all_ids = {
        str(guild_id)
        for guild_id in (config_data.get("guilds") or {})
    }
    if is_bot_owner_username(current_admin_username()):
        return all_ids
    access_map = dashboard_user_server_access_map(current_admin_username())
    allowed_ids = {
        guild_id
        for guild_id, role in access_map.items()
        if guild_id in all_ids
        and ROLE_LEVELS[normalize_role(role)] >= ROLE_LEVELS[minimum_role]
    }
    legacy_role = normalize_role(session.get("sdac_admin_role") or "user")
    if ROLE_LEVELS[legacy_role] >= ROLE_LEVELS[minimum_role]:
        allowed_ids |= current_admin_legacy_scoped_ids(config_data)
    return all_ids & allowed_ids


def can_admin_access_guild(guild_id, config_data=None, minimum_role="moderator"):
    if not has_request_context():
        return True
    if is_bot_owner_username(current_admin_username()):
        return True
    return ROLE_LEVELS[current_admin_role_for_guild(guild_id, config_data)] >= ROLE_LEVELS[normalize_role(minimum_role)]


def dashboard_user(username):
    username = str(username or "").strip().casefold()
    if not username:
        return None
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT username, email, display_name, discord_user_id,
                   password_hash, role, disabled, guild_ids_json, last_login_at
            FROM dashboard_admin_users
            WHERE username = ?
            LIMIT 1
        """, (username,)).fetchone()


def dashboard_user_by_login(identifier):
    value = str(identifier or "").strip().casefold()
    if not value:
        return None
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT username, email, display_name, discord_user_id,
                   password_hash, role, disabled, guild_ids_json, last_login_at
            FROM dashboard_admin_users
            WHERE username = ?
               OR lower(COALESCE(email, '')) = ?
            LIMIT 1
        """, (value, value)).fetchone()


def dashboard_user_count():
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT COUNT(*)
            FROM dashboard_admin_users
            WHERE disabled = 0
        """).fetchone()[0]


def dashboard_users():
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT username, email, display_name, discord_user_id, role, disabled,
                   guild_ids_json, created_at, updated_at, last_login_at,
                   approved_by, approved_at, notes
            FROM dashboard_admin_users
            ORDER BY disabled ASC, role DESC, username ASC
        """).fetchall()


def dashboard_user_server_access(username=""):
    raw_username = str(username or current_account_username() or "").strip()
    if not raw_username:
        return []
    username = normalize_account_username(raw_username)
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT username, guild_id, role, source, verified_at, updated_at
            FROM dashboard_user_server_access
            WHERE username = ?
            ORDER BY guild_id ASC
        """, (username,)).fetchall()


def dashboard_user_server_access_map(username=""):
    return {
        str(row["guild_id"]): normalize_role(row["role"])
        for row in dashboard_user_server_access(username)
    }


def upsert_user_server_access(connection, username, guild_ids, role="user", source="manual", preserve_existing_roles=True):
    username = normalize_account_username(username)
    role = normalize_role(role)
    now = utc_now_iso()
    rows = []
    for guild_id in sorted({str(item).strip() for item in guild_ids if str(item).strip()}):
        existing = connection.execute("""
            SELECT role
            FROM dashboard_user_server_access
            WHERE username = ? AND guild_id = ?
        """, (username, guild_id)).fetchone()
        row_role = normalize_role(existing["role"]) if existing and preserve_existing_roles else role
        connection.execute("""
            INSERT INTO dashboard_user_server_access (
                username, guild_id, role, source, verified_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?)
            ON CONFLICT(username, guild_id) DO UPDATE SET
                role = ?,
                source = excluded.source,
                verified_at = excluded.verified_at,
                updated_at = excluded.updated_at
        """, (
            username,
            guild_id,
            row_role,
            source,
            now,
            now,
            row_role,
        ))
        rows.append(guild_id)
    return rows


def prune_user_server_access(connection, username, guild_ids):
    username = normalize_account_username(username)
    guild_ids = sorted({str(item).strip() for item in guild_ids if str(item).strip()})
    if not guild_ids:
        connection.execute(
            "DELETE FROM dashboard_user_server_access WHERE username = ?",
            (username,),
        )
        return
    placeholders = ", ".join("?" for _ in guild_ids)
    connection.execute(f"""
        DELETE FROM dashboard_user_server_access
        WHERE username = ?
          AND guild_id NOT IN ({placeholders})
    """, [username] + guild_ids)



def set_user_server_role(connection, username, guild_id, role, source="manual"):
    username = normalize_account_username(username)
    guild_id = str(guild_id or "").strip()
    role = normalize_role(role)
    if not username or not guild_id:
        raise ValueError("A user and server are required.")
    now = utc_now_iso()
    connection.execute("""
        INSERT INTO dashboard_user_server_access (
            username, guild_id, role, source, verified_at, updated_at
        )
        VALUES (?, ?, ?, ?, ?, ?)
        ON CONFLICT(username, guild_id) DO UPDATE SET
            role = excluded.role,
            source = excluded.source,
            updated_at = excluded.updated_at
    """, (username, guild_id, role, source, now, now))


def remove_user_server_role(connection, username, guild_id):
    username = normalize_account_username(username)
    guild_id = str(guild_id or "").strip()
    if not username or not guild_id:
        raise ValueError("A user and server are required.")
    connection.execute(
        "DELETE FROM dashboard_user_server_access WHERE username = ? AND guild_id = ?",
        (username, guild_id),
    )
    user = connection.execute("""
        SELECT guild_ids_json
        FROM dashboard_admin_users
        WHERE username = ?
    """, (username,)).fetchone()
    if user:
        new_scope = sorted(set(parse_guild_scope(user["guild_ids_json"])) - {guild_id})
        connection.execute("""
            UPDATE dashboard_admin_users
            SET guild_ids_json = ?, updated_at = ?
            WHERE username = ?
        """, (json.dumps(new_scope, separators=(",", ":")), utc_now_iso(), username))
    return True


def dashboard_user_access_rows(user, config_data=None):
    config_data = config_data or load_config()
    configured = config_data.get("guilds") or {}
    username = normalize_account_username(user["username"] if user else "")
    if not username:
        return []
    if is_bot_owner_username(username) or normalize_role(user["role"] if user else "") == "bot_owner":
        return [
            {
                "id": str(guild_id),
                "name": guild_config.get("brand_name") or guild_config.get("guild_name") or f"Discord {guild_id}",
                "role": "bot_owner",
                "source": "bot owner",
            }
            for guild_id, guild_config in sorted(configured.items(), key=lambda item: (item[1].get("guild_name") or item[0]).casefold())
        ]
    access_map = dashboard_user_server_access_map(username)
    legacy_scope = set(parse_guild_scope(user["guild_ids_json"] if user else []))
    rows = []
    for guild_id, guild_config in sorted(configured.items(), key=lambda item: (item[1].get("guild_name") or item[0]).casefold()):
        guild_id = str(guild_id)
        role = access_map.get(guild_id)
        source = "per-server access"
        if not role and guild_id in legacy_scope:
            role = normalize_role(user["role"] if user else "user")
            source = "legacy scope"
        if not role:
            continue
        rows.append({
            "id": guild_id,
            "name": guild_config.get("brand_name") or guild_config.get("guild_name") or f"Discord {guild_id}",
            "role": normalize_role(role),
            "source": source,
        })
    return rows


def dashboard_user_access_summary(user, config_data=None):
    rows = dashboard_user_access_rows(user, config_data)
    if not rows:
        return "Not Added"
    return "; ".join(
        f"{row['name']} ({ROLE_LABELS.get(row['role'], row['role'])})"
        for row in rows
    )


def dashboard_user_addable_guilds(user, config_data=None):
    config_data = config_data or load_config()
    existing_ids = {row["id"] for row in dashboard_user_access_rows(user, config_data)}
    return [
        guild
        for guild in guild_options(config_data)
        if str(guild["id"]) not in existing_ids
        and can_admin_access_guild(str(guild["id"]), config_data)
    ]


def issue_dashboard_auth_code(connection, username, guild_id, role, created_by):
    username = normalize_account_username(username)
    guild_id = str(guild_id or "").strip()
    role = normalize_role(role)
    if role == "not_added":
        raise ValueError("Choose an access role before issuing a code.")
    if not username or not guild_id:
        raise ValueError("A user and server are required.")
    alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"
    now_dt = datetime.now(timezone.utc)
    expires_at = (now_dt + timedelta(hours=24)).isoformat()
    for _ in range(10):
        code = "".join(secrets.choice(alphabet) for _ in range(8))
        existing = connection.execute(
            "SELECT 1 FROM dashboard_account_auth_codes WHERE code = ?",
            (code,),
        ).fetchone()
        if existing:
            continue
        connection.execute("""
            INSERT INTO dashboard_account_auth_codes (
                code, username, guild_id, role, created_by, created_at, expires_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?)
        """, (code, username, guild_id, role, created_by, now_dt.isoformat(), expires_at))
        return code, expires_at
    raise ValueError("Could not create a unique authentication code. Try again.")


def redeem_dashboard_auth_code(connection, username, code, config_data=None):
    config_data = config_data or load_config()
    username = normalize_account_username(username)
    code = str(code or "").strip().upper().replace("-", "")
    if not username or not code:
        raise ValueError("Enter an authentication code.")
    row = connection.execute("""
        SELECT *
        FROM dashboard_account_auth_codes
        WHERE code = ?
          AND used_at IS NULL
        LIMIT 1
    """, (code,)).fetchone()
    if not row:
        raise ValueError("That authentication code was not found or has already been used.")
    if normalize_account_username(row["username"]) != username:
        raise ValueError("That authentication code belongs to a different account.")
    expires_at = parse_database_datetime(row["expires_at"])
    if not expires_at or expires_at < datetime.now(timezone.utc):
        raise ValueError("That authentication code has expired.")
    guild_id = str(row["guild_id"] or "")
    if guild_id not in (config_data.get("guilds") or {}):
        raise ValueError("That authentication code is for an unknown server.")
    role = normalize_role(row["role"])
    if role == "not_added":
        raise ValueError("That authentication code does not grant server access.")
    account = connection.execute("""
        SELECT username, role, guild_ids_json
        FROM dashboard_admin_users
        WHERE username = ?
    """, (username,)).fetchone()
    if not account:
        raise ValueError("Account was not found.")
    set_user_server_role(connection, username, guild_id, role, source="code")
    new_scope = sorted(set(parse_guild_scope(account["guild_ids_json"])) | {guild_id})
    account_role = normalize_role(account["role"])
    new_account_role = "user" if account_role == "not_added" else account_role
    now = utc_now_iso()
    connection.execute("""
        UPDATE dashboard_admin_users
        SET role = ?, guild_ids_json = ?, updated_at = ?
        WHERE username = ?
    """, (new_account_role, json.dumps(new_scope, separators=(",", ":")), now, username))
    connection.execute("""
        UPDATE dashboard_account_auth_codes
        SET used_at = ?, used_by = ?
        WHERE code = ?
    """, (now, username, code))
    return guild_id, role, new_scope, new_account_role


def dashboard_user_max_role(username, fallback_role="user"):
    username = normalize_account_username(username)
    if is_bot_owner_username(username):
        return "bot_owner"
    max_role = normalize_role(fallback_role)
    for row in dashboard_user_server_access(username):
        row_role = normalize_role(row["role"])
        if ROLE_LEVELS[row_role] > ROLE_LEVELS[max_role]:
            max_role = row_role
    return max_role


def dashboard_user_by_discord_id(connection, user_id):
    user_id = str(user_id or "").strip()
    if not user_id:
        return None
    return connection.execute("""
        SELECT username, email, display_name, discord_user_id, role, disabled,
               guild_ids_json, created_at, updated_at, last_login_at,
               approved_by, approved_at, notes
        FROM dashboard_admin_users
        WHERE discord_user_id = ?
        LIMIT 1
    """, (user_id,)).fetchone()


def dashboard_user_restrictions():
    with closing(connect_db()) as connection:
        return connection.execute("""
            SELECT restrictions.*, users.role AS dashboard_role,
                   users.username AS dashboard_username
            FROM user_restrictions AS restrictions
            LEFT JOIN dashboard_admin_users AS users
              ON users.discord_user_id = restrictions.user_id
            WHERE restrictions.active = 1
            ORDER BY restrictions.updated_at DESC, restrictions.created_at DESC,
                     restrictions.id DESC
        """).fetchall()


def active_user_restriction(connection, guild_id, user_id, scope):
    lock_column = (
        "lock_games" if scope == "games" else "lock_submissions"
    )
    return connection.execute(f"""
        SELECT *
        FROM user_restrictions
        WHERE active = 1
          AND user_id = ?
          AND (guild_id = '' OR guild_id = ?)
          AND {lock_column} = 1
        ORDER BY CASE WHEN guild_id = ? THEN 0 ELSE 1 END, updated_at DESC
        LIMIT 1
    """, (str(user_id), str(guild_id), str(guild_id))).fetchone()


def known_discord_users(limit=100):
    with closing(connect_db()) as connection:
        rows = connection.execute("""
            SELECT user_id, MAX(username) AS username, MAX(last_seen_at) AS last_seen_at,
                   SUM(submissions) AS submissions, SUM(guess_points) AS guess_points
            FROM (
                SELECT user_id, username,
                       COALESCE(created_at, submitted_at, '') AS last_seen_at,
                       1 AS submissions, 0 AS guess_points
                FROM submissions
                WHERE COALESCE(user_id, '') != ''
                UNION ALL
                SELECT user_id, username, COALESCE(updated_at, '') AS last_seen_at,
                       0 AS submissions, points AS guess_points
                FROM guess_points
                WHERE COALESCE(user_id, '') != ''
            )
            GROUP BY user_id
            ORDER BY last_seen_at DESC, submissions DESC, guess_points DESC
            LIMIT ?
        """, (limit,)).fetchall()
    return rows


def notification_routes(config_data=None):
    config_data = config_data or load_config()
    guild_names = guild_name_map(config_data)
    scope_sql, scope_params = admin_scope_filter("guild_id", config_data)
    where_sql = f"WHERE {scope_sql}" if scope_sql else ""
    with closing(connect_db()) as connection:
        rows = connection.execute(f"""
            SELECT guild_id, event_key, channel_id, enabled, updated_at
            FROM admin_notifications
            {where_sql}
            ORDER BY guild_id, event_key
        """, scope_params).fetchall()
    return [
        {
            "guild_id": row["guild_id"],
            "guild_name": guild_names.get(row["guild_id"], row["guild_id"]),
            "event_key": row["event_key"],
            "event_label": NOTIFICATION_EVENT_LABELS.get(
                row["event_key"],
                row["event_key"],
            ),
            "channel_id": row["channel_id"],
            "enabled": bool(row["enabled"]),
            "updated_at": row["updated_at"],
        }
        for row in rows
    ]


def sanitize_theme_color(value, fallback):
    value = str(value or "").strip()
    if re.fullmatch(r"#[0-9a-fA-F]{6}", value):
        return value.lower()
    return fallback


def clamp_int(value, fallback, minimum, maximum):
    try:
        number = int(str(value).strip())
    except (TypeError, ValueError):
        number = int(fallback)
    return max(minimum, min(maximum, number))


def layout_item_defaults():
    return [
        {
            "id": item_id,
            "label": label,
            "value": value,
            "tone": tone,
            "width": "medium",
            "visible": True,
            "font_size": "normal",
            "locked": False,
        }
        for item_id, label, value, tone in LAYOUT_EDITOR_ITEMS
    ]


def sanitize_layout_item_order(raw_value):
    allowed = [item["id"] for item in layout_item_defaults()]
    seen = set()
    order = []
    for item_id in str(raw_value or "").split(","):
        item_id = item_id.strip()
        if item_id in allowed and item_id not in seen:
            order.append(item_id)
            seen.add(item_id)
    for item_id in allowed:
        if item_id not in seen:
            order.append(item_id)
    return order


def sanitize_layout_item_properties(raw_value):
    if isinstance(raw_value, str):
        try:
            raw_value = json.loads(raw_value or "{}")
        except (TypeError, ValueError, json.JSONDecodeError):
            raw_value = {}
    if not isinstance(raw_value, dict):
        raw_value = {}
    defaults = {item["id"]: item for item in layout_item_defaults()}
    clean = {}
    for item_id, values in raw_value.items():
        if item_id not in defaults or not isinstance(values, dict):
            continue
        default = defaults[item_id]
        label = re.sub(r"\s+", " ", str(values.get("label") or default["label"]).strip())[:40]
        value = re.sub(r"\s+", " ", str(values.get("value") or default["value"]).strip())[:40]
        width = str(values.get("width") or default["width"]).strip()
        tone = str(values.get("tone") or default["tone"]).strip()
        if width not in {"small", "medium", "wide", "full"}:
            width = default["width"]
        if tone not in {"surface", "primary", "secondary", "accent"}:
            tone = default["tone"]
        font_size = str(values.get("font_size") or default.get("font_size", "normal")).strip()
        if font_size not in {"small", "normal", "large", "display"}:
            font_size = default.get("font_size", "normal")
        clean[item_id] = {
            "label": label or default["label"],
            "value": value or default["value"],
            "width": width,
            "tone": tone,
            "visible": values.get("visible") is not False,
            "font_size": font_size,
            "locked": values.get("locked") is True,
        }
    return clean


def layout_items_for_editor(layout):
    defaults = {item["id"]: item for item in layout_item_defaults()}
    properties = layout.get("item_properties") or {}
    rows = []
    for item_id in sanitize_layout_item_order(layout.get("item_order")):
        item = dict(defaults[item_id])
        item.update(properties.get(item_id) or {})
        rows.append(item)
    return rows



