@app.after_request
def inject_admin_sidebar(response):
    response = optimize_response(response, compress=False)
    if (
        response.status_code != 200
        or response.direct_passthrough
        or not response.mimetype.startswith("text/html")
    ):
        return optimize_response(response)
    page_html = response.get_data(as_text=True)
    if "<body" not in page_html:
        return response
    if "sdac-pwa-head" not in page_html:
        page_html = page_html.replace("</head>", PWA_HEAD_HTML.replace("<link", "<link id=\"sdac-pwa-head\"", 1) + "\n</head>", 1)
    if "sdac-theme-vars" not in page_html:
        page_html = page_html.replace("</head>", dashboard_theme_css() + "\n</head>", 1)
    page_html = add_body_classes(page_html, "sdac-theme")
    if should_render_admin_sidebar() and request.args.get("embed") != "1" and 'class="sdac-sidebar"' not in page_html:
        if "sdac-sidebar-style" not in page_html:
            page_html = page_html.replace("</head>", SIDEBAR_STYLE + "\n</head>", 1)
        menu_alignment = dashboard_layout().get("menu_button_alignment", "sidebar_edge")
        menu_class = f"sdac-menu-{menu_alignment.replace('_', '-')}"
        page_html = add_body_classes(page_html, "sdac-has-sidebar", menu_class)
        page_html = re.sub(
            r'(<body[^>]*>)',
            r'\1' + admin_sidebar_html(),
            page_html,
            count=1,
        )
    if "sdac-pwa-script" not in page_html:
        page_html = page_html.replace("</body>", PWA_INSTALL_HTML + "\n</body>", 1)
    response.set_data(page_html)
    response.headers["Content-Length"] = str(len(response.get_data()))
    return optimize_response(response)


def optimize_response(response, compress=True):
    if response.status_code == 200:
        path = request.path if has_request_context() else ""
        if path.startswith("/media/") or path == "/app-icon.svg":
            response.headers.setdefault("Cache-Control", "public, max-age=604800, immutable")
        elif path in {"/manifest.webmanifest", "/sw.js"}:
            response.headers.setdefault("Cache-Control", "public, max-age=300")
        elif path.startswith("/api/"):
            response.headers.setdefault("Cache-Control", "public, max-age=30")
        elif response.mimetype.startswith("text/html"):
            response.headers.setdefault("Cache-Control", "private, max-age=15")

    if (
        not compress
        or response.status_code != 200
        or response.direct_passthrough
        or response.headers.get("Content-Encoding")
        or "gzip" not in request.headers.get("Accept-Encoding", "")
        or not (
            response.mimetype.startswith("text/")
            or response.mimetype in {
                "application/json",
                "application/javascript",
                "application/manifest+json",
                "image/svg+xml",
            }
        )
    ):
        return response

    body = response.get_data()
    if len(body) < 1024:
        return response
    compressed = gzip.compress(body, compresslevel=5)
    if len(compressed) >= len(body):
        return response
    response.set_data(compressed)
    response.headers["Content-Encoding"] = "gzip"
    response.headers["Content-Length"] = str(len(compressed))
    response.headers["Vary"] = add_vary_header(response.headers.get("Vary"), "Accept-Encoding")
    return response


def add_vary_header(current, value):
    existing = [item.strip() for item in str(current or "").split(",") if item.strip()]
    if value.lower() not in {item.lower() for item in existing}:
        existing.append(value)
    return ", ".join(existing)


