def read_bot_status():
    if not BOT_STATUS_FILE.is_file():
        return {
            "available": False,
            "message": "No bot status heartbeat has been written yet.",
        }
    try:
        data = json.loads(BOT_STATUS_FILE.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as error:
        return {
            "available": False,
            "message": f"Bot status file could not be read: {error}",
        }
    updated_at = data.get("updated_at") or ""
    age_seconds = None
    if updated_at:
        try:
            updated = datetime.fromisoformat(updated_at)
            age_seconds = int(
                (datetime.now(timezone.utc) - updated).total_seconds()
            )
        except ValueError:
            age_seconds = None
    data["available"] = True
    data["age_seconds"] = age_seconds
    data["fresh"] = age_seconds is not None and age_seconds <= 600
    data["message"] = (
        "Fresh heartbeat"
        if data["fresh"]
        else "Heartbeat is older than 10 minutes"
    )
    return data


def read_update_config():
    values = {}
    try:
        if not UPDATE_ENV_FILE.is_file():
            return values
        with UPDATE_ENV_FILE.open("r", encoding="utf-8") as file:
            for line in file:
                line = line.strip()
                if not line or line.startswith("#") or "=" not in line:
                    continue
                key, raw_value = line.split("=", 1)
                key = key.strip()
                raw_value = raw_value.strip()
                try:
                    parsed = shlex.split(raw_value)
                    values[key] = parsed[0] if parsed else ""
                except ValueError:
                    values[key] = raw_value.strip("'\"")
    except OSError:
        return values
    return values


def release_asset_metadata(payload, asset_name):
    for asset in payload.get("assets") or []:
        if asset.get("name") != asset_name:
            continue
        digest = asset.get("digest") or ""
        if digest.startswith("sha256:"):
            digest = digest.split(":", 1)[1]
        return {
            "name": asset.get("name") or asset_name,
            "url": asset.get("browser_download_url") or "",
            "size": asset.get("size") or 0,
            "sha256": digest,
        }
    return {"name": asset_name, "url": "", "size": 0, "sha256": ""}


def fetch_github_release(tag):
    token = os.getenv("GITHUB_TOKEN") or os.getenv("GH_TOKEN")
    headers = {
        "Accept": "application/vnd.github+json",
        "User-Agent": "SDAC-Dashboard/2.5",
    }
    if token:
        headers["Authorization"] = f"Bearer {token}"
    api_request = Request(
        f"https://api.github.com/repos/{RELEASE_REPO}/releases/tags/{tag}",
        headers=headers,
    )
    with urlopen(api_request, timeout=8) as response:
        payload = json.loads(response.read().decode("utf-8"))
    release_tag = payload.get("tag_name") or tag
    release_name = payload.get("name") or ""
    apk = release_asset_metadata(payload, "Sana-Chan-Android-Debug.apk")
    apk_checksum = release_asset_metadata(payload, "Sana-Chan-Android-Debug.apk.sha256")
    return {
        "tag": release_tag,
        "name": release_name,
        "version": extract_release_version(f"{release_name} {release_tag}"),
        "published_at": payload.get("published_at") or "",
        "html_url": payload.get("html_url") or f"https://github.com/{RELEASE_REPO}/releases/tag/{release_tag}",
        "apk": apk,
        "apk_sha256": apk_checksum,
    }


def release_status():
    cached = RELEASE_CACHE.get("status")
    if cached and RELEASE_CACHE.get("expires_at", 0) > time.time():
        return cached

    update_config = read_update_config()
    status = {
        "repo": RELEASE_REPO,
        "original_repo": ORIGINAL_REPO,
        "installed": os.getenv("SDAC_RELEASE") or "development",
        "configured_tag": (
            os.getenv("SDAC_RELEASE_TAG")
            or update_config.get("SDAC_RELEASE_TAG")
            or "latest-official"
        ),
        "official": {"tag": "unknown", "published_at": ""},
        "experimental": {"tag": "unknown", "published_at": ""},
        "error": "",
    }
    try:
        status["official"] = fetch_github_release("latest-official")
        status["experimental"] = fetch_github_release("latest-experimental")
    except (HTTPError, URLError, TimeoutError, ValueError, json.JSONDecodeError) as error:
        status["error"] = str(error)

    installed = (
        os.getenv("SDAC_RELEASE")
        or update_config.get("SDAC_RELEASE")
        or latest_release_note_version()
        or "development"
    )
    if status["official"].get("tag") == "unknown" and status["configured_tag"] == "latest-official" and installed != "development":
        status["official"] = {"tag": "latest-official", "name": f"Latest Official ({installed})", "version": installed, "published_at": ""}
    if status["experimental"].get("tag") == "unknown" and status["configured_tag"] == "latest-experimental" and installed != "development":
        status["experimental"] = {"tag": "latest-experimental", "name": f"Latest Experimental ({installed})", "version": installed, "published_at": ""}

    status["installed_version"] = installed
    status["official_version"] = status["official"].get("version") or status["official"].get("tag") or "unknown"
    status["experimental_version"] = status["experimental"].get("version") or status["experimental"].get("tag") or "unknown"

    RELEASE_CACHE["status"] = status
    RELEASE_CACHE["expires_at"] = time.time() + 3600
    return status


def oauth_enabled():
    return bool(DISCORD_OAUTH_CLIENT_ID and DISCORD_OAUTH_CLIENT_SECRET)


OAUTH_STATE_TTL_SECONDS = 600


def store_oauth_state(state, next_url):
    expires_at = time.time() + OAUTH_STATE_TTL_SECONDS
    with database() as connection:
        connection.execute("DELETE FROM dashboard_oauth_states WHERE expires_at < ?", (time.time(),))
        connection.execute("""
            INSERT OR REPLACE INTO dashboard_oauth_states (state, next_url, created_at, expires_at)
            VALUES (?, ?, ?, ?)
        """, (state, safe_next_url(next_url, url_for("account_home")), time.time(), expires_at))


def consume_oauth_state(state):
    if not state:
        return None
    with database() as connection:
        row = connection.execute("""
            SELECT next_url, expires_at
            FROM dashboard_oauth_states
            WHERE state = ?
        """, (state,)).fetchone()
        connection.execute("DELETE FROM dashboard_oauth_states WHERE state = ? OR expires_at < ?", (state, time.time()))
    if not row or float(row["expires_at"] or 0) < time.time():
        return None
    return safe_next_url(row["next_url"], url_for("account_home"))



def app_login_serializer():
    return URLSafeTimedSerializer(app.secret_key, salt="sdac-app-login-v1")


def create_app_login_ticket(username, role, login_role, guild_ids, discord_user_id=""):
    return app_login_serializer().dumps({
        "username": username,
        "role": normalize_role(role),
        "login_role": normalize_role(login_role),
        "guild_ids": [str(guild_id) for guild_id in (guild_ids or [])],
        "discord_user_id": str(discord_user_id or ""),
        "created_at": utc_now_iso(),
    })


def load_app_login_ticket(ticket):
    try:
        payload = app_login_serializer().loads(
            str(ticket or ""),
            max_age=APP_LOGIN_TICKET_MAX_AGE_SECONDS,
        )
    except SignatureExpired:
        return None, "That app login link expired. Start Discord login again."
    except BadSignature:
        return None, "That app login link was not valid. Start Discord login again."
    if not isinstance(payload, dict) or not payload.get("username"):
        return None, "That app login link was incomplete. Start Discord login again."
    return payload, ""


def apply_app_login_ticket(payload):
    username = str(payload.get("username") or "").strip()
    account = dashboard_user_by_login(username)
    if not account or int(account["disabled"] or 0):
        return False, "That dashboard account is not available."
    config_data = load_config()
    role = "bot_owner" if is_bot_owner_username(account["username"]) else normalize_role(account["role"] or payload.get("role") or "user")
    login_role = dashboard_user_max_role(account["username"], role)
    scope_ids = parse_guild_scope(payload.get("guild_ids") or account["guild_ids_json"])
    if role == "bot_owner":
        scope_ids = sorted(str(guild_id) for guild_id in (config_data.get("guilds") or {}))
    remember_dashboard_session()
    session["sdac_account_username"] = account["username"]
    session["sdac_account_role"] = role
    session["sdac_account_guild_ids"] = scope_ids
    session["sdac_oauth_available_guild_ids"] = scope_ids
    session["sdac_discord_user_id"] = account["discord_user_id"] or payload.get("discord_user_id") or ""
    if ROLE_LEVELS.get(login_role, 0) >= ROLE_LEVELS["moderator"]:
        session["sdac_admin"] = True
        session["sdac_admin_username"] = account["username"]
        session["sdac_admin_role"] = login_role
        session["sdac_admin_auth"] = "app-ticket"
        session["sdac_admin_guild_ids"] = scope_ids
    return True, "Signed in."


