def discord_json_request(url, token, token_type="Bearer", method="GET", payload=None):
    headers = {
        "Accept": "application/json",
        "User-Agent": "SDAC-Dashboard/3.0",
        "Authorization": f"{token_type} {token}",
    }
    data = None
    if payload is not None:
        data = json.dumps(payload).encode("utf-8")
        headers["Content-Type"] = "application/json"
    api_request = Request(url, data=data, method=method, headers=headers)
    with urlopen(api_request, timeout=12) as response:
        body = response.read().decode("utf-8")
        return json.loads(body) if body else {}


def discord_api_error_message(error):
    try:
        body = error.read().decode("utf-8")
    except Exception:
        body = ""
    if body:
        try:
            parsed = json.loads(body)
            message = parsed.get("message") or body
        except (TypeError, ValueError):
            message = body
        return f"Discord API returned {error.code}: {message[:300]}"
    return f"Discord API returned {error.code}: {error.reason}"


def normalize_bot_nickname(value):
    nickname = str(value or "").strip()
    if len(nickname) > 32:
        raise ValueError("Bot nickname must be 32 characters or fewer.")
    if any(character in nickname for character in "\r\n"):
        raise ValueError("Bot nickname cannot contain line breaks.")
    return nickname


def normalize_bot_username(value):
    username = str(value or "").strip()
    if not 2 <= len(username) <= 32:
        raise ValueError("Global bot username must be 2-32 characters.")
    if any(character in username for character in "\r\n"):
        raise ValueError("Global bot username cannot contain line breaks.")
    return username


def update_discord_bot_nickname(guild_id, nickname):
    if not TOKEN:
        raise ValueError("DISCORD_TOKEN is missing, so the dashboard cannot update the bot nickname.")
    return discord_json_request(
        f"https://discord.com/api/v10/guilds/{guild_id}/members/@me",
        TOKEN,
        token_type="Bot",
        method="PATCH",
        payload={"nick": nickname or None},
    )


def update_discord_bot_username(username):
    if not TOKEN:
        raise ValueError("DISCORD_TOKEN is missing, so the dashboard cannot update the bot username.")
    return discord_json_request(
        "https://discord.com/api/v10/users/@me",
        TOKEN,
        token_type="Bot",
        method="PATCH",
        payload={"username": username},
    )


BOT_AVATAR_MIME_TYPES = {
    "image/png": "png",
    "image/jpeg": "jpeg",
    "image/gif": "gif",
    "image/webp": "webp",
}
BOT_AVATAR_MAX_BYTES = 8 * 1024 * 1024


def normalize_bot_avatar_url(value):
    avatar_url = str(value or "").strip()
    if not avatar_url:
        raise ValueError("Enter an HTTPS image URL or upload an image file.")
    if any(character in avatar_url for character in "\r\n"):
        raise ValueError("Bot image URL cannot contain line breaks.")
    if not avatar_url.lower().startswith("https://"):
        raise ValueError("Bot image URL must start with https://.")
    if len(avatar_url) > 500:
        raise ValueError("Bot image URL must be 500 characters or fewer.")
    return avatar_url


def validate_bot_avatar_bytes(data, content_type):
    if not data:
        raise ValueError("Bot image file is empty.")
    if len(data) > BOT_AVATAR_MAX_BYTES:
        raise ValueError("Bot image must be 8 MB or smaller.")
    mime_type = str(content_type or "").split(";", 1)[0].strip().lower()
    if mime_type not in BOT_AVATAR_MIME_TYPES:
        raise ValueError("Bot image must be PNG, JPEG, GIF, or WebP.")
    return mime_type


def fetch_bot_avatar_url(avatar_url):
    avatar_url = normalize_bot_avatar_url(avatar_url)
    request_headers = {"User-Agent": "SDAC-Dashboard/4.1"}
    with urlopen(Request(avatar_url, headers=request_headers), timeout=12) as response:
        content_type = response.headers.get("Content-Type", "")
        data = response.read(BOT_AVATAR_MAX_BYTES + 1)
    return data, validate_bot_avatar_bytes(data, content_type), avatar_url


def discord_avatar_payload(data, content_type):
    mime_type = validate_bot_avatar_bytes(data, content_type)
    encoded = base64.b64encode(data).decode("ascii")
    return f"data:{mime_type};base64,{encoded}"


def update_discord_bot_avatar(data, content_type):
    if not TOKEN:
        raise ValueError("DISCORD_TOKEN is missing, so the dashboard cannot update the bot image.")
    return discord_json_request(
        "https://discord.com/api/v10/users/@me",
        TOKEN,
        token_type="Bot",
        method="PATCH",
        payload={"avatar": discord_avatar_payload(data, content_type)},
    )


def exchange_discord_oauth_code(code, redirect_uri=None):
    payload = urlencode({
        "client_id": DISCORD_OAUTH_CLIENT_ID,
        "client_secret": DISCORD_OAUTH_CLIENT_SECRET,
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri or oauth_redirect_uri(),
    }).encode("utf-8")
    api_request = Request(
        "https://discord.com/api/oauth2/token",
        data=payload,
        method="POST",
        headers={
            "Content-Type": "application/x-www-form-urlencoded",
            "Accept": "application/json",
            "User-Agent": "SDAC-Dashboard/2.7",
        },
    )
    with urlopen(api_request, timeout=12) as response:
        return json.loads(response.read().decode("utf-8"))


def discord_user_guilds(access_token):
    token_hash = hashlib.sha256(str(access_token or "").encode("utf-8")).hexdigest()
    cache_id = cache_key("discord_user_guilds", token_hash)
    cached = ttl_cache_get(cache_id)
    if cached is not None:
        return cached
    return ttl_cache_set(cache_id, discord_json_request(
        "https://discord.com/api/users/@me/guilds",
        access_token,
    ), 900)


def discord_current_user(access_token):
    token_hash = hashlib.sha256(str(access_token or "").encode("utf-8")).hexdigest()
    cache_id = cache_key("discord_current_user", token_hash)
    cached = ttl_cache_get(cache_id)
    if cached is not None:
        return cached
    return ttl_cache_set(cache_id, discord_json_request(
        "https://discord.com/api/users/@me",
        access_token,
    ), 900)


def discord_member_role_ids(guild_id, user_id):
    if not TOKEN:
        return []
    cache_id = cache_key("discord_member_roles", guild_id, user_id)
    cached = ttl_cache_get(cache_id)
    if cached is not None:
        return cached
    try:
        member = discord_json_request(
            f"https://discord.com/api/v10/guilds/{guild_id}/members/{user_id}",
            TOKEN,
            token_type="Bot",
        )
    except (HTTPError, URLError, TimeoutError, json.JSONDecodeError):
        return []
    return ttl_cache_set(
        cache_id,
        [str(role_id) for role_id in member.get("roles") or []],
        300,
    )


def oauth_configured_member_guild_ids(access_token, config_data):
    configured = config_data.get("guilds") or {}
    try:
        guilds = discord_user_guilds(access_token)
    except (HTTPError, URLError, TimeoutError, json.JSONDecodeError):
        return []
    return sorted({
        str(guild.get("id") or "")
        for guild in guilds
        if str(guild.get("id") or "") in configured
    })


def oauth_allowed_guild_ids(access_token, user_id, config_data):
    configured = config_data.get("guilds") or {}
    try:
        guilds = discord_user_guilds(access_token)
    except (HTTPError, URLError, TimeoutError, json.JSONDecodeError):
        return []
    allowed = []
    for guild in guilds:
        guild_id = str(guild.get("id") or "")
        guild_config = configured.get(guild_id)
        if not guild_config:
            continue
        try:
            permissions = int(guild.get("permissions") or 0)
        except (TypeError, ValueError):
            permissions = 0
        if permissions & DISCORD_ADMINISTRATOR_PERMISSION:
            allowed.append(guild_id)
            continue
        admin_roles = {
            str(role_id)
            for role_id in guild_config.get("admin_role_ids", [])
        }
        if admin_roles and admin_roles.intersection(
            discord_member_role_ids(guild_id, user_id)
        ):
            allowed.append(guild_id)
    return sorted(set(allowed))


