@app.route("/admin/login", methods=["GET", "POST"])
def admin_login():
    if not has_valid_key():
        abort(403)

    next_url = safe_next_url(request.values.get("next"), url_for(
        "index",
        key=ADMIN_KEY,
    ))
    error = request.args.get("error", "")
    username = request.values.get("username", "").strip()

    if request.method == "POST":
        require_csrf_token()
        username = request.form.get("username", "").strip().casefold()
        password = request.form.get("password", "")
        actor_id, actor_name = web_actor()
        remote_key = login_remote_key()
        if login_rate_limited(remote_key):
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_login_rate_limited",
                    actor_id,
                    actor_name,
                    "dashboard",
                    "admin_login",
                    "Too many failed admin login attempts.",
                )
            error = "Too many failed login attempts. Try again in a few minutes."
        else:
            user = dashboard_user_by_login(username)
            role = ""
            login_ok = False
            if user and not int(user["disabled"] or 0):
                login_ok = check_password_hash(user["password_hash"], password)
                role = "bot_owner" if is_bot_owner_username(user["username"]) else normalize_role(user["role"])
                role = dashboard_user_max_role(user["username"], role)

            if login_ok and ROLE_LEVELS.get(role, 0) >= ROLE_LEVELS["moderator"]:
                clear_login_failures(remote_key)
                remember_dashboard_session()
                session["sdac_admin"] = True
                session["sdac_admin_username"] = user["username"]
                session["sdac_admin_role"] = role
                session["sdac_admin_auth"] = "password"
                session["sdac_account_username"] = user["username"]
                session["sdac_account_role"] = role
                session["sdac_account_guild_ids"] = parse_guild_scope(user["guild_ids_json"])
                session["sdac_discord_user_id"] = user["discord_user_id"] or ""
                session["sdac_admin_guild_ids"] = (
                    parse_guild_scope(user["guild_ids_json"])
                    if user
                    else []
                )
                if user:
                    with database() as connection:
                        upsert_user_server_access(
                            connection,
                            user["username"],
                            parse_guild_scope(user["guild_ids_json"]),
                            role=normalize_role(user["role"]),
                            source="legacy",
                        )
                        connection.execute("""
                            UPDATE dashboard_admin_users
                            SET last_login_at = ?, role = CASE WHEN username = ? THEN 'bot_owner' ELSE role END
                            WHERE username = ?
                        """, (utc_now_iso(), OWNER_OVERRIDE_USERNAME, user["username"]))
                with database() as connection:
                    add_admin_audit_log(
                        connection,
                        None,
                        "dashboard_login_success",
                        user["username"],
                        f"{user['username']} ({role})",
                        "dashboard",
                        "admin_login",
                        "Admin login succeeded.",
                    )
                return redirect(next_url)

            if login_ok:
                error = "That account is not an admin account yet."
            else:
                error = "Invalid admin username/email or password."

            record_login_failure(remote_key)
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_login_failed",
                    actor_id,
                    actor_name,
                    "dashboard",
                    "admin_login",
                    f"Invalid password for {username}.",
                )

    return render_template_string(
        LOGIN_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        error=error,
        next_url=next_url,
        oauth_enabled=False,
        username=username,
    )


@app.route("/account/register", methods=["GET", "POST"])
def account_register():
    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    email = request.values.get("email", "").strip()
    username = request.values.get("username", "").strip()
    discord_user_id = request.values.get("discord_user_id", "").strip()
    if request.method == "POST":
        require_csrf_token()
        email = request.form.get("email", "")
        username = request.form.get("username", "")
        discord_user_id = request.form.get("discord_user_id", "")
        password = request.form.get("password", "")
        confirm_password = request.form.get("confirm_password", "")
        try:
            normalized_email = normalize_email(email)
            normalized_discord_user_id = normalize_discord_user_id(discord_user_id)
            preferred_username = normalize_account_username(
                username,
                normalized_email,
            )
            if len(password) < 10:
                raise ValueError("Password must be at least 10 characters.")
            if password != confirm_password:
                raise ValueError("Passwords did not match.")
            now = utc_now_iso()
            with database() as connection:
                existing_email = connection.execute("""
                    SELECT 1
                    FROM dashboard_admin_users
                    WHERE lower(COALESCE(email, '')) = ?
                    LIMIT 1
                """, (normalized_email,)).fetchone()
                if existing_email:
                    raise ValueError("An account with that email already exists.")
                if normalized_discord_user_id:
                    existing_discord_id = connection.execute("""
                        SELECT 1
                        FROM dashboard_admin_users
                        WHERE discord_user_id = ?
                        LIMIT 1
                    """, (normalized_discord_user_id,)).fetchone()
                    if existing_discord_id:
                        raise ValueError("That Discord user ID is already linked.")
                account_username = unique_account_username(
                    connection,
                    preferred_username,
                )
                connection.execute("""
                    INSERT INTO dashboard_admin_users (
                        username, email, display_name, discord_user_id,
                        password_hash, role, disabled, email_verified,
                        created_ip, created_at, updated_at, guild_ids_json
                    )
                    VALUES (?, ?, ?, ?, ?, 'not_added', 0, 0, ?, ?, ?, '[]')
                """, (
                    account_username,
                    normalized_email,
                    (username or account_username).strip()[:80],
                    normalized_discord_user_id,
                    generate_password_hash(password),
                    request.remote_addr or "",
                    now,
                    now,
                ))
                add_admin_audit_log(
                    connection,
                    None,
                    "account_registered",
                    account_username,
                    account_username,
                    "dashboard_user",
                    account_username,
                    f"User account registered with email {normalized_email}.",
                )
            remember_dashboard_session()
            session["sdac_account_username"] = account_username
            session["sdac_account_role"] = "not_added"
            session["sdac_discord_user_id"] = normalized_discord_user_id
            return redirect(url_for(
                "account_home",
                notice="Account created.",
            ))
        except (ValueError, sqlite3.Error) as form_error:
            notice = str(form_error)
            error = True
    return render_template_string(
        ACCOUNT_REGISTER_HTML,
        csrf_token=get_csrf_token(),
        discord_user_id=discord_user_id,
        email=email,
        error=error,
        notice=notice,
        username=username,
    )


@app.route("/account/login", methods=["GET", "POST"])
def account_login():
    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    next_url = safe_next_url(request.values.get("next"), url_for("account_home"))
    identifier = request.values.get("identifier", "").strip()
    if request.method == "POST":
        require_csrf_token()
        identifier = request.form.get("identifier", "").strip()
        password = request.form.get("password", "")
        remote_key = "account:" + login_remote_key()
        if login_rate_limited(remote_key):
            notice = "Too many failed login attempts. Try again in a few minutes."
            error = True
        else:
            account = dashboard_user_by_login(identifier)
            if (
                account
                and not int(account["disabled"] or 0)
                and check_password_hash(account["password_hash"], password)
            ):
                clear_login_failures(remote_key)
                remember_dashboard_session()
                session["sdac_account_username"] = account["username"]
                account_role = "bot_owner" if is_bot_owner_username(account["username"]) else normalize_role(account["role"])
                login_role = dashboard_user_max_role(account["username"], account_role)
                session["sdac_account_role"] = account_role
                session["sdac_account_guild_ids"] = parse_guild_scope(account["guild_ids_json"])
                session["sdac_discord_user_id"] = account["discord_user_id"] or ""
                with database() as connection:
                    upsert_user_server_access(
                        connection,
                        account["username"],
                        parse_guild_scope(account["guild_ids_json"]),
                        role=account_role,
                        source="legacy",
                    )
                    connection.execute("""
                        UPDATE dashboard_admin_users
                        SET last_login_at = ?, role = CASE WHEN username = ? THEN 'bot_owner' ELSE role END
                        WHERE username = ?
                    """, (utc_now_iso(), OWNER_OVERRIDE_USERNAME, account["username"]))
                    add_admin_audit_log(
                        connection,
                        None,
                        "account_login_success",
                        account["username"],
                        account["username"],
                        "dashboard_user",
                        account["username"],
                        "User account login succeeded.",
                    )
                if ROLE_LEVELS.get(login_role, 0) >= ROLE_LEVELS["moderator"]:
                    session["sdac_admin"] = True
                    session["sdac_admin_username"] = account["username"]
                    session["sdac_admin_role"] = login_role
                    session["sdac_admin_auth"] = "account"
                    session["sdac_admin_guild_ids"] = parse_guild_scope(
                        account["guild_ids_json"]
                    )
                return redirect(next_url)
            record_login_failure(remote_key)
            notice = "Invalid username/email or password."
            error = True
    return render_template_string(
        ACCOUNT_LOGIN_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        error=error,
        identifier=identifier,
        next_url=next_url,
        notice=notice,
    )


@app.route("/account/oauth/start")
def account_oauth_start():
    if not oauth_enabled():
        return redirect(url_for(
            "account_login",
            notice="Discord login is visible, but OAuth is not configured yet. Set SDAC_DISCORD_CLIENT_ID and SDAC_DISCORD_CLIENT_SECRET.",
            error=1,
            next=request.args.get("next") or url_for("account_home"),
        ))
    state = secrets.token_urlsafe(24)
    next_url = safe_next_url(request.args.get("next"), url_for("account_home"))
    remember_dashboard_session()
    session["sdac_account_oauth_state"] = state
    session["sdac_account_oauth_next"] = next_url
    store_oauth_state(state, next_url)
    authorize_params = {
        "client_id": DISCORD_OAUTH_CLIENT_ID,
        "redirect_uri": url_for("account_oauth_callback", _external=True),
        "response_type": "code",
        "scope": "identify guilds",
        "state": state,
    }
    if request.args.get("silent") == "1":
        authorize_params["prompt"] = "none"
    authorize_url = "https://discord.com/api/oauth2/authorize?" + urlencode(authorize_params)
    return redirect(authorize_url)


@app.route("/account/oauth/callback")
def account_oauth_callback():
    if not oauth_enabled():
        abort(404)
    state = request.args.get("state", "")
    code = request.args.get("code", "")
    session_state = session.get("sdac_account_oauth_state")
    stored_next_url = consume_oauth_state(state)
    if not code or not state or (state != session_state and not stored_next_url):
        return redirect(url_for("account_login", notice="Discord login state did not match. Try again.", error=1))
    try:
        token_payload = exchange_discord_oauth_code(
            code,
            url_for("account_oauth_callback", _external=True),
        )
        access_token = token_payload.get("access_token") or ""
        user = discord_current_user(access_token)
    except (HTTPError, URLError, TimeoutError, json.JSONDecodeError) as error:
        return redirect(url_for("account_login", notice=f"Discord login failed: {error}", error=1))
    user_id = str(user.get("id") or "")
    if not user_id:
        return redirect(url_for("account_login", notice="Discord did not return a user ID.", error=1))
    username = (user.get("global_name") or user.get("username") or f"discord-{user_id}").strip()[:80]
    now = utc_now_iso()
    config_data = load_config()
    oauth_guild_ids = oauth_configured_member_guild_ids(access_token, config_data)
    with database() as connection:
        account = dashboard_user_by_discord_id(connection, user_id)
        new_account = False
        if not account:
            new_account = True
            base_username = normalize_account_username(username, f"{user_id}@discord.local")
            account_username = unique_account_username(connection, base_username)
            connection.execute("""
                INSERT INTO dashboard_admin_users (
                    username, email, display_name, discord_user_id,
                    password_hash, role, disabled, email_verified,
                    created_ip, created_at, updated_at, guild_ids_json
                )
                VALUES (?, '', ?, ?, ?, 'user', 0, 1, ?, ?, ?, ?)
            """, (
                account_username,
                username or account_username,
                user_id,
                generate_password_hash(secrets.token_urlsafe(32)),
                request.remote_addr or "",
                now,
                now,
                json.dumps(oauth_guild_ids, separators=(",", ":")),
            ))
            account = dashboard_user_by_discord_id(connection, user_id)
        elif int(account["disabled"] or 0):
            return redirect(url_for("account_login", notice="That account is disabled.", error=1))
        role = "bot_owner" if is_bot_owner_username(account["username"]) else normalize_role(account["role"])
        scope_ids = sorted((set(config_data.get("guilds") or {}) if role == "bot_owner" else set(oauth_guild_ids)))
        upsert_user_server_access(
            connection,
            account["username"],
            scope_ids,
            role=role if role == "bot_owner" else "user",
            source="oauth",
        )
        login_role = dashboard_user_max_role(account["username"], role)
        connection.execute("""
            UPDATE dashboard_admin_users
            SET last_login_at = ?, updated_at = ?,
                display_name = COALESCE(NULLIF(display_name, ''), ?),
                role = ?,
                guild_ids_json = ?
            WHERE username = ?
        """, (now, now, username, role, json.dumps(scope_ids, separators=(",", ":")), account["username"]))
        add_admin_audit_log(
            connection,
            None,
            "account_discord_login_success",
            account["username"],
            account["username"],
            "dashboard_user",
            account["username"],
            "User account Discord OAuth login succeeded.",
        )
    remember_dashboard_session()
    session["sdac_account_username"] = account["username"]
    session["sdac_account_role"] = role
    session["sdac_account_guild_ids"] = scope_ids
    session["sdac_oauth_available_guild_ids"] = oauth_guild_ids
    session["sdac_discord_user_id"] = user_id
    if ROLE_LEVELS.get(login_role, 0) >= ROLE_LEVELS["moderator"]:
        session["sdac_admin"] = True
        session["sdac_admin_username"] = account["username"]
        session["sdac_admin_role"] = login_role
        session["sdac_admin_auth"] = "discord"
        session["sdac_admin_guild_ids"] = scope_ids
    session.pop("sdac_account_oauth_state", None)
    next_url = stored_next_url or safe_next_url(session.pop("sdac_account_oauth_next", None), url_for("account_home"))
    if not scope_ids or (new_account and len(scope_ids) != 1):
        return redirect(url_for("account_server", next=next_url, notice="Choose the Discord server you are joining from."))
    return redirect(next_url)


@app.route("/account/server", methods=["GET", "POST"])
def account_server():
    if not is_account_logged_in():
        return redirect(url_for("account_login", next=request.full_path))
    next_url = safe_next_url(request.values.get("next"), url_for("index"))
    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    config_data = load_config()
    available_ids = set(parse_guild_scope(session.get("sdac_oauth_available_guild_ids", [])))
    if not available_ids:
        available_ids = current_account_allowed_guild_ids(config_data)
    guilds = []
    for guild_id, guild_config in sorted(
        (config_data.get("guilds") or {}).items(),
        key=lambda item: (item[1].get("guild_name") or item[0]).casefold(),
    ):
        if str(guild_id) not in available_ids:
            continue
        guilds.append({
            "id": str(guild_id),
            "name": (
                guild_config.get("brand_name")
                or guild_config.get("guild_name")
                or f"Discord {guild_id}"
            ),
        })
    if request.method == "POST":
        require_csrf_token()
        guild_id = request.form.get("guild_id", "").strip()
        valid_ids = {str(option["id"]) for option in guilds}
        if guild_id not in valid_ids:
            return redirect(url_for(
                "account_server",
                next=next_url,
                notice="Choose one of your Discord-authenticated servers.",
                error=1,
            ))
        session["sdac_guild_id"] = guild_id
        existing_scope = current_account_allowed_guild_ids(config_data)
        if guild_id not in existing_scope:
            new_scope = sorted(existing_scope | {guild_id})
            with database() as connection:
                upsert_user_server_access(
                    connection,
                    current_account_username(),
                    [guild_id],
                    role=normalize_role(session.get("sdac_account_role")),
                    source="selected",
                )
                connection.execute("""
                    UPDATE dashboard_admin_users
                    SET guild_ids_json = ?, updated_at = ?
                    WHERE username = ?
                """, (
                    json.dumps(new_scope, separators=(",", ":")),
                    utc_now_iso(),
                    current_account_username(),
                ))
            session["sdac_account_guild_ids"] = new_scope
            if is_admin_logged_in() and current_admin_role() != "bot_owner":
                session["sdac_admin_guild_ids"] = new_scope
        return redirect(next_url)
    return render_template_string(
        ACCOUNT_SERVER_HTML,
        csrf_token=get_csrf_token(),
        error=error,
        guild_options=guilds,
        next_url=next_url,
        notice=notice,
    )


