@app.route("/admin/anime-activities", methods=["GET", "POST"])
def admin_anime_activities():
    login_response = require_admin_login("moderator")
    if login_response:
        return login_response
    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    config_data = load_config()
    options = guild_options(config_data, minimum_role="admin")
    valid_guild_ids = {option["id"] for option in options}
    selected_server_id = request.values.get("guild_id", "").strip()
    if selected_server_id not in valid_guild_ids:
        selected_server_id = options[0]["id"] if options else ""

    if request.method == "POST":
        admin_response = require_admin_login("admin")
        if admin_response:
            return admin_response
        require_csrf_token()
        action = request.form.get("action", "")
        actor_id, actor_name = web_actor()
        try:
            if action != "seed_anime_library":
                raise ValueError("Unknown anime activity action.")
            guild_id = request.form.get("guild_id", "").strip()
            if guild_id not in valid_guild_ids:
                raise ValueError("Choose a valid Discord server.")
            now = utc_now_iso()
            created = 0
            skipped = 0
            with database() as connection:
                for seed in anime_activity_seed_rows():
                    existing = connection.execute("""
                        SELECT id
                        FROM guess_library_items
                        WHERE guild_id = ?
                          AND pack_name = ?
                          AND category = ?
                        LIMIT 1
                    """, (
                        guild_id,
                        seed["pack_name"],
                        seed["category"],
                    )).fetchone()
                    if existing:
                        skipped += 1
                        continue
                    normalized_answer = seed["answer_aliases"][0]["normalized"]
                    connection.execute("""
                        INSERT INTO guess_library_items (
                            guild_id, title, answer, answer_display,
                            answer_aliases_json, prompt_text, category,
                            tags_json, pack_name, enabled, notes,
                            hint_text, auto_hint_minutes, media_path,
                            media_name, media_type, media_size,
                            media_metadata_json, status, times_used,
                            created_by, created_at, updated_at
                        )
                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 1, ?, ?, 0,
                                '', '', 'unknown', 0, '{}', 'draft', 0, ?, ?, ?)
                    """, (
                        guild_id,
                        seed["title"],
                        normalized_answer,
                        seed["answer_display"],
                        json.dumps(seed["answer_aliases"], separators=(",", ":")),
                        seed["prompt_text"],
                        seed["category"],
                        json.dumps(seed["tags"], separators=(",", ":")),
                        seed["pack_name"],
                        seed["notes"],
                        seed["hint_text"],
                        actor_name,
                        now,
                        now,
                    ))
                    created += 1
                add_admin_audit_log(
                    connection,
                    guild_id,
                    "dashboard_seed_anime_activities",
                    actor_id,
                    actor_name,
                    "guess_library_item",
                    "",
                    f"Seeded {created} anime activity draft(s); skipped {skipped} existing mode(s).",
                )
            return redirect(url_for(
                "admin_anime_activities",
                key=ADMIN_KEY,
                guild_id=guild_id,
                notice=f"Seeded {created} anime activity draft(s); skipped {skipped} existing mode(s).",
            ))
        except (ValueError, sqlite3.Error) as form_error:
            return redirect(url_for(
                "admin_anime_activities",
                key=ADMIN_KEY,
                guild_id=request.form.get("guild_id", selected_server_id),
                notice=str(form_error),
                error=1,
            ))

    return render_template_string(
        ANIME_ACTIVITIES_HTML,
        activity_key=anime_activity_key,
        admin_key=ADMIN_KEY,
        catalog=ANIME_ACTIVITY_CATALOG,
        csrf_token=get_csrf_token(),
        error=error,
        guild_options=options,
        notice=notice,
        retirement_note=ANIME_ACTIVITY_RETIREMENT_NOTE,
        selected_guild_id=selected_server_id,
    )

@app.route("/admin/game-library", methods=["GET", "POST"])
def admin_game_library():
    login_response = require_admin_login("admin")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    config_data = load_config()
    options = guild_options(config_data)
    valid_guild_ids = {option["id"] for option in options}
    selected_server_id = request.values.get("guild_id", "all").strip()
    if selected_server_id == "all":
        selected_server_id = ""
    if selected_server_id and selected_server_id not in valid_guild_ids:
        selected_server_id = ""
    if current_admin_role() != "bot_owner" and not selected_server_id and options:
        selected_server_id = options[0]["id"]

    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        actor_id, actor_name = web_actor()
        redirect_guild_id = request.form.get(
            "guild_id",
            selected_server_id or "all",
        ).strip() or "all"
        try:
            if action == "create_item":
                guild_id = request.form.get("guild_id", "").strip()
                if guild_id not in valid_guild_ids:
                    raise ValueError("Choose a valid Discord server.")
                answer_aliases = parse_answer_aliases(
                    request.form.get("answer", "")
                )
                if not answer_aliases:
                    raise ValueError("Answer is required.")
                answer_display = answer_aliases[0]["display"]
                normalized_answer = answer_aliases[0]["normalized"]
                title = request.form.get("title", "").strip()[:120]
                prompt_text = request.form.get("prompt_text", "").strip()
                max_text_length = int(
                    config_data.get("limits", {}).get(
                        "max_text_length",
                        DEFAULT_LIMITS["max_text_length"],
                    )
                )
                if len(prompt_text) > max_text_length:
                    raise ValueError(
                        f"Prompt text is limited to {max_text_length} characters."
                    )
                category = request.form.get("category", "").strip()[:80]
                hint_text = request.form.get("hint_text", "").strip()
                if len(hint_text) > 500:
                    raise ValueError("Hints are limited to 500 characters.")
                pack_name = request.form.get("pack_name", "").strip()[:80]
                tags = parse_metadata_list(request.form.get("tags", ""))
                notes = request.form.get("notes", "").strip()[:1000]
                enabled = parse_enabled_field(request.form.get("enabled"), True)
                try:
                    auto_hint_minutes = int(
                        request.form.get("auto_hint_minutes", "0") or 0
                    )
                except ValueError as form_error:
                    raise ValueError(
                        "Automatic hint minutes must be a number."
                    ) from form_error
                if auto_hint_minutes < 0 or auto_hint_minutes > 1440:
                    raise ValueError(
                        "Automatic hint minutes must be between 0 and 1440."
                    )

                media_info = save_guess_library_upload(
                    guild_id,
                    request.files.get("media"),
                    config_data.get("limits", {}),
                )
                now = utc_now_iso()
                try:
                    with database() as connection:
                        cursor = connection.execute("""
                            INSERT INTO guess_library_items (
                                guild_id, title, answer, answer_display,
                                answer_aliases_json, prompt_text, category,
                                tags_json, pack_name, enabled, notes,
                                hint_text, auto_hint_minutes, media_path,
                                media_name, media_type, media_size,
                                media_metadata_json, status, times_used,
                                created_by, created_at, updated_at
                            )
                            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', 0, ?, ?, ?)
                        """, (
                            guild_id,
                            title or answer_display,
                            normalized_answer,
                            answer_display,
                            json.dumps(answer_aliases, separators=(",", ":")),
                            prompt_text,
                            category,
                            json.dumps(tags, separators=(",", ":")),
                            pack_name,
                            enabled,
                            notes,
                            hint_text,
                            auto_hint_minutes,
                            media_info["path"],
                            media_info["name"],
                            media_info["type"],
                            int(media_info["size"] or 0),
                            json.dumps(
                                media_info["metadata"],
                                separators=(",", ":"),
                            ),
                            actor_name,
                            now,
                            now,
                        ))
                        item_id = cursor.lastrowid
                        add_admin_audit_log(
                            connection,
                            guild_id,
                            "dashboard_create_guess_library_item",
                            actor_id,
                            actor_name,
                            "guess_library_item",
                            item_id,
                            f"Created website game-library item {item_id}.",
                        )
                except Exception:
                    delete_guess_library_media(media_info["path"])
                    raise
                return game_library_redirect(
                    f"Library item {item_id} added.",
                    guild_id=guild_id,
                )

            if action == "bulk_import":
                guild_id = request.form.get("guild_id", "").strip()
                if guild_id not in valid_guild_ids:
                    raise ValueError("Choose a valid Discord server.")
                upload = request.files.get("csv_file")
                if upload is None or not upload.filename:
                    raise ValueError("Choose a CSV file to import.")
                media_upload = request.files.get("media_zip")
                if media_upload is not None and media_upload.filename:
                    payload = stage_guess_library_bulk_import_uploads(upload, media_upload)
                    payload["guild_id"] = guild_id
                    job_id = queue_background_job(
                        "guess_library_bulk_import",
                        guild_id=guild_id,
                        payload=payload,
                        actor_id=actor_id,
                        actor_name=actor_name,
                    )
                    return game_library_redirect(
                        f"Queued media archive import as background job #{job_id}. Open Jobs to watch extraction progress.",
                        guild_id=guild_id,
                    )
                raw_content = upload.stream.read()
                if not raw_content:
                    raise ValueError("CSV file was empty.")
                try:
                    decoded = raw_content.decode("utf-8-sig")
                except UnicodeDecodeError as decode_error:
                    raise ValueError(
                        "CSV must be UTF-8 encoded."
                    ) from decode_error
                reader = csv.DictReader(io.StringIO(decoded))
                if not reader.fieldnames:
                    raise ValueError("CSV must include a header row.")
                media_archive, media_lookup = open_guess_media_zip(
                    request.files.get("media_zip")
                )

                max_text_length = int(
                    config_data.get("limits", {}).get(
                        "max_text_length",
                        DEFAULT_LIMITS["max_text_length"],
                    )
                )
                imported = 0
                imported_with_media = 0
                missing_media = 0
                skipped = 0
                saved_media_paths = []
                now = utc_now_iso()
                storage_limit = guild_storage_limit(
                    config_data.get("guilds", {}).get(guild_id, {})
                )
                try:
                    with database() as connection:
                        for raw_row in reader:
                            row = {
                                str(key or "").strip().lower(): str(value or "").strip()
                                for key, value in raw_row.items()
                            }
                            answer_value = (
                                row.get("answer")
                                or row.get("answers")
                                or row.get("answer_aliases")
                                or ""
                            )
                            aliases_value = row.get("aliases") or ""
                            alias_source = answer_value
                            if aliases_value:
                                alias_source = (
                                    alias_source
                                    + "|"
                                    + aliases_value.replace(",", "|")
                                )
                            answer_aliases = parse_answer_aliases(alias_source)
                            if not answer_aliases:
                                skipped += 1
                                continue
                            answer_display = answer_aliases[0]["display"]
                            normalized_answer = answer_aliases[0]["normalized"]
                            title = (row.get("title") or answer_display)[:120]
                            prompt_text = (
                                row.get("prompt_text") or row.get("prompt") or ""
                            )[:max_text_length]
                            category = (row.get("category") or "")[:80]
                            hint_text = (
                                row.get("hint") or row.get("hint_text") or ""
                            )[:500]
                            pack_name = (
                                row.get("pack") or row.get("pack_name") or ""
                            )[:80]
                            tags = parse_metadata_list(row.get("tags") or "")
                            notes = (row.get("notes") or "")[:1000]
                            enabled = parse_enabled_field(row.get("enabled"), True)
                            try:
                                auto_hint_minutes = int(
                                    row.get("auto_hint_minutes") or "0"
                                )
                            except ValueError:
                                auto_hint_minutes = 0
                            auto_hint_minutes = max(0, min(1440, auto_hint_minutes))
                            requested_status = (row.get("status") or "draft").lower()
                            media_filename = row.get("media_filename") or row.get("media") or ""
                            media_info = None
                            if media_filename:
                                media_key = zip_media_lookup_key(media_filename)
                                media_entry = media_lookup.get(media_key) or media_lookup.get(
                                    zip_media_lookup_key(Path(media_filename).name)
                                )
                                if media_entry:
                                    if storage_limit and guild_media_size(guild_id) + int(media_entry.file_size or 0) > storage_limit:
                                        raise ValueError(
                                            "This server has reached its configured media storage limit."
                                        )
                                    media_info = save_guess_library_zip_media(
                                        guild_id,
                                        media_archive,
                                        media_entry,
                                        config_data.get("limits", {}),
                                    )
                                    saved_media_paths.append(media_info["path"])
                                    imported_with_media += 1
                                else:
                                    missing_media += 1
                            status = "draft"
                            if requested_status == "disabled":
                                status = "disabled"
                            elif requested_status == "active" and media_info:
                                status = "active"
                            connection.execute("""
                                INSERT INTO guess_library_items (
                                    guild_id, title, answer, answer_display,
                                    answer_aliases_json, prompt_text, category,
                                    tags_json, pack_name, enabled, notes,
                                    hint_text, auto_hint_minutes, media_path,
                                    media_name, media_type, media_size,
                                    media_metadata_json, status, times_used,
                                    created_by, created_at, updated_at
                                )
                                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, ?, ?, ?)
                            """, (
                                guild_id,
                                title,
                                normalized_answer,
                                answer_display,
                                json.dumps(answer_aliases, separators=(",", ":")),
                                prompt_text,
                                category,
                                json.dumps(tags, separators=(",", ":")),
                                pack_name,
                                enabled,
                                notes,
                                hint_text,
                                auto_hint_minutes,
                                media_info["path"] if media_info else "",
                                media_info["name"] if media_info else "",
                                media_info["type"] if media_info else "unknown",
                                int(media_info["size"] or 0) if media_info else 0,
                                json.dumps(
                                    media_info["metadata"],
                                    separators=(",", ":"),
                                ) if media_info else "{}",
                                status,
                                actor_name,
                                now,
                                now,
                            ))
                            imported += 1
                        add_admin_audit_log(
                            connection,
                            guild_id,
                            "dashboard_bulk_import_guess_library",
                            actor_id,
                            actor_name,
                            "guess_library_item",
                            "",
                            (
                                f"Imported {imported} library item(s); "
                                f"attached media to {imported_with_media}; "
                                f"missing media for {missing_media}; skipped {skipped}."
                            ),
                        )
                except Exception:
                    for saved_path in saved_media_paths:
                        delete_guess_library_media(saved_path)
                    raise
                finally:
                    if media_archive is not None:
                        media_archive.close()
                return game_library_redirect(
                    (
                        f"Imported {imported} library item(s); attached media to "
                        f"{imported_with_media}; missing media for {missing_media}; "
                        f"skipped {skipped}."
                    ),
                    guild_id=guild_id,
                )

            if action == "update_item":
                item_id = int(request.form.get("item_id", "0") or 0)
                with database() as connection:
                    existing_item = connection.execute("""
                        SELECT *
                        FROM guess_library_items
                        WHERE id = ?
                    """, (item_id,)).fetchone()
                    if not existing_item:
                        raise ValueError("Library item was not found.")
                    if not can_admin_access_guild(
                        existing_item["guild_id"],
                        config_data,
                    ):
                        abort(403)
                    answer_aliases = parse_answer_aliases(
                        request.form.get("answer", "")
                )
                if not answer_aliases:
                    raise ValueError("Answer is required.")
                answer_display = answer_aliases[0]["display"]
                normalized_answer = answer_aliases[0]["normalized"]
                title = request.form.get("title", "").strip()[:120]
                max_text_length = int(
                    config_data.get("limits", {}).get(
                        "max_text_length",
                        DEFAULT_LIMITS["max_text_length"],
                    )
                )
                prompt_text = request.form.get("prompt_text", "").strip()
                if len(prompt_text) > max_text_length:
                    raise ValueError(
                        f"Prompt text is limited to {max_text_length} characters."
                    )
                hint_text = request.form.get("hint_text", "").strip()
                if len(hint_text) > 500:
                    raise ValueError("Hints are limited to 500 characters.")
                category = request.form.get("category", "").strip()[:80]
                pack_name = request.form.get("pack_name", "").strip()[:80]
                tags = parse_metadata_list(request.form.get("tags", ""))
                notes = request.form.get("notes", "").strip()[:1000]
                enabled = parse_enabled_field(request.form.get("enabled"), True)
                try:
                    auto_hint_minutes = int(
                        request.form.get("auto_hint_minutes", "0") or 0
                    )
                except ValueError as form_error:
                    raise ValueError(
                        "Automatic hint minutes must be a number."
                    ) from form_error
                auto_hint_minutes = max(0, min(1440, auto_hint_minutes))
                new_status = request.form.get("status", "draft").strip()
                if new_status not in {"draft", "active", "disabled"}:
                    raise ValueError("Invalid library item status.")

                media_info = None
                upload = request.files.get("media")
                if upload is not None and upload.filename:
                    media_info = save_guess_library_upload(
                        existing_item["guild_id"],
                        upload,
                        config_data.get("limits", {}),
                    )
                has_media = bool(
                    media_info
                    or (
                        existing_item["media_path"]
                        and Path(existing_item["media_path"]).exists()
                    )
                )
                if new_status == "active" and not has_media:
                    raise ValueError("Active library items must have media attached.")

                old_media_path = existing_item["media_path"] if media_info else ""
                try:
                    with database() as connection:
                        connection.execute("""
                            UPDATE guess_library_items
                            SET title = ?,
                                answer = ?,
                                answer_display = ?,
                                answer_aliases_json = ?,
                                prompt_text = ?,
                                category = ?,
                                tags_json = ?,
                                pack_name = ?,
                                enabled = ?,
                                notes = ?,
                                hint_text = ?,
                                auto_hint_minutes = ?,
                                media_path = ?,
                                media_name = ?,
                                media_type = ?,
                                media_size = ?,
                                media_metadata_json = ?,
                                status = ?,
                                updated_at = ?
                            WHERE id = ?
                        """, (
                            title or answer_display,
                            normalized_answer,
                            answer_display,
                            json.dumps(answer_aliases, separators=(",", ":")),
                            prompt_text,
                            category,
                            json.dumps(tags, separators=(",", ":")),
                            pack_name,
                            enabled,
                            notes,
                            hint_text,
                            auto_hint_minutes,
                            media_info["path"] if media_info else existing_item["media_path"],
                            media_info["name"] if media_info else existing_item["media_name"],
                            media_info["type"] if media_info else existing_item["media_type"],
                            int(media_info["size"] or 0) if media_info else int(existing_item["media_size"] or 0),
                            (
                                json.dumps(
                                    media_info["metadata"],
                                    separators=(",", ":"),
                                )
                                if media_info
                                else existing_item["media_metadata_json"]
                            ),
                            new_status,
                            utc_now_iso(),
                            item_id,
                        ))
                        add_admin_audit_log(
                            connection,
                            existing_item["guild_id"],
                            "dashboard_update_guess_library_item",
                            actor_id,
                            actor_name,
                            "guess_library_item",
                            item_id,
                            f"Updated website game-library item {item_id}.",
                        )
                except Exception:
                    if media_info:
                        delete_guess_library_media(media_info["path"])
                    raise
                if old_media_path:
                    delete_guess_library_media(old_media_path)
                return game_library_redirect(
                    f"Library item {item_id} updated.",
                    guild_id=redirect_guild_id,
                )

            if action == "set_status":
                item_id = int(request.form.get("item_id", "0") or 0)
                new_status = request.form.get("status", "").strip()
                if new_status not in {"active", "disabled", "draft"}:
                    raise ValueError("Invalid library item status.")
                with database() as connection:
                    item = connection.execute("""
                        SELECT id, guild_id, title
                        FROM guess_library_items
                        WHERE id = ?
                    """, (item_id,)).fetchone()
                    if not item:
                        raise ValueError("Library item was not found.")
                    if not can_admin_access_guild(item["guild_id"], config_data):
                        abort(403)
                    connection.execute("""
                        UPDATE guess_library_items
                        SET status = ?,
                            updated_at = ?
                        WHERE id = ?
                    """, (new_status, utc_now_iso(), item_id))
                    add_admin_audit_log(
                        connection,
                        item["guild_id"],
                        "dashboard_update_guess_library_item_status",
                        actor_id,
                        actor_name,
                        "guess_library_item",
                        item_id,
                        f"Set website game-library item to {new_status}.",
                    )
                return game_library_redirect(
                    f"Library item {item_id} set to {new_status}.",
                    guild_id=redirect_guild_id,
                )

            if action == "delete_item":
                item_id = int(request.form.get("item_id", "0") or 0)
                with database() as connection:
                    item = connection.execute("""
                        SELECT id, guild_id, title, media_path
                        FROM guess_library_items
                        WHERE id = ?
                    """, (item_id,)).fetchone()
                    if not item:
                        raise ValueError("Library item was not found.")
                    if not can_admin_access_guild(item["guild_id"], config_data):
                        abort(403)
                    connection.execute(
                        "DELETE FROM guess_library_items WHERE id = ?",
                        (item_id,),
                    )
                    add_admin_audit_log(
                        connection,
                        item["guild_id"],
                        "dashboard_delete_guess_library_item",
                        actor_id,
                        actor_name,
                        "guess_library_item",
                        item_id,
                        "Deleted website game-library item.",
                    )
                delete_guess_library_media(item["media_path"])
                return game_library_redirect(
                    f"Library item {item_id} deleted.",
                    guild_id=redirect_guild_id,
                )

            raise ValueError("Unknown game-library action.")
        except (ValueError, OSError, sqlite3.Error) as form_error:
            return game_library_redirect(
                str(form_error),
                error=True,
                guild_id=redirect_guild_id,
            )

    guild_names = guild_name_map(config_data)
    where = []
    parameters = []
    if selected_server_id:
        where.append("guild_id = ?")
        parameters.append(selected_server_id)
    where_sql = "WHERE " + " AND ".join(where) if where else ""
    with closing(connect_db()) as connection:
        rows = connection.execute(f"""
            SELECT *
            FROM guess_library_items
            {where_sql}
            ORDER BY created_at DESC, id DESC
            LIMIT 200
        """, parameters).fetchall()

    items = []
    for row in rows:
        item = dict(row)
        try:
            aliases = json.loads(item.get("answer_aliases_json") or "[]")
        except (TypeError, json.JSONDecodeError):
            aliases = []
        try:
            tags = json.loads(item.get("tags_json") or "[]")
        except (TypeError, json.JSONDecodeError):
            tags = []
        relative_path = media_relative_path(item.get("media_path") or "")
        size = int(item.get("media_size") or 0)
        item["alias_count"] = len(aliases)
        item["tags"] = [str(tag) for tag in tags if str(tag).strip()]
        try:
            item_enabled = int(
                item.get("enabled")
                if item.get("enabled") is not None
                else 1
            )
        except (TypeError, ValueError):
            item_enabled = 1
        item["enabled"] = item_enabled != 0
        item["guild_name"] = guild_names.get(
            item.get("guild_id"),
            item.get("guild_id") or "Unknown",
        )
        item["media_url"] = (
            media_url(relative_path, item.get("guild_id"))
            if relative_path
            else ""
        )
        item["size_label"] = format_bytes(size) if size else ""
        item["status"] = item.get("status") or "active"
        items.append(item)

    max_file_bytes = int(
        config_data.get("limits", {}).get(
            "max_file_bytes",
            DEFAULT_LIMITS["max_file_bytes"],
        )
    )
    max_text_length = int(
        config_data.get("limits", {}).get(
            "max_text_length",
            DEFAULT_LIMITS["max_text_length"],
        )
    )
    return render_template_string(
        GAME_LIBRARY_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        error=error,
        guild_options=options,
        items=items,
        max_file_label=format_bytes(max_file_bytes),
        max_text_length=max_text_length,
        notice=notice,
        selected_guild_id=selected_server_id,
    )


@app.route("/admin/users", methods=["GET", "POST"])
def admin_users():
    login_response = require_admin_login("moderator")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    config_data = load_config()
    guild_names = guild_name_map(config_data)
    actor_id, actor_name = web_actor()

    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        try:
            with database() as connection:
                if action == "request_owner_ban_code":
                    username = normalize_account_username(request.form.get("username", ""))
                    user = connection.execute("""
                        SELECT username, role, disabled
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user or normalize_role(user["role"]) != "owner":
                        raise ValueError("Owner account was not found.")
                    if not current_admin_is_baytae_owner() or username == OWNER_OVERRIDE_USERNAME:
                        abort(403)
                    code = issue_owner_ban_code(username)
                    notice = f"Owner-ban code for {username}: {code}. It expires in 10 minutes."
                elif action == "ban_dashboard_user":
                    username = normalize_account_username(request.form.get("username", ""))
                    owner_code = request.form.get("owner_code", "")
                    user = connection.execute("""
                        SELECT username, role, disabled
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        raise ValueError("Dashboard user was not found.")
                    if not can_ban_dashboard_user(user["role"], username, owner_code):
                        abort(403)
                    now = utc_now_iso()
                    connection.execute("""
                        UPDATE dashboard_admin_users
                        SET disabled = 1, updated_at = ?
                        WHERE username = ?
                    """, (now, username))
                    add_admin_audit_log(
                        connection,
                        None,
                        "dashboard_ban_user",
                        actor_id,
                        actor_name,
                        "dashboard_user",
                        username,
                        f"Banned dashboard user {username}.",
                    )
                    notice = f"Dashboard user {username} banned."
                elif action == "promote_dashboard_user":
                    username = normalize_account_username(request.form.get("username", ""))
                    new_role = normalize_role(request.form.get("role", "user"))
                    user = connection.execute("""
                        SELECT username, role, disabled
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        raise ValueError("Dashboard user was not found.")
                    if not can_promote_dashboard_user(user["role"], new_role, username):
                        abort(403)
                    now = utc_now_iso()
                    connection.execute("""
                        UPDATE dashboard_admin_users
                        SET role = ?, disabled = 0, approved_by = COALESCE(approved_by, ?),
                            approved_at = COALESCE(approved_at, ?), updated_at = ?
                        WHERE username = ?
                    """, (new_role, current_admin_username(), now, now, username))
                    if new_role == "bot_owner":
                        connection.execute("""
                            INSERT INTO dashboard_bot_owners (
                                username, source, created_at, updated_at
                            )
                            VALUES (?, 'manual', ?, ?)
                            ON CONFLICT(username) DO UPDATE SET
                                source = excluded.source,
                                updated_at = excluded.updated_at
                        """, (username, now, now))
                    elif username != OWNER_OVERRIDE_USERNAME:
                        connection.execute("""
                            DELETE FROM dashboard_bot_owners
                            WHERE lower(username) = ?
                        """, (username,))
                    if username == current_admin_username().casefold():
                        session["sdac_admin_role"] = new_role
                    add_admin_audit_log(
                        connection,
                        None,
                        "dashboard_promote_user",
                        actor_id,
                        actor_name,
                        "dashboard_user",
                        username,
                        f"Set dashboard user {username} role to {new_role}.",
                    )
                    notice = f"Dashboard user {username} role saved as {new_role}."
                elif action in {"set_dashboard_server_role", "add_dashboard_user_to_server"}:
                    username = normalize_account_username(request.form.get("username", ""))
                    guild_id = request.form.get("guild_id", "").strip()
                    new_role = normalize_role(request.form.get("role", "user"))
                    if guild_id not in (config_data.get("guilds") or {}):
                        raise ValueError("Unknown server selected.")
                    if not can_admin_access_guild(guild_id, config_data):
                        abort(403)
                    user = connection.execute("""
                        SELECT username, role, disabled, guild_ids_json
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        raise ValueError("Dashboard user was not found.")
                    access_map = dashboard_user_server_access_map(username)
                    if action == "set_dashboard_server_role" and guild_id not in access_map and normalize_role(user["role"]) != "bot_owner":
                        raise ValueError("That user is not linked to the selected server yet.")
                    current_target_role = access_map.get(guild_id, "not_added" if action == "add_dashboard_user_to_server" else normalize_role(user["role"]))
                    if not can_promote_dashboard_user(current_target_role, new_role, username):
                        abort(403)
                    if new_role == "not_added":
                        remove_user_server_role(connection, username, guild_id)
                        new_scope = sorted(set(parse_guild_scope(user["guild_ids_json"])) - {guild_id})
                        audit_details = f"Removed dashboard user {username} from {guild_id}."
                        notice = f"Removed {username} from that server."
                    else:
                        set_user_server_role(connection, username, guild_id, new_role)
                        new_scope = sorted(set(parse_guild_scope(user["guild_ids_json"])) | {guild_id})
                        new_account_role = "user" if normalize_role(user["role"]) == "not_added" else normalize_role(user["role"])
                        connection.execute("""
                            UPDATE dashboard_admin_users
                            SET role = ?, guild_ids_json = ?, updated_at = ?
                            WHERE username = ?
                        """, (
                            new_account_role,
                            json.dumps(new_scope, separators=(",", ":")),
                            utc_now_iso(),
                            username,
                        ))
                        audit_details = f"Set dashboard user {username} role to {new_role} on {guild_id}."
                        notice = f"Server role saved for {username}."
                    if username == current_admin_username().casefold():
                        session["sdac_admin_guild_ids"] = new_scope
                    if username == current_account_username().casefold():
                        session["sdac_account_guild_ids"] = new_scope
                    add_admin_audit_log(
                        connection,
                        guild_id,
                        "dashboard_set_server_role",
                        actor_id,
                        actor_name,
                        "dashboard_user",
                        username,
                        audit_details,
                    )
                elif action == "issue_dashboard_auth_code":
                    username = normalize_account_username(request.form.get("username", ""))
                    guild_id = request.form.get("guild_id", "").strip()
                    role = normalize_role(request.form.get("role", "user"))
                    if guild_id not in (config_data.get("guilds") or {}):
                        raise ValueError("Unknown server selected.")
                    if not can_admin_access_guild(guild_id, config_data):
                        abort(403)
                    user = connection.execute("""
                        SELECT username, role, disabled
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        raise ValueError("Dashboard user was not found.")
                    if not can_promote_dashboard_user("not_added", role, username):
                        abort(403)
                    code, expires_at = issue_dashboard_auth_code(
                        connection,
                        username,
                        guild_id,
                        role,
                        current_admin_username(),
                    )
                    add_admin_audit_log(
                        connection,
                        guild_id,
                        "dashboard_issue_auth_code",
                        actor_id,
                        actor_name,
                        "dashboard_user",
                        username,
                        f"Issued account authentication code for {username} on {guild_id} as {role}.",
                    )
                    guild_label = guild_names.get(guild_id, guild_id)
                    notice = f"Auth code for {username} on {guild_label}: {code}. It expires at {expires_at}."
                elif action == "set_user_lockout":
                    user_id = normalize_discord_user_id(request.form.get("user_id", ""))
                    if not user_id:
                        raise ValueError("Discord user ID is required.")
                    guild_id = request.form.get("guild_id", "").strip()
                    if guild_id and guild_id not in (config_data.get("guilds") or {}):
                        raise ValueError("Unknown server selected.")
                    if guild_id and not can_admin_access_guild(guild_id, config_data):
                        abort(403)
                    linked = dashboard_user_by_discord_id(connection, user_id)
                    if linked and not can_lockout_dashboard_target(linked["role"], linked["username"]):
                        abort(403)
                    scope = request.form.get("scope", "both")
                    if scope not in LOCKOUT_SCOPE_LABELS:
                        raise ValueError("Unknown lockout scope.")
                    lock_games = 1 if scope in {"games", "both"} else 0
                    lock_submissions = 1 if scope in {"submissions", "both"} else 0
                    username = request.form.get("username", "").strip()[:120]
                    reason = request.form.get("reason", "").strip()[:500]
                    now = utc_now_iso()
                    connection.execute("""
                        INSERT INTO user_restrictions (
                            guild_id, user_id, username, lock_games,
                            lock_submissions, reason, active, created_by,
                            created_by_name, created_at, updated_at
                        )
                        VALUES (?, ?, ?, ?, ?, ?, 1, ?, ?, ?, ?)
                        ON CONFLICT(guild_id, user_id) DO UPDATE SET
                            username = excluded.username,
                            lock_games = excluded.lock_games,
                            lock_submissions = excluded.lock_submissions,
                            reason = excluded.reason,
                            active = 1,
                            updated_at = excluded.updated_at
                    """, (
                        guild_id,
                        user_id,
                        username,
                        lock_games,
                        lock_submissions,
                        reason,
                        str(actor_id),
                        str(actor_name),
                        now,
                        now,
                    ))
                    add_admin_audit_log(
                        connection,
                        guild_id or None,
                        "dashboard_set_user_lockout",
                        actor_id,
                        actor_name,
                        "discord_user",
                        user_id,
                        f"Set {LOCKOUT_SCOPE_LABELS[scope]} lockout. {reason}",
                    )
                    notice = "User lockout saved."
                elif action == "clear_user_lockout":
                    restriction_id = int(request.form.get("restriction_id", "0") or 0)
                    row = connection.execute("""
                        SELECT restrictions.*, users.role AS dashboard_role,
                               users.username AS dashboard_username
                        FROM user_restrictions AS restrictions
                        LEFT JOIN dashboard_admin_users AS users
                          ON users.discord_user_id = restrictions.user_id
                        WHERE restrictions.id = ?
                    """, (restriction_id,)).fetchone()
                    if not row:
                        raise ValueError("Lockout was not found.")
                    if row["guild_id"] and not can_admin_access_guild(row["guild_id"], config_data):
                        abort(403)
                    if row["dashboard_role"] and not can_lockout_dashboard_target(row["dashboard_role"], row["dashboard_username"]):
                        abort(403)
                    now = utc_now_iso()
                    connection.execute("""
                        UPDATE user_restrictions
                        SET active = 0, updated_at = ?
                        WHERE id = ?
                    """, (now, restriction_id))
                    add_admin_audit_log(
                        connection,
                        row["guild_id"] or None,
                        "dashboard_clear_user_lockout",
                        actor_id,
                        actor_name,
                        "discord_user",
                        row["user_id"],
                        "Cleared user lockout.",
                    )
                    notice = "User lockout cleared."
                else:
                    raise ValueError("Unknown user action.")
        except ValueError as form_error:
            return redirect(url_for(
                "admin_users",
                key=ADMIN_KEY,
                notice=str(form_error),
                error=1,
            ))
        return redirect(url_for("admin_users", key=ADMIN_KEY, notice=notice))

    dashboard_user_rows = dashboard_users()
    access_by_user = {
        user["username"]: dashboard_user_server_access_map(user["username"])
        for user in dashboard_user_rows
    }
    access_rows_by_user = {
        user["username"]: dashboard_user_access_rows(user, config_data)
        for user in dashboard_user_rows
    }
    access_summary_by_user = {
        user["username"]: dashboard_user_access_summary(user, config_data)
        for user in dashboard_user_rows
    }
    addable_guilds_by_user = {
        user["username"]: dashboard_user_addable_guilds(user, config_data)
        for user in dashboard_user_rows
    }
    matrix_role_labels = ROLE_LABELS
    assignable_role_labels = {
        key: label
        for key, label in ROLE_LABELS.items()
        if key != "not_added"
    }
    return render_template_string(
        USERS_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        current_admin_is_baytae_owner=current_admin_is_baytae_owner,
        can_ban_dashboard_user=can_ban_dashboard_user,
        can_promote_dashboard_user=can_promote_dashboard_user,
        access_by_user=access_by_user,
        access_rows_by_user=access_rows_by_user,
        access_summary_by_user=access_summary_by_user,
        addable_guilds_by_user=addable_guilds_by_user,
        assignable_role_labels=assignable_role_labels,
        dashboard_users=dashboard_user_rows,
        error=error,
        guild_names=guild_names,
        guilds=guild_options(config_data),
        known_users=known_discord_users(),
        lockout_scope_labels=LOCKOUT_SCOPE_LABELS,
        matrix_role_labels=matrix_role_labels,
        notice=notice,
        owner_override_username=OWNER_OVERRIDE_USERNAME,
        restrictions=dashboard_user_restrictions(),
        role_labels=ROLE_LABELS,
    )


@app.route("/admin/preview-as")
def admin_preview_as():
    login_response = require_admin_login("bot_owner")
    if login_response:
        return login_response
    config_data = load_config()
    users = dashboard_users()
    username = normalize_account_username(
        request.args.get("username") or (users[0]["username"] if users else current_admin_username())
    )
    guild_options_rows = guild_options(config_data)
    guild_id = request.args.get("guild_id", "").strip()
    if not guild_id and guild_options_rows:
        guild_id = str(guild_options_rows[0]["id"])
    user = dashboard_user(username)
    access_map = dashboard_user_server_access_map(username)
    role = "bot_owner" if is_bot_owner_username(username) else normalize_role(user["role"] if user else "user")
    if guild_id and guild_id in access_map:
        role = access_map[guild_id]
    allowed_ids = set(config_data.get("guilds") or {}) if is_bot_owner_username(username) else set(access_map)
    if not allowed_ids and user:
        allowed_ids = set(parse_guild_scope(user["guild_ids_json"]))
    visible_sections = []
    for label, required_role in [
        ("User", "user"),
        ("Cross Server", "moderator"),
        ("Moderation", "moderator"),
        ("Server Owner", "owner"),
        ("Bot Owner", "bot_owner"),
    ]:
        visible_sections.append({
            "label": label,
            "visible": ROLE_LEVELS[role] >= ROLE_LEVELS[required_role],
            "required": ROLE_LABELS[required_role],
        })
    return render_template_string("""
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Preview Access</title>
    <style>
        :root { color-scheme: dark; }
        body { background: #101114; color: #f4f5f7; font-family: Arial, sans-serif; margin: 0; padding: clamp(1rem, 3vw, 1.5rem); }
        main { margin: 0 auto; width: min(100%, 1000px); }
        h1, h2 { text-align: center; }
        .panel { background: #1b1d22; border: 1px solid #30333b; border-radius: 0.75rem; margin: clamp(0.75rem, 2vw, 1rem) 0; padding: clamp(0.85rem, 2vw, 1rem); }
        table { border-collapse: collapse; width: 100%; }
        th, td { border-bottom: 1px solid #30333b; padding: 10px; text-align: left; vertical-align: top; }
        input, select, button { border: 1px solid #30333b; border-radius: 7px; font-size: 15px; padding: 9px 10px; }
        button { background: #7c9cff; color: #0b1020; cursor: pointer; font-weight: bold; }
        .ok { color: #63c174; font-weight: bold; }
        .bad { color: #e45d68; font-weight: bold; }
        .muted { color: #a8adb8; }
        code { color: #cdd7ff; }
    </style>
</head>
<body>
<main>
    <h1>Preview Access</h1>
    <section class="panel">
        <form method="get">
            <input type="hidden" name="key" value="{{ admin_key }}">
            <label>User
                <select name="username">
                    {% for row in users %}
                        <option value="{{ row.username }}" {% if row.username == username %}selected{% endif %}>{{ row.username }}</option>
                    {% endfor %}
                </select>
            </label>
            <label>Server
                <select name="guild_id">
                    {% for guild in guilds %}
                        <option value="{{ guild.id }}" {% if guild.id == guild_id %}selected{% endif %}>{{ guild.name }} ({{ guild.id }})</option>
                    {% endfor %}
                </select>
            </label>
            <button type="submit">Preview</button>
        </form>
    </section>
    <section class="panel">
        <h2>Result</h2>
        <p>User: <code>{{ username }}</code></p>
        <p>Server: <code>{{ guild_id or 'all' }}</code></p>
        <p>Effective role: <strong>{{ role_labels.get(role, role) }}</strong></p>
        <p>Server access: <span class="{{ 'ok' if guild_id in allowed_ids else 'bad' }}">{{ 'Allowed' if guild_id in allowed_ids else 'Not linked' }}</span></p>
        <p class="muted">This is a read-only preview. It does not change your session or perform actions as the selected user.</p>
    </section>
    <section class="panel">
        <h2>Sidebar Sections</h2>
        <table>
            <thead><tr><th>Section</th><th>Required</th><th>Visible</th></tr></thead>
            <tbody>
                {% for section in visible_sections %}
                    <tr>
                        <td>{{ section.label }}</td>
                        <td>{{ section.required }}</td>
                        <td><span class="{{ 'ok' if section.visible else 'bad' }}">{{ 'Yes' if section.visible else 'No' }}</span></td>
                    </tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
</main>
</body>
</html>
""",
        admin_key=ADMIN_KEY,
        allowed_ids=allowed_ids,
        guild_id=guild_id,
        guilds=guild_options_rows,
        role=role,
        role_labels=ROLE_LABELS,
        username=username,
        users=users,
        visible_sections=visible_sections,
    )


@app.route("/admin/settings", methods=["GET", "POST"])
def admin_settings():
    login_response = require_admin_login("admin")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"

    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        actor_id, actor_name = web_actor()
        if action in {
            "create_dashboard_user",
            "update_dashboard_user",
            "disable_dashboard_user",
        }:
            if not has_admin_role("admin"):
                abort(403)
            raw_username = request.form.get("username", "")
            raw_email = request.form.get("email", "")
            raw_discord_user_id = request.form.get("discord_user_id", "")
            display_name = request.form.get("display_name", "").strip()[:120]
            role = normalize_role(request.form.get("role", "user"))
            password = request.form.get("password", "")
            try:
                email = normalize_email(raw_email)
                discord_user_id = normalize_discord_user_id(raw_discord_user_id)
                username = normalize_account_username(raw_username, email)
                guild_scope = parse_guild_scope(request.form.get("guild_ids", ""))
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))
            if not can_assign_dashboard_role(role):
                abort(403)
            if role != "bot_owner":
                assignment_role = "owner" if role in {"admin", "owner"} else "admin"
                allowed_assignment_ids = current_admin_allowed_guild_ids(
                    config_data,
                    assignment_role,
                )
                if any(guild_id not in allowed_assignment_ids for guild_id in guild_scope):
                    abort(403)
            guild_scope_json = json.dumps(guild_scope, separators=(",", ":"))
            now = utc_now_iso()
            with database() as connection:
                if action == "create_dashboard_user":
                    if not password:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="Password is required for new dashboard users.",
                            error=1,
                        ))
                    existing_email = None
                    if email:
                        existing_email = connection.execute("""
                            SELECT username
                            FROM dashboard_admin_users
                            WHERE lower(COALESCE(email, '')) = ?
                              AND username != ?
                            LIMIT 1
                        """, (email, username)).fetchone()
                    if existing_email:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="That email address already belongs to another account.",
                            error=1,
                        ))
                    existing_discord_id = None
                    if discord_user_id:
                        existing_discord_id = connection.execute("""
                            SELECT username
                            FROM dashboard_admin_users
                            WHERE discord_user_id = ?
                              AND username != ?
                            LIMIT 1
                        """, (discord_user_id, username)).fetchone()
                    if existing_discord_id:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="That Discord user ID already belongs to another account.",
                            error=1,
                        ))
                    connection.execute("""
                        INSERT INTO dashboard_admin_users (
                            username, email, display_name, discord_user_id,
                            password_hash, role, disabled, created_at,
                            updated_at, guild_ids_json, approved_by, approved_at
                        )
                        VALUES (?, ?, ?, ?, ?, ?, 0, ?, ?, ?, ?, ?)
                        ON CONFLICT(username) DO UPDATE SET
                            email = excluded.email,
                            display_name = excluded.display_name,
                            discord_user_id = excluded.discord_user_id,
                            password_hash = excluded.password_hash,
                            role = excluded.role,
                            disabled = 0,
                            guild_ids_json = excluded.guild_ids_json,
                            approved_by = excluded.approved_by,
                            approved_at = excluded.approved_at,
                            updated_at = excluded.updated_at
                    """, (
                        username,
                        email,
                        display_name,
                        discord_user_id,
                        generate_password_hash(password),
                        role,
                        now,
                        now,
                        guild_scope_json,
                        current_admin_username(),
                        now,
                    ))
                    assigned_scope = sorted((config_data.get("guilds") or {}).keys()) if role == "bot_owner" else guild_scope
                    upsert_user_server_access(
                        connection,
                        username,
                        assigned_scope,
                        role=role,
                        source="manual",
                    )
                    prune_user_server_access(connection, username, assigned_scope)
                    if role == "bot_owner":
                        connection.execute("""
                            INSERT INTO dashboard_bot_owners (
                                username, source, created_at, updated_at
                            )
                            VALUES (?, 'manual', ?, ?)
                            ON CONFLICT(username) DO UPDATE SET
                                source = excluded.source,
                                updated_at = excluded.updated_at
                        """, (username, now, now))
                    elif username != OWNER_OVERRIDE_USERNAME:
                        connection.execute("""
                            DELETE FROM dashboard_bot_owners
                            WHERE lower(username) = ?
                        """, (username,))
                    message = f"Dashboard user {username} saved as {role}."
                elif action == "update_dashboard_user":
                    user = connection.execute("""
                        SELECT username, role
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="Dashboard user was not found.",
                            error=1,
                        ))
                    if not can_manage_dashboard_user(user["role"], username):
                        abort(403)
                    if not can_assign_dashboard_role(role):
                        abort(403)
                    existing_email = None
                    if email:
                        existing_email = connection.execute("""
                            SELECT username
                            FROM dashboard_admin_users
                            WHERE lower(COALESCE(email, '')) = ?
                              AND username != ?
                            LIMIT 1
                        """, (email, username)).fetchone()
                    if existing_email:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="That email address already belongs to another account.",
                            error=1,
                        ))
                    existing_discord_id = None
                    if discord_user_id:
                        existing_discord_id = connection.execute("""
                            SELECT username
                            FROM dashboard_admin_users
                            WHERE discord_user_id = ?
                              AND username != ?
                            LIMIT 1
                        """, (discord_user_id, username)).fetchone()
                    if existing_discord_id:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="That Discord user ID already belongs to another account.",
                            error=1,
                        ))
                    if password:
                        connection.execute("""
                            UPDATE dashboard_admin_users
                            SET email = ?, display_name = ?, discord_user_id = ?,
                                password_hash = ?, role = ?, guild_ids_json = ?,
                                disabled = 0,
                                approved_by = COALESCE(approved_by, ?),
                                approved_at = COALESCE(approved_at, ?),
                                updated_at = ?
                            WHERE username = ?
                        """, (
                            email,
                            display_name,
                            discord_user_id,
                            generate_password_hash(password),
                            role,
                            guild_scope_json,
                            current_admin_username(),
                            now,
                            now,
                            username,
                        ))
                    else:
                        connection.execute("""
                            UPDATE dashboard_admin_users
                            SET email = ?, display_name = ?, discord_user_id = ?,
                                role = ?, guild_ids_json = ?, disabled = 0,
                                approved_by = COALESCE(approved_by, ?),
                                approved_at = COALESCE(approved_at, ?),
                                updated_at = ?
                            WHERE username = ?
                        """, (
                            email,
                            display_name,
                            discord_user_id,
                            role,
                            guild_scope_json,
                            current_admin_username(),
                            now,
                            now,
                            username,
                        ))
                    assigned_scope = sorted((config_data.get("guilds") or {}).keys()) if role == "bot_owner" else guild_scope
                    upsert_user_server_access(
                        connection,
                        username,
                        assigned_scope,
                        role=role,
                        source="manual",
                    )
                    prune_user_server_access(connection, username, assigned_scope)
                    if role == "bot_owner":
                        connection.execute("""
                            INSERT INTO dashboard_bot_owners (
                                username, source, created_at, updated_at
                            )
                            VALUES (?, 'manual', ?, ?)
                            ON CONFLICT(username) DO UPDATE SET
                                source = excluded.source,
                                updated_at = excluded.updated_at
                        """, (username, now, now))
                    elif username != OWNER_OVERRIDE_USERNAME:
                        connection.execute("""
                            DELETE FROM dashboard_bot_owners
                            WHERE lower(username) = ?
                        """, (username,))
                    message = f"Dashboard user {username} updated."
                    if username == current_account_username().casefold():
                        session["sdac_account_role"] = role
                        session["sdac_discord_user_id"] = discord_user_id
                    if username == current_admin_username().casefold():
                        session["sdac_admin_role"] = role
                        session["sdac_admin_guild_ids"] = guild_scope
                else:
                    user = connection.execute("""
                        SELECT username, role
                        FROM dashboard_admin_users
                        WHERE username = ?
                    """, (username,)).fetchone()
                    if not user:
                        return redirect(url_for(
                            "admin_settings",
                            key=ADMIN_KEY,
                            notice="Dashboard user was not found.",
                            error=1,
                        ))
                    if not can_manage_dashboard_user(user["role"], username):
                        abort(403)
                    connection.execute("""
                        UPDATE dashboard_admin_users
                        SET disabled = 1, updated_at = ?
                        WHERE username = ?
                    """, (now, username))
                    message = f"Dashboard user {username} disabled."
                add_admin_audit_log(
                    connection,
                    None,
                    f"dashboard_{action}",
                    actor_id,
                    actor_name,
                    "dashboard_user",
                    username,
                    message,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
            ))
        if action == "set_bot_nickname":
            config_data = load_config()
            guild_id = request.form.get("guild_id", "").strip()
            guild_config = (config_data.get("guilds") or {}).get(guild_id)
            if not guild_config:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice="Unknown guild for bot nickname.",
                    error=1,
                ))
            if not can_admin_access_guild(guild_id, config_data):
                abort(403)
            if not has_admin_role("owner"):
                abort(403)
            try:
                nickname = normalize_bot_nickname(request.form.get("bot_nickname"))
                update_discord_bot_nickname(guild_id, nickname)
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                    guild_id=guild_id,
                ))
            except HTTPError as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=discord_api_error_message(discord_error),
                    error=1,
                    guild_id=guild_id,
                ))
            except (URLError, TimeoutError, json.JSONDecodeError) as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=f"Discord API request failed: {discord_error}",
                    error=1,
                    guild_id=guild_id,
                ))
            guild_config["bot_nickname"] = nickname
            save_config(config_data)
            message = (
                f"Bot nickname saved for {guild_config.get('guild_name') or guild_id}."
                if nickname
                else f"Bot nickname reset for {guild_config.get('guild_name') or guild_id}."
            )
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    guild_id,
                    "dashboard_set_bot_nickname",
                    actor_id,
                    actor_name,
                    "guild",
                    guild_id,
                    message,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
                guild_id=guild_id,
            ))
        if action == "set_global_bot_username":
            if not has_admin_role("bot_owner"):
                abort(403)
            try:
                username = normalize_bot_username(request.form.get("bot_username"))
                update_discord_bot_username(username)
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))
            except HTTPError as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=discord_api_error_message(discord_error),
                    error=1,
                ))
            except (URLError, TimeoutError, json.JSONDecodeError) as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=f"Discord API request failed: {discord_error}",
                    error=1,
                ))
            config_data = load_config()
            config_data["bot_username"] = username
            save_config(config_data)
            message = f"Global bot username saved as {username}."
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_set_global_bot_username",
                    actor_id,
                    actor_name,
                    "bot",
                    "@me",
                    message,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
            ))
        if action == "set_global_bot_avatar":
            if not has_admin_role("bot_owner"):
                abort(403)
            source = "upload"
            try:
                uploaded = request.files.get("bot_avatar_file")
                if uploaded and uploaded.filename:
                    avatar_data = uploaded.read(BOT_AVATAR_MAX_BYTES + 1)
                    avatar_type = uploaded.mimetype or ""
                else:
                    avatar_data, avatar_type, source = fetch_bot_avatar_url(
                        request.form.get("bot_avatar_url")
                    )
                update_discord_bot_avatar(avatar_data, avatar_type)
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))
            except HTTPError as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=discord_api_error_message(discord_error),
                    error=1,
                ))
            except (URLError, TimeoutError, json.JSONDecodeError) as discord_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=f"Discord API request failed: {discord_error}",
                    error=1,
                ))
            config_data = load_config()
            updated_at = datetime.now(timezone.utc).isoformat()
            config_data["bot_avatar_updated_at"] = updated_at
            config_data["bot_avatar_source"] = source
            save_config(config_data)
            message = "Global bot image updated. Discord may take a moment to refresh it everywhere."
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_set_global_bot_avatar",
                    actor_id,
                    actor_name,
                    "bot",
                    "@me",
                    message,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
            ))
        if action == "set_notification_route":
            config_data = load_config()
            guild_id = request.form.get("guild_id", "").strip()
            if guild_id not in (config_data.get("guilds") or {}):
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice="Unknown guild for notification route.",
                    error=1,
                ))
            if not can_admin_access_guild(guild_id, config_data):
                abort(403)
            event_key = request.form.get("event_key", "").strip()
            if event_key not in NOTIFICATION_EVENT_LABELS:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice="Unknown notification event.",
                    error=1,
                ))
            try:
                channel_id = nullable_channel_id(request.form.get("channel_id"))
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))
            enabled = request.form.get("enabled") == "1"
            if enabled and channel_id is None:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice="Enabled notification routes need a channel ID.",
                    error=1,
                ))
            now = utc_now_iso()
            with database() as connection:
                connection.execute("""
                    INSERT INTO admin_notifications (
                        guild_id, event_key, channel_id, enabled,
                        created_at, updated_at
                    )
                    VALUES (?, ?, ?, ?, ?, ?)
                    ON CONFLICT(guild_id, event_key) DO UPDATE SET
                        channel_id = excluded.channel_id,
                        enabled = excluded.enabled,
                        updated_at = excluded.updated_at
                """, (
                    guild_id,
                    event_key,
                    str(channel_id) if channel_id is not None else "",
                    1 if enabled else 0,
                    now,
                    now,
                ))
                add_admin_audit_log(
                    connection,
                    guild_id,
                    "dashboard_set_notification_route",
                    actor_id,
                    actor_name,
                    "admin_notification",
                    event_key,
                    (
                        f"Set {NOTIFICATION_EVENT_LABELS[event_key]} route to "
                        f"{channel_id or 'disabled'}."
                    ),
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice="Notification route saved.",
            ))
        if action == "backup_now":
            label = datetime.now(timezone.utc).strftime("manual-%Y-%m-%d-%H%M%S")
            try:
                backup_path, created, message = create_database_backup(label)
            except (OSError, sqlite3.Error) as backup_error:
                backup_path = None
                created = False
                message = f"Backup failed: {backup_error}"
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "database_backup_manual",
                    actor_id,
                    actor_name,
                    "backup",
                    backup_path.name if backup_path else "",
                    message,
                )
            if not created and message != "Backup already exists.":
                send_admin_notification(
                    "backup_failed",
                    f"Manual dashboard backup failed: `{message}`",
                    throttle_key="dashboard_backup_failed",
                    throttle_seconds=900,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
                error=0 if created else 1,
            ))
        if action == "update_limits":
            config_data = load_config()
            limits = config_data.setdefault("limits", {})
            try:
                for field in (
                    "wrong_guess_timeout_seconds",
                    "submission_user_cooldown_seconds",
                    "submission_category_cooldown_seconds",
                    "guess_command_cooldown_seconds",
                    "admin_action_cooldown_seconds",
                    "rate_limit_retention_days",
                    "audit_retention_days",
                    "pending_submission_retention_hours",
                    "media_warning_bytes",
                    "database_warning_bytes",
                    "monthly_submission_limit_per_guild",
                    "active_game_limit_per_guild",
                    "guild_storage_limit_bytes",
                    "offsite_backup_warning_hours",
                    "local_original_retention_days",
                    "thumbnail_max_dimension",
                    "image_compression_quality",
                    "archive_full_history_after_months",
                    "spam_review_threshold",
                    "spam_burst_count",
                    "spam_burst_window_minutes",
                ):
                    value = int(request.form.get(field, "0"))
                    if value < 0:
                        raise ValueError("Limits cannot be negative.")
                    limits[field] = value
                if limits["thumbnail_max_dimension"] and not (
                    160 <= limits["thumbnail_max_dimension"] <= 2048
                ):
                    raise ValueError(
                        "Thumbnail max dimension must be between 160 and 2048."
                    )
                if limits["image_compression_quality"] and not (
                    40 <= limits["image_compression_quality"] <= 95
                ):
                    raise ValueError(
                        "Image compression quality must be between 40 and 95."
                    )
                restore_weekday = request.form.get(
                    "restore_test_weekday",
                    "sunday",
                )
                if restore_weekday not in WEEKDAYS:
                    raise ValueError("Invalid restore test weekday.")
                limits["restore_test_weekday"] = restore_weekday
                limits["restore_test_time_utc"] = validate_time(
                    request.form.get("restore_test_time_utc")
                )
                limits["restore_test_enabled"] = (
                    request.form.get("restore_test_enabled") == "1"
                )
                limits["restore_drill_enabled"] = (
                    request.form.get("restore_drill_enabled") == "1"
                )
                limits["monthly_digest_enabled"] = (
                    request.form.get("monthly_digest_enabled") == "1"
                )
                limits["two_admin_approval_enabled"] = (
                    request.form.get("two_admin_approval_enabled") == "1"
                )
                limits["orphan_media_cleanup_enabled"] = (
                    request.form.get("orphan_media_cleanup_enabled") == "1"
                )
                limits["image_compression_enabled"] = (
                    request.form.get("image_compression_enabled") == "1"
                )
                limits["thumbnail_pregeneration_enabled"] = (
                    request.form.get("thumbnail_pregeneration_enabled") == "1"
                )
                limits["database_maintenance_enabled"] = (
                    request.form.get("database_maintenance_enabled") == "1"
                )
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))
            save_config(config_data)
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_update_limits",
                    actor_id,
                    actor_name,
                    "limits",
                    "",
                    "Updated bot limits from dashboard.",
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice="Bot limits saved.",
            ))
        if action in {"update_guild", "save_category", "delete_category"}:
            config_data = load_config()
            guild_id = request.form.get("guild_id", "").strip()
            guild_config = (config_data.get("guilds") or {}).get(guild_id)
            if not guild_config:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice="Unknown guild.",
                    error=1,
                ))
            if not can_admin_access_guild(guild_id, config_data):
                abort(403)
            try:
                if action == "update_guild":
                    brand_accent = (
                        request.form.get("brand_accent", "#7c9cff").strip()
                        or "#7c9cff"
                    )
                    if not re.match(r"^#[0-9A-Fa-f]{6}$", brand_accent):
                        raise ValueError(
                            "Brand accent must be a hex color like #7c9cff."
                        )
                    guild_config["brand_name"] = request.form.get(
                        "brand_name",
                        "",
                    ).strip()[:80]
                    guild_config["brand_accent"] = brand_accent
                    guild_config["brand_logo_url"] = request.form.get(
                        "brand_logo_url",
                        "",
                    ).strip()[:200]
                    guild_config["timezone"] = request.form.get(
                        "timezone",
                        "UTC",
                    ).strip() or "UTC"
                    guild_config["submit_channel"] = nullable_channel_id(
                        request.form.get("submit_channel")
                    )
                    guild_config["daily_top_channel"] = nullable_channel_id(
                        request.form.get("weekly_channel")
                    )
                    guild_config["daily_top_time_utc"] = validate_time(
                        request.form.get("weekly_time")
                    )
                    weekday = request.form.get("weekly_top_day", "sunday")
                    if weekday not in WEEKDAYS:
                        raise ValueError("Invalid weekly day.")
                    guild_config["weekly_top_day"] = weekday
                    guild_config["approval_enabled"] = (
                        request.form.get("approval_enabled") == "1"
                    )
                    guild_config["approval_channel"] = nullable_channel_id(
                        request.form.get("approval_channel")
                    )
                    guild_config["emergency_paused"] = (
                        request.form.get("emergency_paused") == "1"
                    )
                    guild_config["emergency_reason"] = request.form.get(
                        "emergency_reason",
                        "",
                    ).strip()[:300]
                    if not guild_config["emergency_paused"]:
                        guild_config["emergency_reason"] = ""
                    guild_config["game_summary_channel"] = nullable_channel_id(
                        request.form.get("game_summary_channel")
                    )
                    guild_config["error_channel"] = nullable_channel_id(
                        request.form.get("error_channel")
                    )
                    guild_config["admin_role_ids"] = role_id_list(
                        request.form.get("admin_role_ids")
                    )
                    guild_config["public_stats_enabled"] = (
                        request.form.get("public_stats_enabled") == "1"
                    )
                    backup_remote = request.form.get(
                        "external_backup_remote",
                        "",
                    ).strip()[:300]
                    if any(character in backup_remote for character in "\r\n"):
                        raise ValueError(
                            "External backup remote cannot contain line breaks."
                        )
                    backup_public_base = request.form.get(
                        "external_backup_public_base_url",
                        "",
                    ).strip().rstrip("/")[:300]
                    if backup_public_base and not backup_public_base.startswith(
                        ("https://", "http://")
                    ):
                        raise ValueError(
                            "External backup public media URL must start with http:// or https://."
                        )
                    include_media = (
                        request.form.get("external_backup_include_media") == "1"
                    )
                    delete_local_media = (
                        request.form.get(
                            "external_backup_delete_local_media_after_success"
                        ) == "1"
                    )
                    if delete_local_media and not include_media:
                        raise ValueError(
                            "Local media cleanup requires media backup to be enabled."
                        )
                    backup_enabled = (
                        request.form.get("external_backup_enabled") == "1"
                    )
                    if backup_enabled and not backup_remote:
                        raise ValueError(
                            "External backup remote is required when backups are enabled."
                        )
                    existing_backup = guild_config.get("external_backup") or {}
                    guild_config["external_backup"] = {
                        **DEFAULT_GUILD_FIELDS["external_backup"],
                        **existing_backup,
                        "enabled": backup_enabled,
                        "provider": "rclone",
                        "remote": backup_remote,
                        "public_base_url": backup_public_base,
                        "include_media": include_media,
                        "include_database_export": (
                            request.form.get(
                                "external_backup_include_database_export"
                            ) == "1"
                        ),
                        "zip_backups": (
                            request.form.get("external_backup_zip_backups") == "1"
                        ),
                        "delete_local_media_after_success": delete_local_media,
                    }
                    guild_limits = guild_config.setdefault("limits", {})
                    for field, form_name in (
                        ("max_file_bytes", "guild_max_file_bytes"),
                        ("max_total_bytes", "guild_max_total_bytes"),
                        ("monthly_submission_limit", "guild_monthly_submission_limit"),
                        ("active_game_limit", "guild_active_game_limit"),
                        ("storage_limit_bytes", "guild_storage_limit_bytes"),
                    ):
                        value = int(request.form.get(form_name, "0") or 0)
                        if value < 0:
                            raise ValueError("Guild limits cannot be negative.")
                        guild_limits[field] = value
                    media_types = [
                        item.strip().casefold()
                        for item in request.form.get(
                            "allowed_media_types",
                            "image,video,audio",
                        ).split(",")
                        if item.strip()
                    ]
                    invalid_types = sorted(
                        set(media_types) - {"image", "video", "audio"}
                    )
                    if invalid_types:
                        raise ValueError(
                            "Allowed media types can only include image, video, and audio."
                        )
                    new_user_days = int(request.form.get("new_user_days", "7") or 7)
                    if new_user_days < 0 or new_user_days > 365:
                        raise ValueError("New-user days must be 0-365.")
                    spam_burst_count = int(
                        request.form.get("spam_burst_count", "5") or 0
                    )
                    spam_burst_window = int(
                        request.form.get("spam_burst_window_minutes", "10") or 0
                    )
                    spam_review_threshold = int(
                        request.form.get("spam_review_threshold", "40") or 0
                    )
                    if spam_burst_count < 0 or spam_burst_count > 100:
                        raise ValueError("Spam burst count must be 0-100.")
                    if spam_burst_window < 0 or spam_burst_window > 1440:
                        raise ValueError("Spam burst window must be 0-1440 minutes.")
                    if spam_review_threshold < 0 or spam_review_threshold > 1000:
                        raise ValueError("Spam review threshold must be 0-1000.")
                    moderation_config = guild_config.setdefault("moderation", {})
                    moderation_config.update({
                        "blocked_words": [
                            item.strip()
                            for item in request.form.get("blocked_words", "").split(",")
                            if item.strip()
                        ][:100],
                        "allowed_media_types": media_types or ["image", "video", "audio"],
                        "require_approval_for_new_users": (
                            request.form.get("require_approval_for_new_users") == "1"
                        ),
                        "new_user_days": new_user_days,
                        "spoiler_requires_approval": (
                            request.form.get("spoiler_requires_approval") == "1"
                        ),
                        "duplicate_requires_approval": (
                            request.form.get("duplicate_requires_approval") == "1"
                        ),
                        "spam_burst_count": spam_burst_count,
                        "spam_burst_window_minutes": spam_burst_window,
                        "spam_review_threshold": spam_review_threshold,
                    })
                    reuse_days = int(request.form.get("reuse_cooldown_days", "30") or 0)
                    auto_hint = int(request.form.get("default_auto_hint_minutes", "0") or 0)
                    if reuse_days < 0 or reuse_days > 3650:
                        raise ValueError("Reuse cooldown must be 0-3650 days.")
                    if auto_hint < 0 or auto_hint > 1440:
                        raise ValueError("Auto-hint minutes must be 0-1440.")
                    guild_config["game_settings"] = {
                        "reuse_cooldown_days": reuse_days,
                        "default_auto_hint_minutes": auto_hint,
                        "default_difficulty": request.form.get(
                            "default_difficulty",
                            "normal",
                        ).strip()[:40] or "normal",
                    }
                    features = guild_config.setdefault("features", {})
                    for feature_key in DEFAULT_FEATURES:
                        features[feature_key] = (
                            request.form.get(f"feature_{feature_key}") == "1"
                        )
                    message = "Guild settings saved."
                elif action == "save_category":
                    category = clean_category_name(request.form.get("category"))
                    channel_id = nullable_channel_id(
                        request.form.get("channel_id")
                    )
                    if not category or channel_id is None:
                        raise ValueError("Category and channel ID are required.")
                    guild_config.setdefault("categories", {})[category] = channel_id
                    message = f"Category {category} saved."
                else:
                    category = clean_category_name(request.form.get("category"))
                    guild_config.setdefault("categories", {}).pop(category, None)
                    message = f"Category {category} deleted."
            except ValueError as form_error:
                return redirect(url_for(
                    "admin_settings",
                    key=ADMIN_KEY,
                    notice=str(form_error),
                    error=1,
                ))

            save_config(config_data)
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    guild_id,
                    f"dashboard_{action}",
                    actor_id,
                    actor_name,
                    "guild",
                    guild_id,
                    message,
                )
            return redirect(url_for(
                "admin_settings",
                key=ADMIN_KEY,
                notice=message,
            ))

    config_data = load_config()
    limits = config_data.get("limits", {})
    warnings = security_warnings() + storage_warnings(config_data)
    guilds = []
    allowed_settings_ids = {option["id"] for option in guild_options(config_data)}
    for guild_id, guild_config in sorted(
        (config_data.get("guilds") or {}).items()
    ):
        if str(guild_id) not in allowed_settings_ids:
            continue
        features = guild_config.get("features") or {}
        guild_limits = guild_config.get("limits") or {}
        moderation = guild_config.get("moderation") or {}
        game_settings = guild_config.get("game_settings") or {}
        external_backup = {
            **DEFAULT_GUILD_FIELDS["external_backup"],
            **(guild_config.get("external_backup") or {}),
        }
        guilds.append({
            "id": guild_id,
            "name": (
                guild_config.get("brand_name")
                or guild_config.get("guild_name")
                or f"Discord {guild_id}"
            ),
            "guild_name": guild_config.get("guild_name") or f"Discord {guild_id}",
            "brand_name": guild_config.get("brand_name") or "",
            "brand_accent": guild_config.get("brand_accent") or "#7c9cff",
            "brand_logo_url": guild_config.get("brand_logo_url") or "",
            "bot_nickname": guild_config.get("bot_nickname") or "",
            "submit_channel": guild_config.get("submit_channel"),
            "daily_top_channel": guild_config.get("daily_top_channel"),
            "daily_top_time_utc": guild_config.get(
                "daily_top_time_utc",
                "00:00",
            ),
            "weekly_top_day": guild_config.get("weekly_top_day", "sunday").title(),
            "weekly_top_day_lower": guild_config.get("weekly_top_day", "sunday"),
            "timezone": guild_config.get("timezone", "UTC"),
            "approval_enabled": guild_config.get("approval_enabled", False),
            "approval_channel": guild_config.get("approval_channel"),
            "emergency_paused": guild_config.get("emergency_paused", False),
            "emergency_reason": guild_config.get("emergency_reason") or "",
            "limits": {
                **DEFAULT_GUILD_FIELDS["limits"],
                **guild_limits,
            },
            "moderation": {
                **DEFAULT_GUILD_FIELDS["moderation"],
                **moderation,
            },
            "game_settings": {
                **DEFAULT_GUILD_FIELDS["game_settings"],
                **game_settings,
            },
            "public_stats_enabled": guild_config.get("public_stats_enabled", True),
            "external_backup": external_backup,
            "game_summary_channel": guild_config.get("game_summary_channel"),
            "error_channel": guild_config.get("error_channel"),
            "admin_role_ids": " ".join(
                str(role_id)
                for role_id in guild_config.get("admin_role_ids", [])
            ),
            "categories": sorted(
                (guild_config.get("categories") or {}).items()
            ),
            "features": [
                {
                    "key": key,
                    "label": label,
                    "enabled": features.get(key, DEFAULT_FEATURES[key]),
                }
                for key, label in FEATURE_LABELS.items()
            ],
        })

    requested_settings_guild_id = request.args.get("guild_id", "").strip()
    if requested_settings_guild_id not in allowed_settings_ids:
        requested_settings_guild_id = guilds[0]["id"] if guilds else ""
    selected_bot_nickname = ""
    for guild in guilds:
        if guild["id"] == requested_settings_guild_id:
            selected_bot_nickname = guild.get("bot_nickname") or ""
            break
    selected_settings_role = current_admin_role()
    if selected_settings_role != "bot_owner" and requested_settings_guild_id:
        selected_settings_role = normalize_role(
            dashboard_user_server_access_map(current_admin_username()).get(
                requested_settings_guild_id,
                selected_settings_role,
            )
        )
    can_manage_selected_bot_identity = (
        ROLE_LEVELS[selected_settings_role] >= ROLE_LEVELS["owner"]
    )

    scope_sql, scope_params = guild_id_filter("guild_id", allowed_settings_ids)
    with closing(connect_db()) as connection:
        stats = {
            "submissions": connection.execute(
                f"SELECT COUNT(*) FROM submissions WHERE {scope_sql}",
                scope_params,
            ).fetchone()[0],
            "active_games": connection.execute(f"""
                SELECT COUNT(*)
                FROM guess_games
                WHERE status = 'active'
                  AND {scope_sql}
            """, scope_params).fetchone()[0],
            "audit_entries": connection.execute(f"""
                SELECT
                    (SELECT COUNT(*) FROM admin_audit_log WHERE {scope_sql})
                    + (SELECT COUNT(*) FROM moderation_history WHERE {scope_sql})
            """, scope_params + scope_params).fetchone()[0],
            "rate_limit_events": connection.execute(f"""
                SELECT COUNT(*)
                FROM rate_limit_events
                WHERE {scope_sql}
            """, scope_params).fetchone()[0],
            "media_size": format_bytes(media_directory_size()),
        }
        active_games = connection.execute(f"""
            SELECT id, guild_id, channel_id, starter_username,
                   media_name, started_at
            FROM guess_games
            WHERE status = 'active'
              AND {scope_sql}
            ORDER BY started_at DESC, id DESC
        """, scope_params).fetchall()

    db_size = format_bytes(DB_FILE.stat().st_size) if DB_FILE.exists() else "0 B"
    return render_template_string(
        SETTINGS_HTML,
        active_games=active_games,
        admin_key=ADMIN_KEY,
        backups=recent_database_backups(),
        admin_role_choices=ADMIN_ROLE_CHOICES,
        can_manage_bot_identity=can_manage_selected_bot_identity,
        can_manage_global_bot_username=has_admin_role("bot_owner"),
        can_manage_users=has_admin_role("admin"),
        csrf_token=get_csrf_token(),
        current_admin_role=current_admin_role(),
        current_admin_username=current_admin_username(),
        dashboard_users=dashboard_users() if has_admin_role("admin") else [],
        db_file=DB_FILE,
        db_size=db_size,
        error=error,
        global_bot_username=config_data.get("bot_username") or "",
        guilds=guilds,
        limits=limits,
        notice=notice,
        notification_event_labels=NOTIFICATION_EVENT_LABELS,
        notification_routes=notification_routes(config_data),
        parse_guild_scope=parse_guild_scope,
        role_labels=ROLE_LABELS,
        security_warnings=warnings,
        selected_bot_nickname=selected_bot_nickname,
        selected_settings_guild_id=requested_settings_guild_id,
        stats=stats,
        weekdays=WEEKDAYS,
    )


@app.route("/admin/optimization", methods=["GET", "POST"])
def admin_optimization():
    login_response = require_admin_login("admin")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    actor_id, actor_name = web_actor()

    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        try:
            if action == "apply_performance_preset":
                label = apply_performance_preset(
                    request.form.get("preset", ""),
                    actor_id,
                    actor_name,
                )
                clear_runtime_caches()
                return redirect(url_for(
                    "admin_optimization",
                    key=ADMIN_KEY,
                    notice=f"Applied {label} performance preset.",
                ))
            if action == "apply_notification_preset":
                label, enabled, disabled, skipped = apply_notification_preset(
                    request.form.get("preset", ""),
                    request.form.get("guild_id", ""),
                    request.form.get("channel_id", ""),
                    actor_id,
                    actor_name,
                )
                return redirect(url_for(
                    "admin_optimization",
                    key=ADMIN_KEY,
                    notice=(
                        f"Applied {label} notification preset: {enabled} "
                        f"enabled, {disabled} disabled, {skipped} skipped."
                    ),
                ))
            if action == "clear_caches":
                clear_runtime_caches()
                return redirect(url_for(
                    "admin_optimization",
                    key=ADMIN_KEY,
                    notice="Runtime caches cleared.",
                ))
            queue_actions = {
                "optimization_suite",
                "generate_thumbnails",
                "rebuild_media_fingerprints",
                "optimize_database",
            }
            if action in queue_actions:
                payload = {"limit": 10000} if action == "rebuild_media_fingerprints" else {}
                job_id = queue_background_job(
                    action,
                    payload=payload,
                    actor_id=actor_id,
                    actor_name=actor_name,
                )
                return redirect(url_for(
                    "admin_optimization",
                    key=ADMIN_KEY,
                    notice=f"Queued {background_job_label(action)} as job #{job_id}.",
                ))
        except ValueError as form_error:
            return redirect(url_for(
                "admin_optimization",
                key=ADMIN_KEY,
                notice=str(form_error),
                error=1,
            ))

    config_data = load_config()
    guilds = guild_options(config_data)
    return render_template_string(
        OPTIMIZATION_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        error=error,
        guilds=guilds,
        metrics=optimization_metrics(config_data),
        notice=notice,
        notification_presets=NOTIFICATION_PRESETS,
        performance_presets=PERFORMANCE_PRESETS,
    )


@app.route("/admin/maintenance", methods=["GET", "POST"])
def admin_maintenance():
    login_response = require_admin_login("admin")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    actor_id, actor_name = web_actor()

    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        if action == "backup_now":
            label = datetime.now(timezone.utc).strftime("manual-%Y-%m-%d-%H%M%S")
            try:
                backup_path, created, message = create_database_backup(label)
            except (OSError, sqlite3.Error) as backup_error:
                backup_path = None
                created = False
                message = f"Backup failed: {backup_error}"
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "maintenance_backup_manual",
                    actor_id,
                    actor_name,
                    "backup",
                    backup_path.name if backup_path else "",
                    message,
                )
            if not created and message != "Backup already exists.":
                send_admin_notification(
                    "backup_failed",
                    f"Manual maintenance backup failed: `{message}`",
                    throttle_key="maintenance_backup_failed",
                    throttle_seconds=900,
                )
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=message,
                error=0 if created else 1,
            ))
        if action == "restore_test":
            try:
                passed, backup_path, message = run_manual_restore_test()
            except (OSError, sqlite3.Error) as restore_error:
                passed = False
                backup_path = None
                message = f"Restore test failed: {restore_error}"
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "maintenance_restore_test",
                    actor_id,
                    actor_name,
                    "backup",
                    backup_path.name if backup_path else "",
                    message,
                )
            if not passed:
                send_admin_notification(
                    "restore_test_failed",
                    f"Manual restore test failed: `{message}`",
                    throttle_key="maintenance_restore_test_failed",
                    throttle_seconds=900,
                )
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=message,
                error=0 if passed else 1,
            ))
        if action == "restore_config":
            try:
                backup_path, restored, message = restore_latest_config_backup()
            except OSError as restore_error:
                backup_path = None
                restored = False
                message = f"Config restore failed: {restore_error}"
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "maintenance_restore_config",
                    actor_id,
                    actor_name,
                    "config_backup",
                    backup_path.name if backup_path else "",
                    message,
                )
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=message,
                error=0 if restored else 1,
            ))
        if action in {"archive_history", "archive_history_delete"}:
            delete_exported = action == "archive_history_delete"
            job_id = queue_background_job(
                "archive_history",
                payload={"delete_exported": delete_exported},
                actor_id=actor_id,
                actor_name=actor_name,
            )
            message = f"Queued history archive as background job #{job_id}."
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=message,
                error=0,
            ))
        if action == "rollback_latest_snapshot":
            if two_admin_approval_enabled(load_config()):
                return approval_required_redirect(
                    "rollback_latest_snapshot",
                    "deploy_snapshot",
                    "latest",
                    {},
                    actor_id,
                    actor_name,
                    endpoint="admin_maintenance",
                )
            job_id = queue_background_job(
                "rollback_latest_snapshot",
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=(
                    f"Queued rollback to the latest deploy snapshot as "
                    f"background job #{job_id}. Watch the Jobs page; the "
                    "dashboard may briefly restart if rollback succeeds."
                ),
                error=0,
            ))
        if action == "optimize_database":
            job_id = queue_background_job(
                "optimize_database",
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_maintenance",
                key=ADMIN_KEY,
                notice=f"Queued database optimize as background job #{job_id}.",
                error=0,
            ))

    media_stats = media_directory_stats()
    config_data = load_config()
    uptime_seconds = int(
        (datetime.now(timezone.utc) - APP_STARTED_AT).total_seconds()
    )
    days, remainder = divmod(uptime_seconds, 86400)
    hours, remainder = divmod(remainder, 3600)
    minutes = remainder // 60

    with closing(connect_db()) as connection:
        restore_runs = connection.execute("""
            SELECT run_key, backup_name, status, details, created_at
            FROM restore_test_runs
            ORDER BY created_at DESC
            LIMIT 10
        """).fetchall()

    bot_status = read_bot_status()
    maybe_notify_stale_bot(bot_status)
    allowed_guild_ids = current_admin_allowed_guild_ids(config_data)
    guild_backup_rows = []
    for guild_id, guild_config in sorted((config_data.get("guilds") or {}).items()):
        if allowed_guild_ids is not None and str(guild_id) not in allowed_guild_ids:
            continue
        backup = {
            **DEFAULT_GUILD_FIELDS["external_backup"],
            **(guild_config.get("external_backup") or {}),
        }
        if not (
            backup.get("enabled")
            or backup.get("remote")
            or backup.get("last_status")
            or backup.get("public_base_url")
        ):
            continue
        guild_backup_rows.append({
            "guild_id": guild_id,
            "name": (
                guild_config.get("brand_name")
                or guild_config.get("guild_name")
                or f"Discord {guild_id}"
            ),
            **backup,
        })

    return render_template_string(
        MAINTENANCE_HTML,
        admin_key=ADMIN_KEY,
        bot_status=bot_status,
        backups=recent_database_backups(),
        cache_entries=len(PUBLIC_PAGE_CACHE),
        config_backups=recent_config_backups(),
        csrf_token=get_csrf_token(),
        dashboard_instance_id=DASHBOARD_INSTANCE_ID,
        db_file=DB_FILE,
        db_size=format_bytes(DB_FILE.stat().st_size) if DB_FILE.exists() else "0 B",
        error=error,
        guild_backup_rows=guild_backup_rows,
        media_files=media_stats["files"],
        media_size=format_bytes(media_stats["bytes"]),
        notice=notice,
        offsite_backup=config_data.get("offsite_backup") or {},
        release=os.getenv("SDAC_RELEASE") or "development",
        release_status=release_status(),
        restore_runs=restore_runs,
        server_name=os.getenv("SDAC_SERVER_NAME") or "local",
        started_at=APP_STARTED_AT.strftime("%Y-%m-%d %H:%M UTC"),
        storage_forecasts=storage_forecast_rows(config_data),
        uptime=f"{days}d {hours}h {minutes}m",
        warnings=security_warnings() + storage_warnings(config_data),
    )


@app.route("/admin/media", methods=["GET", "POST"])
def admin_media_cleanup():
    login_response = require_admin_login("admin")
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    actor_id, actor_name = web_actor()
    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        config_data = load_config()
        if action == "delete_orphans":
            if two_admin_approval_enabled(config_data):
                return approval_required_redirect(
                    "delete_orphans",
                    "media",
                    "orphans",
                    {},
                    actor_id,
                    actor_name,
                    endpoint="admin_media_cleanup",
                )
            deleted = delete_orphaned_media_files()
            with database() as connection:
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_delete_orphaned_media",
                    actor_id,
                    actor_name,
                    "media",
                    "",
                    f"Deleted {deleted} orphaned media file(s).",
                )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=f"Deleted {deleted} orphaned media file(s).",
            ))
        if action == "generate_thumbnails":
            job_id = queue_background_job(
                "generate_thumbnails",
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=f"Queued thumbnail generation as job #{job_id}.",
            ))
        if action == "rebuild_media_fingerprints":
            job_id = queue_background_job(
                "rebuild_media_fingerprints",
                payload={"limit": 10000},
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=f"Queued media fingerprint rebuild as job #{job_id}.",
            ))
        if action in {"prune_backed_up_originals", "prune_guild_originals"}:
            guild_id = (
                request.form.get("guild_id", "").strip()
                if action == "prune_guild_originals"
                else None
            )
            if two_admin_approval_enabled(config_data):
                return approval_required_redirect(
                    "prune_backed_up_originals",
                    "guild",
                    guild_id or "all",
                    {"guild_id": guild_id},
                    actor_id,
                    actor_name,
                    guild_id=guild_id,
                    endpoint="admin_media_cleanup",
                )
            job_id = queue_background_job(
                "prune_backed_up_originals",
                guild_id=guild_id,
                payload={"guild_id": guild_id},
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=f"Queued backed-up original pruning as job #{job_id}.",
            ))
        if action == "restore_guild_media":
            guild_id = request.form.get("guild_id", "").strip()
            job_id = queue_background_job(
                "restore_guild_media",
                guild_id=guild_id,
                payload={"guild_id": guild_id},
                actor_id=actor_id,
                actor_name=actor_name,
            )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=f"Queued media restore as job #{job_id}.",
            ))
        if action in {"restore_quarantine", "delete_quarantine"}:
            quarantine_id = int(request.form.get("quarantine_id", "0") or 0)
            ok, message = resolve_quarantine_item(
                quarantine_id,
                "restore" if action == "restore_quarantine" else "delete",
                actor_id,
                actor_name,
            )
            return redirect(url_for(
                "admin_media_cleanup",
                key=ADMIN_KEY,
                notice=message,
                error=0 if ok else 1,
            ))

    config_data = load_config()
    return render_template_string(
        MEDIA_CLEANUP_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        guild_storage_rows=guild_storage_rows(config_data),
        notice=notice,
        quarantine_items=quarantine_items(),
        report=media_cleanup_report(),
    )


