@app.route("/admin/maintenance-mode", methods=["GET", "POST"])
def admin_maintenance_mode():
    login_response = require_admin_login("bot_owner")
    if login_response:
        return login_response
    config_data = load_config()
    options = guild_options(config_data)
    allowed_ids = {option["id"] for option in options}
    if request.method == "POST":
        require_csrf_token()
        guild_id = request.form.get("guild_id", "").strip()
        if guild_id not in allowed_ids:
            abort(403)
        paused = request.form.get("paused") == "1"
        reason = request.form.get("reason", "").strip()[:300]
        guild_config = (config_data.get("guilds") or {}).get(guild_id)
        if not guild_config:
            abort(404)
        guild_config["emergency_paused"] = paused
        guild_config["emergency_reason"] = reason if paused else ""
        save_config(config_data)
        actor_id, actor_name = web_actor()
        details = f"Maintenance mode {'enabled' if paused else 'disabled'}. {reason}".strip()
        with database() as connection:
            add_admin_audit_log(connection, guild_id, "maintenance_mode", actor_id, actor_name, "guild", guild_id, details)
        clear_runtime_caches()
        return redirect(url_for("admin_maintenance_mode", key=ADMIN_KEY, notice=details))
    body = """
    <section class="panel">
        <table>
            <thead><tr><th>Server</th><th>Status</th><th>Reason</th><th>Action</th></tr></thead>
            <tbody>
                {% for guild in guilds %}
                    <tr>
                        <td><strong>{{ guild.name }}</strong><br><code>{{ guild.id }}</code></td>
                        <td><span class="{{ 'warn' if guild.paused else 'ok' }}">{{ 'Paused' if guild.paused else 'Open' }}</span></td>
                        <td>{{ guild.reason or '-' }}</td>
                        <td>
                            <form class="toolbar" method="post">
                                <input type="hidden" name="key" value="{{ admin_key }}">
                                <input type="hidden" name="csrf_token" value="{{ csrf_token }}">
                                <input type="hidden" name="guild_id" value="{{ guild.id }}">
                                <select name="paused">
                                    <option value="0" {% if not guild.paused %}selected{% endif %}>Open submissions</option>
                                    <option value="1" {% if guild.paused %}selected{% endif %}>Pause submissions</option>
                                </select>
                                <input name="reason" value="{{ guild.reason }}" placeholder="Reason shown to staff">
                                <button type="submit">Save</button>
                            </form>
                        </td>
                    </tr>
                {% else %}
                    <tr><td colspan="4" class="muted">No servers visible.</td></tr>
                {% endfor %}
            </tbody>
        </table>
    </section>
    """
    guilds = []
    for option in options:
        guild_config = (config_data.get("guilds") or {}).get(option["id"], {})
        guilds.append({
            "id": option["id"],
            "name": option["name"],
            "paused": bool(guild_config.get("emergency_paused")),
            "reason": guild_config.get("emergency_reason") or "",
        })
    return admin_tool_shell(
        "Maintenance Mode",
        "Pause or resume submissions without digging through full settings.",
        body,
        guilds=guilds,
    )


@app.route("/admin/moderation", methods=["GET", "POST"])
def admin_moderation():
    login_response = require_admin_login()
    if login_response:
        return login_response

    notice = request.args.get("notice", "")
    config_data = load_config()
    guild_names = guild_name_map(config_data)
    allowed_moderation_ids = current_admin_allowed_guild_ids(config_data)
    if request.method == "POST":
        require_csrf_token()
        action = request.form.get("action", "")
        actor_id, actor_name = web_actor()
        if action == "bulk_resolve_reports":
            report_ids = [
                int(report_id)
                for report_id in request.form.getlist("report_ids")
                if str(report_id).isdigit()
            ]
            admin_notes = request.form.get("admin_notes", "").strip()[:500]
            if not report_ids:
                return redirect(url_for(
                    "admin_moderation",
                    key=ADMIN_KEY,
                    notice="Choose at least one report.",
                ))
            placeholders = ", ".join("?" for _ in report_ids)
            scope_sql, scope_params = guild_id_filter(
                "guild_id",
                allowed_moderation_ids,
            )
            with database() as connection:
                connection.execute(f"""
                    UPDATE submission_reports
                    SET status = 'resolved',
                        admin_notes = ?,
                        resolved_at = ?
                    WHERE id IN ({placeholders})
                      AND {scope_sql}
                """, [admin_notes, utc_now_iso()] + report_ids + scope_params)
                add_admin_audit_log(
                    connection,
                    None,
                    "dashboard_bulk_resolve_reports",
                    actor_id,
                    actor_name,
                    "submission_report",
                    ",".join(str(report_id) for report_id in report_ids),
                    f"Resolved {len(report_ids)} report(s).",
                )
            return redirect(url_for(
                "admin_moderation",
                key=ADMIN_KEY,
                notice=f"Resolved {len(report_ids)} report(s).",
            ))
        if action == "resolve_report":
            report_id = request.form.get("report_id", "").strip()
            admin_notes = request.form.get("admin_notes", "").strip()[:500]
            with database() as connection:
                report = connection.execute("""
                    SELECT *
                    FROM submission_reports
                    WHERE id = ?
                """, (report_id,)).fetchone()
                if report and not can_admin_access_guild(
                    report["guild_id"],
                    config_data,
                ):
                    abort(403)
                if report:
                    connection.execute("""
                        UPDATE submission_reports
                        SET status = 'resolved',
                            admin_notes = ?,
                            resolved_at = ?
                        WHERE id = ?
                    """, (admin_notes, utc_now_iso(), report["id"]))
                    add_admin_audit_log(
                        connection,
                        report["guild_id"],
                        "submission_report_resolved",
                        actor_id,
                        actor_name,
                        "submission_report",
                        report["id"],
                        admin_notes or "Marked reviewed.",
                    )
                    notice = "Report marked reviewed."
                else:
                    notice = "Report not found."
            clear_runtime_caches()
            return redirect(url_for(
                "admin_moderation",
                key=ADMIN_KEY,
                notice=notice,
            ))

    with closing(connect_db()) as connection:
        scope_sql, scope_params = guild_id_filter(
            "reports.guild_id",
            allowed_moderation_ids,
        )
        reports = connection.execute(f"""
            SELECT reports.id, reports.submission_id, reports.guild_id,
                   reports.reporter_name, reports.reason, reports.created_at
            FROM submission_reports AS reports
            WHERE reports.status = 'open'
              AND {scope_sql}
            ORDER BY reports.created_at DESC, reports.id DESC
            LIMIT 50
        """, scope_params).fetchall()
        scope_sql, scope_params = guild_id_filter(
            "guild_id",
            allowed_moderation_ids,
        )
        pending_rows = connection.execute(f"""
            SELECT *
            FROM submissions
            WHERE status IN ('pending', 'needs_review')
              AND {scope_sql}
            ORDER BY created_at DESC, id DESC
            LIMIT 50
        """, scope_params).fetchall()
        history = connection.execute(f"""
            SELECT guild_id, submission_id, action, actor_username,
                   details, created_at
            FROM moderation_history
            WHERE {scope_sql}
            ORDER BY created_at DESC, id DESC
            LIMIT 50
        """, scope_params).fetchall()
    pending_posts = [prepare_post(row) for row in pending_rows]
    return render_template_string(
        MODERATION_HTML,
        admin_key=ADMIN_KEY,
        csrf_token=get_csrf_token(),
        guild_names=guild_names,
        history=history,
        notice=notice,
        pending_posts=pending_posts,
        reports=reports,
    )


