@app.route("/")
def index():
    config_data = load_config()
    has_key = request.args.get("key") == ADMIN_KEY
    if is_admin_logged_in() and not has_key:
        values = request.args.to_dict(flat=True)
        values["key"] = ADMIN_KEY
        return redirect(url_for("index", **values))
    is_admin = has_key and is_admin_logged_in()
    if has_key and not is_admin:
        return redirect(url_for(
            "admin_login",
            key=ADMIN_KEY,
            next=request.full_path,
        ))

    server_options = guild_options(config_data, public_only=not is_admin)
    guild_names = guild_name_map(config_data)
    visible_guild_ids = {option["id"] for option in server_options}
    selected_server_id = selected_guild_id(server_options)
    if not is_admin and not selected_server_id:
        visible_guild_ids &= feature_guild_ids(config_data, "cross_server_gallery")
    selected_server_name = (
        guild_names.get(selected_server_id, "Selected Server")
        if selected_server_id
        else "All Discord Servers"
    )
    selected_category = request.args.get("category", "").strip()
    selected_status = request.args.get("status", "").strip()
    selected_sort = request.args.get("sort", "newest").strip()
    selected_month = request.args.get("month", "").strip()
    search_query = request.args.get("q", "").strip()
    notice = request.args.get("notice", "")
    error = request.args.get("error") == "1"
    page = positive_page(request.args.get("page"))
    if selected_sort not in {"newest", "votes"}:
        selected_sort = "newest"

    public_cache_key = None
    if not is_admin and not is_account_logged_in() and not notice and not error and request.method == "GET":
        public_cache_key = cache_key(
            "index",
            selected_server_id or "all",
            selected_category,
            selected_sort,
            selected_month,
            search_query,
            page,
        )
        cached = cached_public_page(public_cache_key)
        if cached is not None:
            return cached

    with closing(connect_db()) as connection:
        months = available_submission_months(
            connection,
            selected_server_id,
            guild_ids=visible_guild_ids if not is_admin and not selected_server_id else None,
        )
        category_conditions = ["category IS NOT NULL", "category != ''"]
        category_parameters = []
        if not is_admin:
            category_conditions.append("status = 'posted'")
        if selected_server_id:
            category_conditions.append("guild_id = ?")
            category_parameters.append(selected_server_id)
        elif not is_admin:
            visible_filter, visible_params = guild_id_filter(
                "guild_id",
                visible_guild_ids,
            )
            category_conditions.append(visible_filter)
            category_parameters.extend(visible_params)
        category_where = " WHERE " + " AND ".join(category_conditions)
        categories = [
            row["category"]
            for row in connection.execute(f"""
                SELECT DISTINCT category
                FROM submissions
                {category_where}
                ORDER BY category
            """, category_parameters)
        ]

        if selected_month:
            preserve_monthly_submission_top(connection, selected_month)
            connection.commit()
            where = ["month = ?"]
            parameters = [selected_month]
            if selected_server_id:
                where.append("guild_id = ?")
                parameters.append(selected_server_id)
            elif not is_admin:
                visible_filter, visible_params = guild_id_filter(
                    "guild_id",
                    visible_guild_ids,
                )
                where.append(visible_filter)
                parameters.extend(visible_params)
            if selected_category:
                where.append("category = ?")
                parameters.append(selected_category)
            if search_query:
                where.append("""
                    (
                        CAST(submission_id AS TEXT) = ?
                        OR username LIKE ?
                        OR category LIKE ?
                        OR message_text LIKE ?
                    )
                """)
                like_query = f"%{search_query}%"
                parameters.extend([
                    search_query,
                    like_query,
                    like_query,
                    like_query,
                ])
            where_sql = " WHERE " + " AND ".join(where)
            total_items = connection.execute(
                f"SELECT COUNT(*) FROM monthly_submission_top{where_sql}",
                parameters,
            ).fetchone()[0]
            total_pages = max(1, math.ceil(total_items / PAGE_SIZE))
            page = min(page, total_pages)
            rows = connection.execute(
                f"""
                    SELECT
                        submission_id AS id,
                        guild_id,
                        original_message_id,
                        repost_message_id,
                        repost_channel_id,
                        NULL AS approval_message_id,
                        NULL AS approval_channel_id,
                        user_id,
                        username,
                        category,
                        message_text,
                        file_paths,
                        media_paths,
                        media_names,
                        media_types,
                        media_sizes,
                        media_metadata_json,
                        NULL AS media_hashes,
                        0 AS spam_score,
                        '[]' AS spam_reasons_json,
                        stars,
                        voters,
                        'posted' AS status,
                        submitted_at,
                        created_at,
                        NULL AS approved_at,
                        NULL AS daily_posted_at
                    FROM monthly_submission_top
                    {where_sql}
                    ORDER BY category ASC, rank ASC
                    LIMIT ? OFFSET ?
                """,
                parameters + [PAGE_SIZE, (page - 1) * PAGE_SIZE],
            ).fetchall()
        else:
            where = []
            parameters = []
            if not is_admin:
                where.append("status = 'posted'")
            elif selected_status in {"posted", "pending", "needs_review", "removed"}:
                where.append("status = ?")
                parameters.append(selected_status)
            if selected_server_id:
                where.append("guild_id = ?")
                parameters.append(selected_server_id)
            elif not is_admin:
                visible_filter, visible_params = guild_id_filter(
                    "guild_id",
                    visible_guild_ids,
                )
                where.append(visible_filter)
                parameters.extend(visible_params)
            if selected_category:
                where.append("category = ?")
                parameters.append(selected_category)
            if search_query:
                where.append("""
                    (
                        CAST(id AS TEXT) = ?
                        OR username LIKE ?
                        OR category LIKE ?
                        OR message_text LIKE ?
                    )
                """)
                like_query = f"%{search_query}%"
                parameters.extend([
                    search_query,
                    like_query,
                    like_query,
                    like_query,
                ])

            where_sql = " WHERE " + " AND ".join(where) if where else ""
            order_sql = (
                "stars DESC, created_at DESC, id DESC"
                if selected_sort == "votes"
                else "created_at DESC, id DESC"
            )
            total_items = connection.execute(
                f"SELECT COUNT(*) FROM submissions{where_sql}",
                parameters,
            ).fetchone()[0]
            total_pages = max(1, math.ceil(total_items / PAGE_SIZE))
            page = min(page, total_pages)
            rows = connection.execute(
                f"""
                    SELECT *
                    FROM submissions
                    {where_sql}
                    ORDER BY {order_sql}
                    LIMIT ? OFFSET ?
                """,
                parameters + [PAGE_SIZE, (page - 1) * PAGE_SIZE],
            ).fetchall()

    voter_id = current_dashboard_voter_id()
    grouped_posts = {}
    for row in rows:
        post = prepare_post(row)
        voters = get_voters(post.get("voters"))
        post["current_user_voted"] = bool(voter_id and voter_id in voters)
        post["guild_name"] = guild_names.get(
            post.get("guild_id"),
            f"Discord {post.get('guild_id')}" if post.get("guild_id") else "",
        )
        grouped_posts.setdefault(
            post["category"] or "Uncategorized",
            [],
        ).append(post)

    def page_url(page_number):
        values = {
            "category": selected_category,
            "month": selected_month,
            "page": page_number,
            "q": search_query,
            "sort": selected_sort,
            "guild_id": selected_server_id or "all",
        }
        if is_admin:
            values["key"] = ADMIN_KEY
            values["status"] = selected_status
        return url_for("index", **values)

    rendered = render_template_string(
        HTML,
        account_logged_in=is_account_logged_in(),
        account_username=current_account_username(),
        admin_key=ADMIN_KEY,
        categories=categories,
        error=error,
        grouped_posts=grouped_posts,
        csrf_token=get_csrf_token() if (is_admin or is_account_logged_in()) else "",
        guild_options=server_options,
        is_admin=is_admin,
        months=months,
        notice=notice,
        page=page,
        page_url=page_url,
        selected_category=selected_category,
        selected_guild_name=selected_server_name,
        selected_guild_id=selected_server_id,
        selected_month=selected_month,
        search_query=search_query,
        selected_sort=selected_sort,
        selected_status=selected_status,
        total_pages=total_pages,
    )
    if public_cache_key:
        return store_public_page(public_cache_key, rendered)
    return rendered


@app.post("/submission/<int:submission_id>/vote")
def vote_submission(submission_id):
    if not is_account_logged_in():
        return redirect(url_for("account_login", next=request.referrer or url_for("index")))
    require_csrf_token()

    voter_id = current_dashboard_voter_id()
    if not voter_id:
        return redirect(url_for(
            "account_home",
            notice="Link Discord or finish your account before voting.",
            error=1,
        ))

    config_data = load_config()
    allowed_guild_ids = current_account_allowed_guild_ids(config_data)
    redirect_values = {
        "category": request.args.get("category", "").strip(),
        "guild_id": request.args.get("guild_id", "all").strip() or "all",
        "q": request.args.get("q", "").strip(),
        "sort": request.args.get("sort", "newest").strip() or "newest",
        "status": request.args.get("status", "").strip(),
        "page": positive_page(request.args.get("page")),
    }
    if is_admin_logged_in():
        redirect_values["key"] = ADMIN_KEY

    with database() as connection:
        row = connection.execute(
            "SELECT id, guild_id, status, voters FROM submissions WHERE id = ?",
            (submission_id,),
        ).fetchone()
        if not row or row["status"] != "posted":
            return redirect(url_for(
                "index",
                notice="Only posted submissions can be voted on.",
                error=1,
                **redirect_values,
            ))
        if str(row["guild_id"] or "") not in allowed_guild_ids:
            abort(403)

        voters = get_voters(row["voters"])
        if voter_id in voters:
            voters.remove(voter_id)
            delta = -1
            notice = "Vote removed."
        else:
            voters.add(voter_id)
            delta = 1
            notice = "Vote added."
        connection.execute(
            """
            UPDATE submissions
            SET stars = CASE
                    WHEN COALESCE(stars, 0) + ? < 0 THEN 0
                    ELSE COALESCE(stars, 0) + ?
                END,
                voters = ?
            WHERE id = ?
            """,
            (delta, delta, save_voters(voters), row["id"]),
        )

    clear_runtime_caches()
    return redirect(url_for("index", notice=notice, **redirect_values))


